     /**
      * Apply forward/backward movement to robot
      * Uses Temi's goTo() navigation or custom movement patterns
      */
    private fun applyMovement(robot: Robot, distance: Float) {
        try {
            // Temi SDK doesn't provide direct moveTo() API
            // Instead, we can:
