package com.example.alliswelltemi.data
import java.time.LocalDateTime
/** * Doctor data model with profile information */ data class Doctor( val id: String, val name: String, val department: String, val yearsOfExperience: Int, val aboutBio: String, val cabin: String // e.g., "3A", "5B" )
/** * Time slot for appointment availability */ data class TimeSlot( val startTime: String, // e.g., "10:00 AM" val endTime: String, // e.g., "10:30 AM" val available: Boolean )
