            .height(140.dp) // Unified with Navigation card height
            .graphicsLayer {
                scaleX = scale
                scaleY = scale
            }
            .shadow(
                elevation = if (isSelected) 20.dp else 8.dp, // Unified shadow
                shape = RoundedCornerShape(24.dp),
                spotColor = Color.Black.copy(alpha = 0.1f)
            )
            .clickable(
                interactionSource = remember { MutableInteractionSource() },
                indication = null,
                onClick = onClick
            ),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = bgColor)
    ) {
        Column(
            modifier = Modifier
                .padding(12.dp) // Unified padding
                .fillMaxSize(),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center
        ) {
            Box(
                modifier = Modifier
                    .size(48.dp) // Unified icon box size
                    .background(
                        color = if (isSelected) Color.White.copy(alpha = 0.2f) else HospitalColors.DeepSlate.copy(alpha = 0.05f),
                        shape = CircleShape
                    ),
                contentAlignment = Alignment.Center
            ) {
                if (imageUrl != null && imageUrl.isNotBlank()) {
                    AsyncImage(
                        model = imageUrl,
                        contentDescription = title,
                        modifier = Modifier
                            .fillMaxSize()
                            .clip(CircleShape),
                        contentScale = ContentScale.Crop
                    )
                } else {
                    Icon(
                        imageVector = icon,
                        contentDescription = null,
                        tint = textColor,
                        modifier = Modifier.size(24.dp) // Unified icon size
                    )
                }
            }

            Spacer(modifier = Modifier.height(8.dp)) // Unified spacer

            Column(
                modifier = Modifier.fillMaxWidth(),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.Center
            ) {
                Text(
                    text = title.toUpperCase(Locale.current),
                    style = MaterialTheme.typography.titleLarge.copy(
                        fontSize = 16.sp, // Unified font size
                        fontWeight = FontWeight.Black,
                        color = textColor,
                        textAlign = TextAlign.Center,
                        lineHeight = 18.sp,
                        letterSpacing = 0.sp
                    ),
                    maxLines = 1, // Reduced to 1 line for consistency
                    overflow = TextOverflow.Ellipsis
                )
                Spacer(modifier = Modifier.height(2.dp))
                Text(
                    text = subtitle.toUpperCase(Locale.current),
                    style = MaterialTheme.typography.labelSmall.copy(
                        fontSize = 11.sp, // Unified font size
                        fontWeight = FontWeight.ExtraBold,
                        color = if (isSelected) Color.White else HospitalColors.DeepSlate.copy(alpha = 0.85f),
                        letterSpacing = 0.5.sp,
                        textAlign = TextAlign.Center,
                        lineHeight = 13.sp
                    ),
                    maxLines = 1, // Reduced to 1 line for consistency
                    overflow = TextOverflow.Ellipsis
                )
            }
        }
    }
}

package com.example.alliswelltemi.data
/** * Hospital Knowledge Base - 294 Q&A pairs (COMPLETE VERSION) * Each QA pair represents common hospital questions and answers * These are retrieved intelligently based on user query */ data class KnowledgeBaseQA( val id: String, val question: String, val answer: String, val keywords: List<String>, // For matching user queries val category: String, // hospital_info, departments, appointments, etc. val language: String = "en" // "en" or "hi" )
object HospitalKnowledgeBase {
// ==================== ALL 294 Q&A PAIRS ==================== // Generated from Hospital temi Dataset.json // Updated: April 22, 2026 private val qaDatabase = listOf( // ...existing code... KnowledgeBaseQA( id = "qa_1", question = "What is the hospital name ?", answer = "All Is Well Hospital is a modern multi-speciality healthcare institution located in Burhanpur, Madhya Pradesh. The founder and chairman of All is Well Hospiital is Mr. Anand Prakash Chouksey. The hospital was established in 2019 with the vision of delivering high-quality, ethical, and patient-centered medical care to people in and around the region. The mission of All Is Well Hospital is to provide accessible, affordable, and advanced healthcare services with compassion and integrity.", keywords = listOf("transparent", "dignity", "hospiital", "outcomes", "dental", "specialists", "ophthalmology", "professionals", "burhanpur", "monitoring"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_1_hi", question = "अस्पताल का नाम क्या है?", answer = "ऑल इज़ वेल हॉस्पिटल एक आधुनिक मल्टी-स्पेशलिटी स्वास्थ्य संस्थान है, जो बुरहानपुर, मध्य प्रदेश में स्थित है। इसके संस्थापक और चेयरमैन श्री आनंद प्रकाश चौकसे हैं। अस्पताल 2019 में स्थापित किया गया था, जिसका उद्देश्य उच्च गुणवत्ता, नैतिक और रोगी-केंद्रित चिकित्सा सेवा प्रदान करना है। ऑल इज़ वेल हॉस्पिटल का मिशन करुणा और ईमानदारी के साथ सुलभ, किफायती और उन्नत स्वास्थ्य सेवाएं प्रदान करना है।", keywords = listOf("अस्पताल", "नाम", "ऑल इज़ वेल", "बुरहानपुर", "चौकसे", "मिशन", "सेवा", "स्वास्थ्य", "मध्य प्रदेश"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_2_hi", question = "क्या आपके पास बीमा सुविधाएं हैं?", answer = "अस्पताल विस्तृत श्रेणी के विश्वसनीय स्वास्थ्य बीमा प्रदाताओं के माध्यम से कैशलेस और प्रतिपूर्ति सुविधाएं प्रदान करता है। स्वीकृत बीमा कंपनियों में स्टार हेल्थ इन्शुरेंस, केयर हेल्थ इन्शुरेंस, पैरामाउंट हेल्थ सर्विसेज़, IFFCO-टोकियो जनरल इंश्योरेंस, डिजिट इंश्योरेंस, आदित्य बिड़ला हेल्थ इन्शुरेंस, SBI जनरल इंश्योरेंस शामिल हैं।", keywords = listOf("बीमा", "सुविधाएं", "कैशलेस", "प्रतिपूर्ति", "स्वास्थ्य", "कंपनियां"), category = "insurance", language = "hi" ), KnowledgeBaseQA( id = "qa_3_hi", question = "स्वास्थ्य पैकेज कौन से हैं?", answer = "ऑल इज़ वेल हॉस्पिटल में विशेष रूप से डिज़ाइन किए गए स्वास्थ्य पैकेज हैं: बेसिक वेलनेस, कम्प्रिहेंसिव वेलनेस, महिला स्वास्थ्य पैकेज, डायबिटिक वेलनेस और बाल स्वास्थ्य पैकेज। प्रत्येक पैकेज में प्रयोगशाला परीक्षण और नैदानिक मूल्यांकन शामिल हैं।", keywords = listOf("पैकेज", "स्वास्थ्य", "वेलनेस", "परीक्षण", "महिला", "बाल", "मधुमेह"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_6_hi", question = "क्या वॉक-इन परामर्श की अनुमति है?", answer = "ऑल इज़ वेल हॉस्पिटल 24/7 OPD सेवाएं प्रदान करता है। मरीज़ रिसेप्शन पर आकर परामर्श ले सकते हैं। आपातकालीन मामलों में प्राथमिकता दी जाती है। 24 घंटे फार्मेसी, प्रयोगशाला और रेडियोलॉजी विभाग उपलब्ध हैं।", keywords = listOf("परामर्श", "OPD", "आपातकालीन", "24/7", "डॉक्टर", "उपलब्ध"), category = "departments", language = "hi" ), KnowledgeBaseQA( id = "qa_7_hi", question = "अस्पताल का फोन नंबर क्या है?", answer = "ऑल इज़ वेल हॉस्पिटल से संपर्क करने के लिए आपातकालीन नंबर +91 76977 44444 या +91 70890 66888 पर कॉल करें। ये नंबर अस्पताल के सामने के डेस्क से जुड़े हैं जहां विभाग की जानकारी, अपॉइंटमेंट बुकिंग और आपातकालीन सहायता उपलब्ध है।", keywords = listOf("फोन", "नंबर", "संपर्क", "अपॉइंटमेंट", "आपातकालीन"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_8_hi", question = "क्या आप हिंदी में बोल सकते हैं?", answer = "हां, मैं हिंदी में बोल सकता हूँ। आप हिंदी में अपने सवाल पूछ सकते हैं और मैं हिंदी में जवाब दूंगा। मेरा लक्ष्य आपके लिए संचार को आसान और सुविधाजनक बनाना है।", keywords = listOf("हिंदी", "भाषा", "बोल", "समझ", "सवाल", "जवाब"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_9_hi", question = "क्या आप दोहरा सकते हैं?", answer = "जी, मैं आपके लिए जानकारी को स्पष्ट और धीरे-धीरे दोहराऊंगा। यदि आपको कोई विस्तृत जानकारी चाहिए, तो बस पूछें। मैं आपकी सहायता के लिए यहां हूँ।", keywords = listOf("दोहराना", "स्पष्ट", "जानकारी", "धीरे", "समझ", "विस्तार"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_13_hi", question = "अस्पताल में कौन सी सुविधाएं उपलब्ध हैं?", answer = "ऑल इज़ वेल हॉस्पिटल में उन्नत नैदानिक प्रयोगशालाएं, 24/7 फार्मेसी, कैफेटेरिया, ATM, पेयजल स्टेशन, शौचालय, लिफ्टें, व्हीलचेयर सहायता और समर्पित प्रतीक्षा क्षेत्र हैं। ICU के लिए विशेष समय हैं (आमतौर पर 11 AM-12 PM और 6 PM-7 PM)।", keywords = listOf("सुविधाएं", "प्रयोगशाला", "फार्मेसी", "ATM", "शौचालय", "लिफ्ट", "ICU"), category = "diagnostics", language = "hi" ), KnowledgeBaseQA( id = "qa_51_hi", question = "अस्पताल का ईमेल क्या है?", answer = "आप अस्पताल को frontdesk@alliswellhospital.com पर ईमेल कर सकते हैं। यह ईमेल पता अस्पताल की प्रशासनिक टीम द्वारा समीक्षा किया जाता है और सामान्य पूछताछ, अपॉइंटमेंट अनुरोध और स्वास्थ्य पैकेज विवरण के लिए उपयोग किया जा सकता है।", keywords = listOf("ईमेल", "संपर्क", "frontdesk", "अपॉइंटमेंट", "पूछताछ"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_57_hi", question = "अस्पताल का खुलने का समय क्या है?", answer = "सोमवार से शुक्रवार: सुबह 8:00 से शाम 8:00 बजे | शनिवार से रविवार: सुबह 9:00 से शाम 6:00 बजे", keywords = listOf("खुलने", "समय", "सोमवार", "शुक्रवार", "शनिवार", "रविवार", "घंटे"), category = "hospital_info", language = "hi" ), KnowledgeBaseQA( id = "qa_58_hi", question = "ऑल इज़ वेल हॉस्पिटल कहां स्थित है?", answer = "ऑल इज़ वेल हॉस्पिटल मैक्रो विजन अकादमी के पास, बुरहानपुर, मध्य प्रदेश, 450331 में स्थित है।", keywords = listOf("स्थान", "पता", "बुरहानपुर", "मध्य प्रदेश", "मैक्रो", "विजन", "अकादमी"), category = "facilities", language = "hi" ), KnowledgeBaseQA( id = "qa_2", question = "Do you have insurance facilities?", answer = "The hospital provides cashless and reimbursement facilities through a wide range of trusted health insurance providers to ensure convenient and hassle-free treatment for patients. The accepted insurance companies include Star Health Insurance, Care Health Insurance, Paramount Health Services, IFFCO-Tokio General Insurance, Digit Insurance, Aditya Birla Health Insurance, SBI General Insurance, ICICI Lombard, FHPL (Family Health Plan Limited), MDIndia Healthcare Services, Niva Bupa Health Insurance.", keywords = listOf("provided", "limited", "plan", "according", "available", "doctor", "unless", "specific", "coverage", "eligible"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_3", question = "What all are the health packages ?", answer = "At All Is Well Hospital, we offer a variety of specially designed health check-up packages to meet the preventive and diagnostic healthcare needs of adults, women, children, and patients managing chronic conditions such as diabetes. Currently, we provide five major health packages: Basic Wellness, Comprehensive Wellness, Comprehensive Women Wellness, Diabetic Wellness, and Healthy Child Wellness. Each package includes a carefully selected combination of laboratory tests and diagnostic evaluations.", keywords = listOf("metabolic", "8540", "performance", "focuses", "tsh", "ecg", "lipid", "each", "available", "consultation"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_4", question = "What are types of yoga treatment available ?", answer = "At All Is Well Hospital, a range of structured yoga treatments is available to support physical health, mental well-being, and overall lifestyle balance. The hospital offers multiple therapeutic yoga approaches tailored to different health needs. These include Hatha Yoga, Vinyasa Flow, Yin Yoga, Pranayama, Meditation and Mindfulness, and Yoga Therapy, each designed with specific benefits and therapeutic goals.", keywords = listOf("fascia", "ligaments", "focuses", "supports", "stamina", "fluid", "each", "yin", "particularly", "available"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_5", question = "Treatments Available in Nutrition and diet ?", answer = "The Treatments Available in Nutrition and Diet focus on improving overall health, preventing diseases, and supporting specific medical conditions through scientifically designed dietary strategies. Personalized Meal Planning involves creating custom nutrition plans tailored to an individual's health goals, medical history, lifestyle, and dietary preferences. This approach ensures balanced nutrient intake while addressing concerns such as weight control, nutrient deficiencies, food allergies.", keywords = listOf("strategies", "gain", "metabolic", "performance", "holistic", "focuses", "qualified", "loss", "available", "specific"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_6", question = "Is walk in consultation allowed ?", answer = "All Is Well Hospital provides 24×7 OPD services along with emergency care, and patients can generally walk in for consultations on a first-come, first-served basis at the reception, with priority sometimes given to emergency cases or senior citizens. Specific walk-in policies will depend on doctor availability, but urgent care is always accessible any time due to the 24-hour OPD and emergency setup. The in-house Pharmacy, the labs and radiology department at All Is Well Hospital operates 24×7.", keywords = listOf("availability", "consultation", "available", "doctor", "urgent", "specific", "online", "firstserved", "room", "reports"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_7", question = "What is the hospital's phone number?", answer = "You can contact All Is Well Hospital directly by calling on the emergency number +91 76977 44444 or +91 70890 66888. These numbers connect you to the hospital's front desk and support team, where staff members can assist you with appointment bookings, department inquiries, emergency coordination, and general hospital information. The phone lines are active to ensure patients and visitors receive timely assistance whenever needed.", keywords = listOf("query", "feedback", "bookings", "quicker", "available", "specific", "package", "without", "ensure", "health", "phone number"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_8", question = "Can you speak in Hindi?", answer = "Yes, I can speak in Hindi. You can ask your questions in Hindi, and I will respond in Hindi to make it easier for you. My goal is to make communication simple and comfortable for you during your visit to the hospital.", keywords = listOf("questions", "will", "hospital", "easier", "during", "yes", "hindi", "goal", "respond", "simple"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_9", question = "Can you repeat?", answer = "Of course. I will repeat the information for you clearly and slowly. Please listen carefully, and if you need me to repeat it again or explain any specific part in more detail, feel free to ask. I am here to assist you.", keywords = listOf("specific", "information", "any", "detail", "slowly", "here", "please", "clearly", "repeat", "feel"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_10", question = "Can you repeat the direction ?", answer = "Certainly. I will repeat the directions step by step so you can follow them easily. Please proceed straight from your current location, then turn as instructed. If you would like, I can also guide you by moving with you to the destination. Let me know how you would prefer to proceed.", keywords = listOf("moving", "directions", "direction", "proceed", "them", "step", "from", "current", "know", "prefer"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_11", question = "Can you show the map ?", answer = "yes. Yes, I can display the hospital map on my screen for you. The map will show your current location and the route to your destination inside the hospital. You can follow the highlighted path, or I can guide you personally to the location. Please confirm where you would like to go.", keywords = listOf("personally", "confirm", "current", "please", "location", "path", "destination", "where", "highlighted", "hospital"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_12", question = "can you explain again ?", answer = "Yes, let me explain you again in a simple language. I am here to ensure you receive complete and accurate information.", keywords = listOf("let", "language", "accurate", "receive", "yes", "explain", "here", "simple", "ensure", "complete"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_13", question = "What facilities are available at the hospital?", answer = "All Is Well Hospital provides comprehensive facilities including advanced diagnostic labs, 24/7 pharmacy, cafeteria, ATM, drinking water stations, restrooms, elevators, wheelchair assistance, and dedicated waiting areas for visitors . Visiting hours for general wards are typically not defined one family member/visitor can visit the patient with a pass that is given to the patient. ICU visiting hours are more restricted (commonly 11 AM-12 PM and 6 PM-7 PM) to ensure patient rest and infection control.", keywords = listOf("provided", "xray", "additional", "availability", "12000day", "discharge", "each", "available", "consultation", "doctor"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_14", question = "How much the radiology and imaging costs ?", answer = "At All Is Well Hospital, the Radiology and Imaging Department offers a wide range of advanced diagnostic imaging services. The exact cost of each test depends on the type of scan, body part examined, contrast usage, and clinical requirements. Patients are advised to contact the billing counter for updated pricing. The available radiology and imaging services include X-Ray for examining bones, chest, lungs, fractures, infections, and joint conditions.", keywords = listOf("safe", "internal", "xray", "performance", "nursing", "perday", "105", "tsh", "each", "available"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_15", question = "Is cash accepted ?", answer = "Yes, the hospital accepts cash payments for consultations, diagnostic tests, room charges, and other medical services. In addition to cash, digital payment options may also be available for patient convenience. For large bills such as admissions or surgeries, patients can confirm accepted payment methods at the billing counter.", keywords = listOf("availability", "discharge", "station", "doctor", "visits", "ensure", "suites", "gear", "preauthorization", "instructions"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_16", question = "Name of Hospital", answer = "The Name of the Hospital is All is Well Hospital. I'm here to assist you, Welcome to All Is Well Hospital. I'm your digital assistant—ready to help with directions, appointments, or information.", keywords = listOf("help", "hospital", "well", "appointments", "name", "here", "assistantready", "welcome", "all", "directions"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_17", question = "Who is the Director?", answer = "Kabir Chouksey and Devanshi Chouksey is the Director of the hospital.", keywords = listOf("hospital", "director", "devanshi", "chouksey", "who", "kabir"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_18", question = "Who is Kabir Chouksey?", answer = "Kabir Chouksey is the Director of the hospital.", keywords = listOf("hospital", "director", "chouksey", "who", "kabir"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_19", question = "Who is Devanshi Chouksey?", answer = "Devanshi Chouksey is the Director of the hospital.", keywords = listOf("hospital", "director", "devanshi", "chouksey", "who"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_51", question = "What is Hospital's Email?", answer = "You can reach the hospital via email at frontdesk@alliswellhospital.com. This email address is monitored by the hospital's administrative team and can be used for general inquiries, appointment requests, health package details, feedback, or non-urgent medical coordination.", keywords = listOf("recommended", "query", "sending", "feedback", "quicker", "receive", "number", "package", "medical", "brief"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_52", question = "How many OTs are there?", answer = "There are 6+ Modular OTs in All is Well", keywords = listOf("well", "there", "many", "all", "how", "modular", "ots"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_53", question = "How many rooms are there in hospital?", answer = "There are around 350 rooms in our hospital.", keywords = listOf("hospital", "there", "around", "our", "many", "350", "rooms", "how"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_54", question = "How many beds are there in hospital?", answer = "There are 360+ beds in hospital.", keywords = listOf("hospital", "there", "many", "beds", "360", "how"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_55", question = "What are the core Values of All is Well?", answer = "1)Valuing Time , 2) Striving for Excellence, 3) Practicing Humility, 4) Fostering Inclusion , 5) Living with Integrity.", keywords = listOf("integrity", "inclusion", "well", "core", "fostering", "practicing", "striving", "all", "1valuing", "excellence"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_56", question = "Which Hospital is best in All is Well Hospital?", answer = "All is Well Hospital is Counted in best hospitals in Burhanpur.", keywords = listOf("which", "hospital", "well", "best", "all", "hospitals", "counted", "burhanpur"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_57", question = "What is Hospital Opening timing?", answer = "Mon - Fri: 8:00 AM - 8:00 PM | Sat - Sun: 9:00 AM - 6:00 PM", keywords = listOf("900", "hospital", "mon", "sat", "800", "opening", "sun", "600", "timing", "fri"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_58", question = "Where is All is Well Hospital located?", answer = "Near Macro Vision Academy, Burhanpur, Madhya Pradesh, 450331", keywords = listOf("madhya", "academy", "hospital", "well", "macro", "near", "pradesh", "all", "vision", "located"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_59", question = "How can i contact to hospital?", answer = "You can contact on +91 7697744444 or +91 7089099888", keywords = listOf("hospital", "7089099888", "contact", "7697744444", "how"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_60", question = "What is the email for all is well hospital?", answer = "digitalmarketing@mvaburhanpur.com", keywords = listOf("hospital", "well", "email", "all", "digitalmarketingmvaburhanpurcom"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_61", question = "Do I need a referral to see a specialist?", answer = "No referral is needed for most departments; you can directly book with the specialist of your choice.", keywords = listOf("referral", "departments", "specialist", "most", "choice", "directly", "need", "book", "needed", "see"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_62", question = "How can I see which doctor treats my condition?", answer = "Visit \"Meet Our Specialists\" on the website to filter doctors by department and view their expertise.", keywords = listOf("which", "meet", "our", "website", "view", "expertise", "department", "specialists", "visit", "see"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_63", question = "Are your doctors experienced?", answer = "Yes, our team includes qualified consultants with fellowships and specialized training in their fields.", keywords = listOf("our", "includes", "yes", "qualified", "fields", "specialized", "experienced", "their", "fellowships", "doctors"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_64", question = "What health check-up packages do you offer?", answer = "We offer Basic Wellness (₹899), Comprehensive Wellness (₹4999), Women's, Diabetic, Pregnancy, and Child packages.", keywords = listOf("wellness", "899", "4999", "womens", "offer", "checkup", "diabetic", "packages", "health", "pregnancy"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_65", question = "Are the health packages discounted?", answer = "Yes, all packages currently offer 25–53% off the original price—check the website for latest offers.", keywords = listOf("2553", "discounted", "yes", "currently", "offer", "original", "pricecheck", "all", "offers", "off"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_66", question = "What's included in the Diabetic Wellness package?", answer = "It includes HbA1c, sugar tests, ECG, 2D Echo, kidney/liver tests, eye exam, and consultations with physician & dietitian.", keywords = listOf("wellness", "exam", "eye", "includes", "package", "sugar", "consultations", "hba1c", "kidneyliver", "dietitian"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_67", question = "Do you offer dietitian consultations?", answer = "Yes, dietitian consultations are included in Comprehensive Wellness and Diabetic Wellness packages.", keywords = listOf("wellness", "consultations", "yes", "offer", "dietitian", "included", "diabetic", "packages", "comprehensive"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_68", question = "Are your services affordable?", answer = "We provide high-quality, cost-effective care with transparent pricing and discounted wellness packages.", keywords = listOf("services", "provide", "transparent", "wellness", "costeffective", "discounted", "highquality", "affordable", "care", "packages"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_69", question = "Is parking available at the hospital?", answer = "Yes, we offer free parking for patients and visitors near the main entrance.", keywords = listOf("patients", "hospital", "free", "near", "yes", "offer", "entrance", "available", "parking", "visitors"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_70", question = "Do you accept walk-in patients?", answer = "Yes, walk-ins are welcome for general consultation; appointments help reduce waiting time.", keywords = listOf("patients", "help", "waiting", "time", "appointments", "walkins", "yes", "welcome", "general", "consultation"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_71", question = "Can I get a bill estimate before treatment?", answer = "Yes, our front desk can provide a tentative cost estimate after a brief consultation with the doctor.", keywords = listOf("get", "before", "bill", "provide", "our", "desk", "tentative", "yes", "treatment", "front"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_72", question = "Can I access my past visit history online?", answer = "Hospital have all past detail of the patient every patient has a unique ID at the time of first visit from there they can access there past history.", keywords = listOf("online", "has", "patient", "hospital", "access", "detail", "there", "unique", "from", "history"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_73", question = "Do you share reports with other doctors?", answer = "Yes, with your consent, we can share digital or printed reports with any specialist you refer to.", keywords = listOf("refer", "share", "yes", "other", "consent", "specialist", "digital", "doctors", "reports", "any"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_74", question = "What should I do in a medical emergency?", answer = "Call our emergency number immediately or visit the hospital—our 24/7 team is ready to help.", keywords = listOf("should", "call", "247", "help", "our", "number", "hospitalour", "medical", "immediately", "visit"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_75", question = "Is the hospital wheelchair-accessible?", answer = "Yes, the entire facility is ramp-enabled and wheelchair-friendly for patient comfort.", keywords = listOf("patient", "hospital", "rampenabled", "yes", "entire", "wheelchairaccessible", "comfort", "facility", "wheelchairfriendly"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_76", question = "How do I use the WhatsApp chat feature?", answer = "Click the WhatsApp icon on the website to start a chat for appointment help or quick queries.", keywords = listOf("use", "click", "help", "start", "queries", "website", "icon", "feature", "quick", "chat"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_77", question = "Can I reschedule my appointment online?", answer = "Yes, log in to your booking or message us via WhatsApp to change your slot.", keywords = listOf("online", "via", "reschedule", "yes", "message", "whatsapp", "booking", "change", "slot", "appointment"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_78", question = "Do you provide food for patients and attendants?", answer = "Yes, we offer hygienic, dietitian-approved meals; special diets can be arranged on request.", keywords = listOf("patients", "diets", "provide", "food", "special", "yes", "offer", "meals", "arranged", "request"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_79", question = "Is your hospital accredited or certified?", answer = "Yes, we follow national healthcare standards and maintain certified protocols for safety, hygiene, and treatment.", keywords = listOf("protocols", "hospital", "maintain", "yes", "treatment", "standards", "safety", "follow", "healthcare", "accredited"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_80", question = "What makes your hospital different?", answer = "We combine experienced specialists, advanced diagnostics, transparent pricing, and patient-first care under one roof.", keywords = listOf("hospital", "different", "transparent", "one", "patientfirst", "diagnostics", "specialists", "roof", "experienced", "care"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_81", question = "Do you serve rural or remote patients?", answer = "Yes, we welcome patients from all areas and offer tele-consultation support for those traveling from far.", keywords = listOf("patients", "serve", "those", "teleconsultation", "rural", "remote", "yes", "from", "offer", "welcome"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_82", question = "Is your hospital eco-friendly or sustainable?", answer = "We follow green practices like waste segregation, energy-efficient systems, and reduced plastic use where possible.", keywords = listOf("practices", "use", "hospital", "green", "reduced", "possible", "energyefficient", "waste", "follow", "systems"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_83", question = "Can I tour the hospital before admission?", answer = "Yes, our front desk can arrange a guided visit—just call ahead or request via WhatsApp.", keywords = listOf("call", "before", "hospital", "our", "desk", "visitjust", "via", "yes", "ahead", "front"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_84", question = "How do I give feedback or file a complaint?", answer = "Share your experience via the \"Contact Us\" , WhatsApp, or after the discharge of the patient, the patient care will contact you for the feedback—we value your input.", keywords = listOf("patient", "will", "feedbackwe", "via", "share", "discharge", "feedback", "complaint", "experience", "contact"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_85", question = "Are your doctors full-time staff?", answer = "Yes, our core specialists are dedicated full-time consultants ensuring consistent, reliable care.", keywords = listOf("staff", "consistent", "our", "fulltime", "reliable", "yes", "core", "specialists", "dedicated", "care"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_86", question = "Is patient privacy protected?", answer = "All medical records and personal data are confidential and shared only with your consent.", keywords = listOf("patient", "records", "shared", "personal", "consent", "medical", "all", "only", "privacy", "data"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_87", question = "Who is Anand Prakash Chouksey?", answer = "Anand Prakash Chouksey is the founder of All is Well Hospital.", keywords = listOf("hospital", "well", "chouksey", "who", "anand", "all", "prakash", "founder"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_88", question = "Is Hospital NABH certified?", answer = "Yes we're NABH certified.You can view it on our website.", keywords = listOf("nabh", "hospital", "were", "view", "our", "yes", "certifiedyou", "certified", "website"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_89", question = "Is the hospital ISO 9001 certified?", answer = "Yes, the hospital is ISO 9001 certified.", keywords = listOf("hospital", "yes", "9001", "certified", "iso"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_90", question = "Doctors Count ?", answer = "There are more than 30+ doctors available.", keywords = listOf("there", "available", "doctors", "more", "count", "than"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_91", question = "Can I book appointment online ?", answer = "Yes, You can book appointment online directly through website or by calling on reception.", keywords = listOf("online", "through", "reception", "yes", "calling", "directly", "book", "appointment", "website"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_92", question = "Is Emergency Services available ?", answer = "Yes, Emergency services are available 24/7 in our hospital.", keywords = listOf("247", "services", "hospital", "our", "yes", "available", "emergency"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_93", question = "What is Ambulance number?", answer = "Call ambulance: +91 7697744444", keywords = listOf("call", "number", "7697744444", "ambulance"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_94", question = "What time does the cafeteria stop serving breakfast/lunch/dinner?", answer = "Cafeterias serve meals during standard morning, midday, and evening windows. Arrive midway through any meal period to ensure you don't miss the cutoff.", keywords = listOf("midday", "standard", "cutoff", "arrive", "any", "breakfastlunchdinner", "through", "ensure", "stop", "period"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_95", question = "What time do doctors do ward rounds?", answer = "Ward rounds commonly happen once or twice a day.", keywords = listOf("happen", "day", "commonly", "twice", "ward", "rounds", "once", "doctors", "time"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_96", question = "What are the surgery scheduling hours?", answer = "Surgeries are generally scheduled during regular weekday daytime hours. For specific timing, please check with reception, as schedules vary based on availability and urgency.", keywords = listOf("based", "availability", "urgency", "specific", "schedules", "weekday", "regular", "surgery", "please", "timing"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_97", question = "When are health camps or screening drives held?", answer = "There are many health camps held by the hospital previously in panchayat & clinics, cardiology camp many more camps like this were held.", keywords = listOf("camps", "cardiology", "hospital", "were", "there", "previously", "more", "many", "clinics", "when"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_98", question = "Can I bring my own food for the patient?", answer = "Yes, you can bring food but give it after the concerned by the specialist only.", keywords = listOf("but", "patient", "concerned", "bring", "food", "own", "yes", "specialist", "only", "give"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_99", question = "Is photography or video recording allowed inside?", answer = "For privacy and safety reasons, photography and video recording are generally not permitted inside. Please check with reception for any specific guidelines or exceptions.", keywords = listOf("guidelines", "recording", "generally", "allowed", "reception", "not", "safety", "please", "check", "exceptions"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_100", question = "Do you offer payment plans or EMI for expensive treatments?", answer = "We understand treatment costs can vary, and flexible payment options may be available. Kindly speak with reception to explore plans or EMI details suited to your needs.", keywords = listOf("offer", "may", "options", "available", "plans", "emi", "treatment", "treatments", "details", "payment"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_101", question = "Is there a discount for government employees or senior citizens?", answer = "No, there is no discount like this right now but the employees who is working under Micro vision academy, All is Well can be treated by the vision card.", keywords = listOf("well", "treated", "senior", "right", "government", "micro", "vision", "this", "under", "working"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_102", question = "What happens if I can't pay the full bill immediately?", answer = "If you can't pay the full bill immediately, please speak with reception—they can guide you through available support options or payment arrangements.", keywords = listOf("bill", "payment", "through", "cant", "guide", "immediately", "please", "support", "available", "full"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_103", question = "What should I do if I suspect a heart attack or stroke?", answer = "Alert any staff member immediately or call the emergency no. +91 7697744444.", keywords = listOf("should", "heart", "staff", "call", "attack", "stroke", "alert", "immediately", "member", "7697744444"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_104", question = "Do you have a poison control or toxicology unit?", answer = "For poisoning concerns, contact reception or emergency services immediately for rapid guidance and care coordination.", keywords = listOf("unit", "services", "concerns", "reception", "guidance", "toxicology", "contact", "rapid", "poison", "have"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_105", question = "What is the protocol if a patient's condition suddenly worsens?", answer = "Alert any nearby staff or press the emergency call button—our team is trained to respond quickly to urgent changes. Reception can also assist with immediate escalation.", keywords = listOf("changes", "immediate", "respond", "alert", "trained", "press", "urgent", "condition", "any", "suddenly"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_106", question = "Do you offer genetic testing or advanced molecular diagnostics?", answer = "While we don't conduct genetic or advanced molecular tests on-site, we can refer you to trusted partner labs. They will perform the test and share the report through us for your doctor to review.", keywords = listOf("conduct", "refer", "molecular", "offer", "testing", "partner", "doctor", "through", "review", "onsite"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_107", question = "Can I get vitamin D, B12, or hormone tests without a prescription?", answer = "Most routine tests—including Vitamin D, B12, and hormone panels—can be done without a prescription. The only exception is pregnancy testing, which requires a doctor's prescription.", keywords = listOf("get", "which", "testing", "most", "done", "exception", "without", "prescription", "tests", "pregnancy"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_108", question = "Do patient rooms have TVs or entertainment options?", answer = "Room amenities like TVs vary by category (General, Silver, Diamond, or Platinum). Please check with reception for what's included in your selected room.", keywords = listOf("diamond", "entertainment", "rooms", "options", "tvs", "amenities", "room", "please", "general", "category"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_109", question = "Is there a refrigerator or microwave in the room?", answer = "These conveniences depend on your room type. Reception can confirm availability based on your booking.", keywords = listOf("confirm", "there", "microwave", "reception", "availability", "based", "room", "these", "booking", "type"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_110", question = "Do you provide laundry services for patients?", answer = "For inquiries about laundry services, please check with reception—they can provide the most up-to-date information on availability", keywords = listOf("patients", "uptodate", "services", "provide", "inquiries", "availability", "most", "about", "please", "check"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_111", question = "Is free WiFi available in patient rooms and waiting areas?", answer = "WiFi availability differs across room types and common areas. For access details, please ask reception at check-in.", keywords = listOf("availability", "rooms", "available", "room", "please", "common", "waiting", "details", "differs", "ask"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_112", question = "Do you offer a mobile app for appointments and reports?", answer = "you can book appointments, generate tokens, and access reports via our website or WhatsApp. Reception is also happy to assist with bookings anytime.", keywords = listOf("our", "happy", "offer", "bookings", "book", "mobile", "assist", "reports", "website", "appointments"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_113", question = "Do you issue birth/death certificates?", answer = "Yes, the hospital processes applications for birth and death certificates. For queries or assistance, please contact the MRD (Medical Records Department) or check with reception for direction.", keywords = listOf("queries", "certificates", "issue", "department", "birthdeath", "direction", "records", "death", "medical", "processes"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_114", question = "Do you conduct free health camps in nearby villages?", answer = "Yes, we regularly conduct free health camps in nearby villages. For schedules or participation details, please inquire at reception.", keywords = listOf("conduct", "camps", "inquire", "schedules", "nearby", "free", "yes", "reception", "regularly", "participation"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_115", question = "Can I volunteer or intern at the hospital?", answer = "Yes, we welcome volunteers and interns to work under our specialists. Please speak with reception to learn about opportunities and the application process.", keywords = listOf("our", "application", "welcome", "specialists", "volunteers", "please", "learn", "opportunities", "under", "hospital"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_116", question = "Do you offer medical training or certification courses?", answer = "Yes, we offer medical training programs with certification upon completion.", keywords = listOf("upon", "certification", "completion", "yes", "offer", "programs", "medical", "courses", "training"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_117", question = "How many visitors are allowed at a time?", answer = "For general wards, one visitor with a patient pass is allowed at a time. ICU visits are restricted to 1–2 close relatives during designated hours (11 AM–12 PM and 6 PM–7 PM).", keywords = listOf("many", "am12", "pass", "close", "visits", "visitor", "general", "visitors", "pm7", "how"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_118", question = "Can children visit patients in ICU?", answer = "Children under 12 are generally not permitted in ICU to ensure patient safety and infection control. Please consult the nursing station for any exceptions.", keywords = listOf("nursing", "station", "any", "patients", "ensure", "safety", "please", "consult", "control", "permitted"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_119", question = "What items can I bring for the patient?", answer = "You may bring essential personal items, prescribed medicines, and light snacks. Always check with nursing staff before bringing outside food or gifts, especially for ICU patients.", keywords = listOf("prescribed", "especially", "nursing", "personal", "items", "may", "medicines", "patients", "before", "bring"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_120", question = "Are flowers or outside food allowed in patient rooms?", answer = "Flowers and outside food are not allowed in ICU/critical care areas. For general wards, please confirm with the nursing team before bringing such items.", keywords = listOf("nursing", "items", "care", "rooms", "flowers", "before", "confirm", "food", "icucritical", "please"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_121", question = "Can I stay overnight with the patient?", answer = "Yes, one attendant may stay overnight in private rooms or designated guest rooms (102, 103, 221, 222), subject to availability and hospital policy.", keywords = listOf("availability", "may", "rooms", "222", "102", "overnight", "221", "103", "stay", "hospital"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_122", question = "Can I video call the patient if I cannot visit physically?", answer = "Yes, video calls are permitted with the patient's consent and nursing staff coordination, especially for ICU patients or when physical visits aren't possible.", keywords = listOf("especially", "arent", "nursing", "consent", "patients", "visits", "coordination", "permitted", "video", "call"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_123", question = "Can I visit multiple patients in one trip?", answer = "Yes, you may visit multiple patients during visiting hours. Please collect separate visitor passes for each patient at the reception desk.", keywords = listOf("desk", "each", "may", "separate", "patients", "passes", "trip", "please", "visitor", "hours"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_124", question = "What items are prohibited in patient rooms or ICU?", answer = "Prohibited items include outside food (in ICU), flowers, sharp objects, alcohol, tobacco, and large electronics. Please check with staff for a complete, updated list.", keywords = listOf("items", "rooms", "flowers", "sharp", "food", "updated", "alcohol", "please", "tobacco", "electronics"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_126", question = "How do I confirm if my appointment is booked?", answer = "After booking, you'll receive a token number via SMS/WhatsApp as confirmation. You can also call +91 76977 44444 or +91 70890 99888 or check with reception to verify your appointment status.", keywords = listOf("booked", "smswhatsapp", "booking", "token", "receive", "status", "confirm", "44444", "number", "99888"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_127", question = "What happens if I miss my appointment slot?", answer = "If you miss your slot, please contact reception at +91 76977 44444 or +91 70890 99888 to reschedule. Walk-in consultations may be available based on doctor availability, though waiting times may apply.", keywords = listOf("based", "availability", "times", "may", "available", "doctor", "though", "44444", "please", "99888"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_128", question = "Can I get a same-day or urgent appointment?", answer = "Yes, same-day walk-in consultations are available for general OPD on a first-come, first-served basis. For urgent medical needs, our 24/7 emergency services are always accessible.", keywords = listOf("get", "our", "available", "urgent", "247", "services", "firstserved", "accessible", "sameday", "medical"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_129", question = "How do I reschedule or cancel my appointment?", answer = "You can reschedule or cancel by calling +91 76977 44444 or +91 70890 99888, messaging via WhatsApp, or logging into your online booking. Please provide prior notice to free the slot for other patients.", keywords = listOf("other", "calling", "booking", "online", "patients", "44444", "prior", "logging", "please", "99888"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_130", question = "Is there a separate counter for senior citizens or pregnant women?", answer = "While there's no dedicated counter, senior citizens and pregnant women receive priority assistance at reception. Please inform staff upon arrival for expedited support.", keywords = listOf("women", "separate", "counter", "receive", "upon", "expedited", "inform", "senior", "please", "dedicated"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_131", question = "Do I need to carry previous medical reports for consultation?", answer = "Yes, carrying previous medical reports, prescriptions, and test results helps your doctor make accurate decisions. Please also bring a valid ID and insurance documents if applicable.", keywords = listOf("previous", "consultation", "doctor", "applicable", "bring", "medical", "carry", "please", "reports", "test"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_132", question = "Can I consult a doctor via phone or video call?", answer = "Yes, tele-consultation via video/phone is available for remote patients. Contact +91 76977 44444 or use the WhatsApp feature on our website to schedule a virtual consultation.", keywords = listOf("our", "virtual", "available", "consultation", "doctor", "patients", "44444", "consult", "video", "videophone"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_133", question = "How early should I arrive before my appointment time?", answer = "We recommend arriving 15–20 minutes before your scheduled time for registration and token collection. For first-time visits, please allow an extra 10 minutes for documentation.", keywords = listOf("recommend", "extra", "token", "arrive", "documentation", "should", "before", "minutes", "visits", "1520"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_134", question = "Can I pay using UPI, Google Pay, or PhonePe?", answer = "Yes, we accept UPI payments including Google Pay, PhonePe, and Paytm, along with cash, cards, and net banking at all billing counters.", keywords = listOf("using", "including", "yes", "payments", "along", "banking", "upi", "paytm", "cash", "google"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_135", question = "Do you provide an itemized/detailed bill?", answer = "Yes, you can request an itemized bill showing consultation fees, tests, medicines, and room charges at the billing counter during or after payment.", keywords = listOf("bill", "payment", "provide", "charges", "during", "itemizeddetailed", "yes", "room", "itemized", "fees"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_136", question = "Can I receive my payment receipt via email or WhatsApp?", answer = "Yes, payment receipts can be shared via your registered WhatsApp number or email upon request at the billing desk.", keywords = listOf("payment", "via", "shared", "receipts", "number", "yes", "upon", "desk", "email", "request"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_137", question = "What should I do if there is an error in my bill?", answer = "Please inform the billing counter staff immediately or call +91 76977 44444; our team will verify and correct any discrepancies promptly.", keywords = listOf("our", "correct", "discrepancies", "counter", "billing", "any", "should", "44444", "inform", "please"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_138", question = "Do you accept international health insurance?", answer = "Currently, we primarily accept Indian health insurance providers and government schemes like Ayushman Bharat; for international policies, please contact our billing desk for case-by-case assistance.", keywords = listOf("our", "desk", "providers", "billing", "indian", "bharat", "currently", "government", "please", "accept"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_139", question = "Can I get a tentative cost estimate before treatment starts?", answer = "Yes, after a brief consultation, our front desk can provide a tentative cost estimate for procedures, tests, or admissions.", keywords = listOf("get", "before", "starts", "provide", "our", "desk", "tentative", "yes", "treatment", "admissions"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_140", question = "Is there a separate billing counter for insurance patients?", answer = "While there's no dedicated counter, our billing team has specialized staff to assist insurance patients with cashless pre-authorization and documentation.", keywords = listOf("patients", "has", "staff", "there", "our", "while", "cashless", "dedicated", "specialized", "separate"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_141", question = "How do I claim a refund if treatment is cancelled?", answer = "Refund requests are processed at the billing desk with doctor approval and original payment proof; please contact +91 76977 44444 for guidance on your specific case.", keywords = listOf("desk", "guidance", "claim", "proof", "doctor", "specific", "billing", "approval", "44444", "processed"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_142", question = "Can I pay my bill in installments or EMI?", answer = "For eligible treatments and admissions, EMI options through partner banks may be available; please discuss with our billing desk at the time of admission.", keywords = listOf("our", "desk", "partner", "may", "options", "available", "discuss", "billing", "eligible", "emi"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_143", question = "Is there a discount for cash payment or early payment?", answer = "Discounted rates are available on our health check-up packages; for other services, please inquire at the billing counter for any ongoing offers or concessions.", keywords = listOf("our", "other", "available", "packages", "counter", "billing", "any", "services", "please", "rates"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_144", question = "How do I get a duplicate bill if I lose the original?", answer = "Visit the billing counter with a valid ID and patient details to request a duplicate bill; a nominal processing fee may apply, and the copy will be stamped for official use.", keywords = listOf("get", "lose", "may", "counter", "billing", "nominal", "request", "processing", "details", "how"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_145", question = "Do you offer concessions for senior citizens or BPL card holders?", answer = "Concessions may be available for eligible patients. For details on applicable benefits, please contact the Insurance Department or check with reception.", keywords = listOf("offer", "department", "may", "available", "eligible", "patients", "applicable", "senior", "please", "details"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_146", question = "Is Ayushman Bharat / PM-JAY card accepted here?", answer = "Yes, we accept Ayushman Bharat / PM-JAY cards. For eligibility, coverage, and claim assistance, please speak with the Insurance Department.", keywords = listOf("bharat", "yes", "here", "department", "card", "eligibility", "claim", "assistance", "please", "speak"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_147", question = "Who can I contact for insurance-related queries at the hospital?", answer = "You can contact to Ashish Rawale for all the insurance queries.", keywords = listOf("queries", "hospital", "insurancerelated", "contact", "who", "all", "insurance", "ashish", "rawale"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_148", question = "What if I need emergency surgery but have no insurance?", answer = "Emergency care is provided based on medical need, regardless of insurance status. For financial support options or billing guidance, please contact the Insurance Department after stabilization.", keywords = listOf("provided", "based", "guidance", "department", "stabilization", "care", "options", "billing", "status", "medical"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_149", question = "What should I do if I lose a personal item in the hospital?", answer = "Please inform the reception desk or call +91 76977 44444 immediately; our staff will help you search and coordinate with security for recovery.", keywords = listOf("desk", "our", "personal", "lose", "item", "should", "44444", "recovery", "inform", "please"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_150", question = "Is there a lost and found desk or contact?", answer = "Lost items are managed at the reception/security desk near the main entrance—please contact them directly or call +91 76977 44444 for assistance.", keywords = listOf("call", "receptionsecurity", "76977", "desk", "there", "44444", "near", "items", "contact", "assistance"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_151", question = "Can the hospital help me book a taxi, auto, or cab?", answer = "Yes, our reception team can assist you in arranging local transport, or you can directly book an auto transport via our online auto booking app.", keywords = listOf("cab", "our", "booking", "book", "auto", "arranging", "online", "transport", "team", "assist"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_152", question = "Can I get a visit summary letter for my employer or school?", answer = "Yes, you can request a visit summary or medical certificate at the reception or billing desk after consultation; please carry valid ID for verification.", keywords = listOf("get", "summary", "desk", "consultation", "billing", "verification", "medical", "please", "carry", "request"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_153", question = "Where can I buy toiletries, blankets, or essentials for the patient?", answer = "Our in-house pharmacy and nearby cafeteria stock basic essentials; for specialized items, please ask reception—they can assist with procurement or local vendor guidance.", keywords = listOf("our", "stock", "guidance", "items", "procurement", "specialized", "receptionthey", "blankets", "vendor", "please"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_154", question = "Is there a cloakroom or locker facility available?", answer = "While dedicated lockers aren't available, reception can help store small valuables temporarily; we recommend keeping important items with you for security.", keywords = listOf("arent", "recommend", "important", "items", "facility", "available", "keeping", "valuables", "temporarily", "dedicated"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_155", question = "Do you have facilities for visually or hearing-impaired patients?", answer = "Yes, the hospital is wheelchair-accessible with ramps and elevators; please inform reception upon arrival for personalized assistance and communication support.", keywords = listOf("ramps", "facilities", "wheelchairaccessible", "hearingimpaired", "patients", "elevators", "upon", "inform", "visually", "please"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_156", question = "Can elderly or differently-abled patients get priority service?", answer = "Yes, senior citizens and differently-abled patients receive priority assistance at reception and OPD—just inform staff upon arrival for expedited support.", keywords = listOf("get", "elderly", "receive", "patients", "upon", "differentlyabled", "expedited", "inform", "senior", "priority"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_157", question = "Is there a private lactation or nursing room for mothers?", answer = "While a dedicated lactation room isn't specified, private rooms and guest areas can be arranged for nursing mothers upon request at reception.", keywords = listOf("nursing", "there", "mothers", "while", "upon", "reception", "room", "dedicated", "areas", "rooms"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_158", question = "Where can I park my vehicle for multiple days during admission?", answer = "Free parking is available near the main entrance for patients and visitors; for multi-day parking during admission, please register your vehicle at reception for security coordination.", keywords = listOf("multiday", "vehicle", "park", "available", "patients", "near", "days", "multiple", "please", "coordination"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_159", question = "Do I need a doctor's prescription for lab tests?", answer = "Yes, a valid doctor's prescription is required for most diagnostic tests to ensure appropriate testing and accurate interpretation of results.", keywords = listOf("valid", "required", "accurate", "yes", "testing", "diagnostic", "most", "ensure", "appropriate", "need"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_160", question = "Can I walk in for a blood test without an appointment?", answer = "Yes, our 24/7 laboratory accepts walk-in patients for blood tests; simply register at the lab counter with your prescription or it can be done without prescription.", keywords = listOf("our", "simply", "counter", "247", "patients", "done", "without", "prescription", "tests", "laboratory"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_161", question = "How do I give a urine or stool sample?", answer = "Clean collection containers and instructions are provided at the lab counter; please follow the hygiene guidelines shared by our staff for accurate results.", keywords = listOf("provided", "our", "stool", "clean", "counter", "hygiene", "sample", "shared", "containers", "urine"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_162", question = "Is home sample collection service available?", answer = "Home sample collection may be available for select tests and areas; please call +91 76977 44444 or WhatsApp us to check eligibility and schedule.", keywords = listOf("sample", "call", "select", "44444", "service", "schedule", "eligibility", "please", "check", "areas"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_163", question = "How long are lab reports considered valid?", answer = "Report validity depends on the test and clinical context; generally, routine reports are valid for 3–6 months, but your doctor will advise based on your condition.", keywords = listOf("based", "doctor", "condition", "validity", "considered", "depends", "advise", "long", "reports", "test"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_164", question = "Do you provide both hard copy and digital soft copy of reports?", answer = "Yes, lab reports are delivered digitally via your registered WhatsApp number and can also be collected as printed copies from the report counter.", keywords = listOf("collected", "delivered", "digitally", "registered", "digital", "counter", "soft", "number", "from", "reports"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_165", question = "Can I repeat a test if I doubt the result?", answer = "Yes, you may request a repeat test after consulting your doctor; please discuss your concerns with the lab staff or treating physician for guidance.", keywords = listOf("staff", "lab", "concerns", "yes", "result", "guidance", "please", "physician", "may", "doubt"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_166", question = "What if I need a specialized test not available here?", answer = "For specialized tests not available onsite, our team can coordinate with accredited external labs; please consult your doctor or the lab desk for assistance.", keywords = listOf("our", "desk", "specialized", "available", "doctor", "onsite", "here", "external", "please", "accredited"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_167", question = "Can I access my reports through an online patient portal?", answer = "Digital reports are shared via WhatsApp or email please check with reception for the latest updates.", keywords = listOf("online", "patient", "portal", "access", "shared", "through", "via", "reception", "latest", "email"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_168", question = "Is the pharmacy located inside or outside the main building?", answer = "Our in-house pharmacy is located inside the main hospital building on the ground floor for easy access.", keywords = listOf("outside", "floor", "hospital", "building", "our", "access", "ground", "inhouse", "easy", "inside"), category = "pharmacy", language = "en" ), KnowledgeBaseQA( id = "qa_169", question = "Do you have all prescribed medicines in stock?", answer = "We maintain a comprehensive stock of essential medicines; if a specific item is unavailable, we can arrange procurement within 24 hours.", keywords = listOf("prescribed", "stock", "maintain", "hours", "within", "unavailable", "procurement", "all", "have", "essential"), category = "pharmacy", language = "en" ), KnowledgeBaseQA( id = "qa_170", question = "Are generic/low-cost medicine options available?", answer = "Yes, we offer both branded and affordable generic medicine options as per your doctor's prescription and preference.", keywords = listOf("per", "genericlowcost", "branded", "yes", "offer", "affordable", "medicine", "available", "options", "generic"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_171", question = "Do you offer home delivery for medicines?", answer = "No, the In-house pharmacy of our hospital do not offer home deliver for medicines.", keywords = listOf("hospital", "deliver", "our", "offer", "not", "inhouse", "home", "medicines", "pharmacy", "delivery"), category = "pharmacy", language = "en" ), KnowledgeBaseQA( id = "qa_172", question = "Can I buy over-the-counter medicines without a prescription?", answer = "Yes, basic OTC medicines like pain relievers or vitamins are available without prescription; prescription medicines require a valid doctor's prescription.", keywords = listOf("overthecounter", "vitamins", "valid", "yes", "pain", "without", "require", "doctors", "buy", "medicines"), category = "pharmacy", language = "en" ), KnowledgeBaseQA( id = "qa_173", question = "Is the pharmacy open 24/7 for emergency prescriptions?", answer = "Yes, our pharmacy operates 24/7 to serve emergency and urgent prescription needs at any time.", keywords = listOf("247", "serve", "our", "operates", "yes", "pharmacy", "emergency", "needs", "prescription", "prescriptions"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_174", question = "What is the policy for returning unused or unopened medicines?", answer = "For safety and regulatory reasons, we cannot accept returns on dispensed medicines; please confirm your prescription details before purchase.", keywords = listOf("regulatory", "confirm", "before", "policy", "unused", "returning", "safety", "please", "unopened", "cannot"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_175", question = "Do you compound or prepare custom medications?", answer = "For questions about compounded or custom-prepared medicines, please speak with our pharmacy team or your treating specialist—they can advise on availability and options.", keywords = listOf("questions", "compounded", "our", "specialistthey", "availability", "medicines", "treating", "options", "prepare", "customprepared"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_176", question = "Do you offer medication counseling or usage instructions?", answer = "Yes, we provide medication counseling and clear usage instructions. Our pharmacists are happy to walk you through dosage, timing, and precautions.", keywords = listOf("counseling", "provide", "our", "happy", "through", "yes", "offer", "clear", "pharmacists", "usage"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_177", question = "Is there a formulary list I can check for available medicines?", answer = "Medicine availability can vary. For the most accurate and up-to-date information, please check directly with our pharmacy staff.", keywords = listOf("staff", "uptodate", "vary", "formulary", "list", "there", "accurate", "our", "availability", "most"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_178", question = "Do you stock Ayurvedic or herbal medicines?", answer = "Yes, our pharmacy stocks a range of Ayurvedic and herbal products. For specific items or recommendations, kindly ask the pharmacy team.", keywords = listOf("stocks", "products", "stock", "our", "yes", "ayurvedic", "pharmacy", "items", "specific", "medicines"), category = "pharmacy", language = "en" ), KnowledgeBaseQA( id = "qa_179", question = "Does the ambulance have ventilator or life-support equipment?", answer = "Yes, we offer both basic and advanced life-support ambulances equipped with ventilators, oxygen, and emergency monitoring; please specify your requirement when calling +91 76977 44444.", keywords = listOf("offer", "calling", "ventilator", "ambulances", "monitoring", "specify", "44444", "ambulance", "ventilators", "please"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_180", question = "Can I track the ambulance location after booking?", answer = "Real-time tracking is not currently available; however, our dispatch team will provide estimated arrival time and driver contact details upon confirmation.", keywords = listOf("our", "estimated", "booking", "available", "upon", "ambulance", "currently", "location", "however", "details"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_181", question = "Is there a charge for ambulance service, and how much?", answer = "Ambulance charges vary based on distance, type (basic/advanced), and equipment; please contact +91 76977 44444 for a case-specific quote.", keywords = listOf("quote", "based", "distance", "much", "44444", "ambulance", "please", "how", "there", "service"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_182", question = "Can ambulance pick up from my home or another location?", answer = "Yes, our ambulances can pick up patients from home, workplaces, or other locations within Burhanpur and nearby areas—just share the exact address when booking.", keywords = listOf("our", "another", "other", "booking", "areasjust", "burhanpur", "patients", "ambulances", "ambulance", "from"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_183", question = "What details should I provide when calling for an ambulance?", answer = "Please share patient name, age, condition/symptoms, exact pickup location, contact number, and any special requirements (e.g., ventilator, wheelchair access).", keywords = listOf("calling", "ventilator", "any", "should", "age", "ambulance", "number", "please", "location", "details"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_184", question = "Can a family member accompany the patient in the ambulance?", answer = "Yes, one attendant may accompany the patient in most cases; for advanced life-support ambulances, space may be limited—please confirm with the dispatch team.", keywords = listOf("most", "may", "family", "cases", "confirm", "ambulances", "ambulance", "advanced", "team", "member"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_185", question = "Can you arrange ambulance for inter-hospital patient transfer?", answer = "Yes, we coordinate safe inter-hospital transfers with appropriate medical support; please call +91 76977 44444 with patient details and destination hospital for arrangement.", keywords = listOf("safe", "appropriate", "arrangement", "44444", "ambulance", "medical", "please", "destination", "details", "call"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_186", question = "Can I see the room before confirming admission?", answer = "Yes, you can request a brief room view before confirming admission; our admission desk staff will arrange this based on availability and patient priority.", keywords = listOf("our", "desk", "based", "availability", "before", "view", "room", "brief", "request", "this"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_187", question = "Is an attendant bed or recliner provided in the room?", answer = "Yes, private rooms and designated guest rooms (102, 103, 221, 222) include seating or recliner facilities for attendants; please confirm amenities at admission.", keywords = listOf("provided", "facilities", "recliner", "rooms", "222", "102", "attendants", "confirm", "221", "103"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_188", question = "Are patient meals included in the room charge?", answer = "Basic hygienic meals are included in room charges; special or dietitian-approved diets can be arranged on request, with any additional costs communicated upfront.", keywords = listOf("diets", "patient", "charges", "special", "additional", "room", "meals", "communicated", "costs", "included"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_189", question = "Is WiFi available in patient rooms for family?", answer = "Complimentary WiFi is available in common areas; for in-room connectivity, please check with reception for current availability and access instructions.", keywords = listOf("patient", "access", "reception", "availability", "complimentary", "inroom", "current", "please", "check", "areas"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_190", question = "Can I request a room closer to the nursing station?", answer = "Yes, you can request a room near the nursing station for added convenience; we'll accommodate based on availability and medical priority.", keywords = listOf("nursing", "well", "priority", "near", "yes", "based", "station", "room", "closer", "added"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_191", question = "Do private rooms have attached bathrooms?", answer = "Yes, all private room categories (Diamond, Platinum, Golden, Silver, Ruby Suite) include attached bathrooms with essential amenities for patient comfort and hygiene.", keywords = listOf("diamond", "ruby", "suite", "comfort", "rooms", "hygiene", "amenities", "room", "bathrooms", "attached"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_192", question = "Can I change to a different room category after admission?", answer = "Yes, room changes or upgrades are possible subject to availability, please discuss with the admission or billing desk for options and any additional charges.", keywords = listOf("changes", "desk", "additional", "availability", "options", "discuss", "billing", "any", "room", "please"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_193", question = "Are there isolation rooms for infectious disease patients?", answer = "Yes, we have designated isolation rooms and strict infection control protocols for infectious disease patients to ensure safety for all, please inform staff upon admission.", keywords = listOf("rooms", "patients", "upon", "inform", "strict", "ensure", "disease", "safety", "please", "control"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_194", question = "Do you provide bed linens, towels, and basic toiletries?", answer = "Yes, all rooms are provided with clean bed linens, towels, and basic toiletries; additional items can be requested from nursing staff as needed.", keywords = listOf("staff", "bed", "provided", "provide", "nursing", "toiletries", "additional", "linens", "yes", "requested"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_195", question = "Where is the nearest restroom or washroom?", answer = "Restrooms are available on every floor near the elevator lobbies and waiting areas; please follow the signage or ask any staff member for the closest one.", keywords = listOf("restroom", "nearest", "every", "available", "lobbies", "any", "signage", "restrooms", "near", "please"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_196", question = "Is there a cafeteria, canteen, or food court inside?", answer = "Yes, our cafeteria is located on the ground floor near the main lobby, serving hygienic vegetarian and non-vegetarian meals from 7 AM to 9 PM.", keywords = listOf("our", "food", "canteen", "near", "from", "ground", "vegetarian", "nonvegetarian", "floor", "there"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_197", question = "Where can I find safe drinking water?", answer = "Safe, filtered drinking water stations are available on all floors near waiting areas and nursing stations.", keywords = listOf("filtered", "safe", "nursing", "near", "drinking", "floors", "all", "areas", "available", "waiting"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_198", question = "Is there an ATM or cash withdrawal facility on campus?", answer = "Yes, an ATM is located for easy cash withdrawal, additional digital payment options are accepted throughout the hospital.", keywords = listOf("payment", "hospital", "there", "additional", "campus", "yes", "withdrawal", "facility", "easy", "options"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_199", question = "Where can I get a wheelchair or stretcher assistance?", answer = "Wheelchairs and stretchers are available free of charge at the reception desk, simply request assistance and our support staff will help you promptly.", keywords = listOf("get", "desk", "our", "available", "simply", "request", "where", "help", "wheelchairs", "stretchers"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_200", question = "Where can I buy patient care items like masks, gloves, or sanitizers?", answer = "Our 24/7 in-house pharmacy on the ground floor stocks masks, gloves, sanitizers, and other essential patient care items.", keywords = listOf("247", "floor", "patient", "gloves", "sanitizers", "our", "stocks", "other", "items", "masks"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_201", question = "Is there a patient care coordinator or helpdesk I can contact?", answer = "Yes, our Patient Care Desk at reception and the front desk team (+91 76977 44444) are available to assist with coordination, queries, and support throughout your hospital visit.", keywords = listOf("queries", "helpdesk", "our", "desk", "care", "available", "throughout", "coordinator", "44444", "coordination"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_202", question = "How do I report a concern about staff behavior or service quality?", answer = "You can share feedback or concerns directly with the reception desk, call +91 76977 44444, or use the \"Contact Us\" form on our website; all feedback is reviewed promptly by our patient care team.", keywords = listOf("desk", "our", "feedback", "care", "44444", "concern", "team", "how", "call", "use"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_203", question = "Can I seek a second opinion from another specialist in the hospital?", answer = "Yes, you may request a second opinion from another in-house specialist; please discuss with your treating doctor or contact reception to coordinate the consultation.", keywords = listOf("another", "may", "treating", "consultation", "doctor", "discuss", "second", "from", "specialist", "please"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_204", question = "How can I receive regular updates on my patient's condition without being at bedside?", answer = "You can request periodic updates via phone or WhatsApp by providing your contact details to the nursing station; for ICU patients, updates are shared during designated visiting hours or as clinically appropriate.", keywords = listOf("nursing", "station", "appropriate", "condition", "receive", "patients", "shared", "clinically", "regular", "without"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_205", question = "Is there a waiting lounge with seating, charging points, or reading material?", answer = "Yes, we have comfortable waiting areas near OPD and main lobby with seating, drinking water, and basic amenities; charging points and reading material availability may vary—please ask reception for current facilities.", keywords = listOf("facilities", "availability", "comfortable", "may", "water", "amenities", "near", "current", "material", "waiting"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_206", question = "Where is the pharmacy?", answer = "The pharmacy is located on the Ground Floor, directly in front of the reception desk.", keywords = listOf("floor", "desk", "reception", "ground", "front", "directly", "located", "pharmacy", "where"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_207", question = "Where is the pathology lab?", answer = "The pathology department is situated to the left of the reception desk—just follow the signs from there.", keywords = listOf("there", "signs", "left", "reception", "from", "department", "deskjust", "situated", "follow", "pathology"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_208", question = "Where is the blood collection center?", answer = "The blood collection center is located in the hospital Basement.", keywords = listOf("basement", "center", "hospital", "located", "blood", "collection", "where"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_209", question = "Where is the X-ray room?", answer = "The X-ray room and most scans are on the Ground Floor. For MRI and CT scans, please proceed to the Basement floor.", keywords = listOf("floor", "basement", "xray", "room", "ground", "most", "please", "mri", "where", "scans"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_210", question = "Where is the MRI scan center?", answer = "The MRI scan center is located on the Basement floor.", keywords = listOf("basement", "floor", "center", "scan", "mri", "located", "where"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_211", question = "Where is the CT scan room?", answer = "The CT scan room is also on the Basement floor, alongside other advanced imaging services.", keywords = listOf("basement", "floor", "services", "other", "room", "scan", "also", "imaging", "alongside", "advanced"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_212", question = "Where is the ultrasound department?", answer = "Ultrasound services are typically available on the Ground Floor. For exact location, please check with reception or follow directional signs.", keywords = listOf("floor", "exact", "services", "directional", "signs", "reception", "typically", "department", "ground", "please"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_213", question = "Where is the radiology department?", answer = "Most radiology services, including X-ray, are on the Ground Floor; advanced imaging like MRI/CT is on the Basement. Reception can guide you to the right counter.", keywords = listOf("floor", "basement", "services", "xray", "mrict", "including", "reception", "department", "most", "ground"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_214", question = "Where is the diagnostic center?", answer = "Our main diagnostic services are spread across Ground and Basement floors. For a specific test or department, reception can provide quick directions.", keywords = listOf("basement", "services", "center", "provide", "our", "spread", "reception", "diagnostic", "ground", "floors"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_215", question = "Where is the emergency room?", answer = "The Emergency Room is clearly signposted from the main hospital entrance. If you're unsure, please ask reception or any staff member—they'll guide you right away.", keywords = listOf("main", "any", "room", "from", "right", "please", "youre", "clearly", "signposted", "where"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_216", question = "Where is the ICU?", answer = "The ICUs (including KICU, MICU, and NICU) are located on the upper floors. For exact location based on patient need, please check with reception or follow emergency signage.", keywords = listOf("icus", "based", "floors", "upper", "nicu", "micu", "signage", "please", "location", "where"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_217", question = "Where is the cardiology department?", answer = "Cardiology services are available on the Ground Floor. Reception can guide you to the right counter or consultation room.", keywords = listOf("floor", "services", "cardiology", "reception", "room", "department", "ground", "right", "guide", "available"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_218", question = "Where is the pediatrics ward?", answer = "Pediatric care is provided on the Ground Floor. For ward-specific directions, kindly ask reception or look for pediatric signage.", keywords = listOf("floor", "provided", "look", "signage", "wardspecific", "reception", "ground", "ward", "care", "kindly"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_219", question = "Where is the maternity ward?", answer = "The maternity ward is located on the Ground Floor. Reception can assist with visitation guidelines and room directions.", keywords = listOf("floor", "reception", "visitation", "directions", "room", "ground", "maternity", "ward", "guidelines", "located"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_220", question = "Where is the labor room?", answer = "Labor and delivery services are coordinated through the Operation Theater (OT) area. For immediate assistance, please alert reception or any nursing staff.", keywords = listOf("staff", "services", "operation", "immediate", "nursing", "through", "reception", "room", "assistance", "alert"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_221", question = "Where is the NICU?", answer = "The Neonatal ICU (NICU) is located on the 3rd floor. Access is coordinated through medical staff—please check with reception for visitor protocols and directions.", keywords = listOf("neonatal", "floor", "protocols", "icu", "access", "through", "reception", "directions", "where", "medical"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_222", question = "Where is the neurology department?", answer = "Neurology services are located on the Ground Floor. For appointment check-in or directions, please ask reception.", keywords = listOf("floor", "services", "reception", "department", "ground", "neurology", "checkin", "please", "directions", "located"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_223", question = "Where is the dental department?", answer = "Dental care is provided on the Ground Floor. Reception can help you locate the dental clinic and confirm doctor availability.", keywords = listOf("floor", "help", "provided", "confirm", "dental", "reception", "availability", "department", "ground", "clinic"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_224", question = "Where is the surgery department?", answer = "Surgical consultations and pre-op care are coordinated on the Ground Floor. For surgeon availability or appointment check-in, please check with reception.", keywords = listOf("floor", "surgeon", "preop", "consultations", "availability", "reception", "department", "ground", "surgery", "surgical"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_225", question = "Where is the operation theater?", answer = "Our hospital has 6 operation theaters located across different floors. Since surgeries are scheduled based on urgency and specialty, reception can guide you to the correct OT or provide updates on your procedure location.", keywords = listOf("our", "procedure", "based", "correct", "floors", "specialty", "urgency", "theaters", "theater", "since"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_226", question = "Where is the cafeteria?", answer = "All dining options are located beside the back gate of the hospital. Reception can provide quick directions if needed.", keywords = listOf("dining", "quick", "beside", "gate", "hospital", "provide", "cafeteria", "reception", "back", "all"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_227", question = "Where is the vending machine?", answer = "We don't have vending machines on campus, but snacks and meals are available at the canteen beside the back gate.", keywords = listOf("but", "machine", "beside", "machines", "gate", "campus", "canteen", "back", "meals", "dont"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_228", question = "Where is the restaurant?", answer = "All dining options are located beside the back gate of the hospital. Reception can provide quick directions if needed.", keywords = listOf("dining", "quick", "beside", "gate", "hospital", "provide", "reception", "restaurant", "back", "all"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_229", question = "Where is the restroom?", answer = "Restrooms are available on every floor, typically near waiting areas and elevators. If you need directions to the nearest one, please ask reception or any staff member", keywords = listOf("restroom", "every", "nearest", "available", "directions", "any", "elevators", "restrooms", "near", "please"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_230", question = "Where is the waiting area?", answer = "Comfortable seating areas are available on the Ground Floor, near the main entrance and department cabins.", keywords = listOf("floor", "near", "ground", "entrance", "department", "comfortable", "seating", "areas", "cabins", "available"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_231", question = "Where is the reception?", answer = "The main reception desk is located on the Ground Floor, right at the hospital entrance—your first stop for any assistance.", keywords = listOf("floor", "entranceyour", "hospital", "desk", "reception", "ground", "right", "assistance", "stop", "first"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_232", question = "Where is the help desk?", answer = "A dedicated help desk is available on the Ground Floor to guide visitors, answer queries, and provide support.", keywords = listOf("floor", "help", "queries", "provide", "desk", "answer", "ground", "guide", "dedicated", "support"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_233", question = "Where is the registration counter?", answer = "Patient registration is handled at the counter on the Ground Floor, adjacent to the main reception area.", keywords = listOf("floor", "patient", "handled", "reception", "adjacent", "ground", "registration", "counter", "where", "main"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_234", question = "Where is the billing counter?", answer = "Billing and payment services are available at the dedicated counter on the Ground Floor, near the main reception.", keywords = listOf("floor", "services", "payment", "main", "near", "reception", "ground", "dedicated", "available", "counter"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_235", question = "Where is the insurance desk?", answer = "The insurance desk is located on the Ground Floor. For claim assistance, documentation, or policy queries, please visit the desk directly or check with reception for exact directions.", keywords = listOf("floor", "queries", "documentation", "exact", "desk", "reception", "policy", "ground", "claim", "assistance"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_236", question = "Where is the appointment counter?", answer = "Appointments can be booked directly at the reception desk on the Ground Floor—or via our website/WhatsApp for convenience.", keywords = listOf("booked", "appointment", "appointments", "desk", "via", "reception", "our", "ground", "websitewhatsapp", "directly"), category = "appointments", language = "en" ), KnowledgeBaseQA( id = "qa_237", question = "Where is the parking lot?", answer = "General parking is available both in front of the main entrance and near the back gate. Follow signage or ask security for guidance.", keywords = listOf("both", "lot", "gate", "signage", "security", "near", "back", "guidance", "entrance", "front"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_238", question = "Where is the visitor parking?", answer = "Dedicated visitor parking is provided at both the front (main entrance) and back gate areas on the Ground Level.", keywords = listOf("provided", "both", "gate", "back", "ground", "entrance", "front", "level", "visitor", "dedicated"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_239", question = "Where is the ambulance bay?", answer = "The ambulance bay is located directly in front of the main entrance for quick emergency access. Staff are always ready to assist upon arrival.", keywords = listOf("staff", "quick", "access", "upon", "ambulance", "arrival", "bay", "entrance", "front", "directly"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_240", question = "Where is the lift?", answer = "Lifts are located near the staircase, just beside the reception desk on the Ground Floor.", keywords = listOf("floor", "beside", "lifts", "desk", "near", "reception", "ground", "staircase", "just", "located"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_241", question = "Where is the staircase?", answer = "Staircases are conveniently situated near the reception desk on the Ground Floor for easy access to all floors.", keywords = listOf("floor", "desk", "access", "near", "reception", "conveniently", "ground", "floors", "staircase", "all"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_242", question = "Where is the wheelchair access?", answer = "Wheelchairs are available right at the main entrance—just inform any staff member or security for immediate assistance.", keywords = listOf("staff", "immediate", "entrancejust", "access", "wheelchair", "security", "inform", "wheelchairs", "right", "assistance"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_243", question = "Where is the ramp?", answer = "A ramp is available for easy access. Please ask any staff member for guidance or support while using it.", keywords = listOf("staff", "using", "access", "while", "guidance", "any", "ramp", "please", "support", "easy"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_244", question = "Where is the ATM?", answer = "An ATM is available in front of the back entrance, beside Nacl Restaurant.", keywords = listOf("nacl", "beside", "where", "restaurant", "entrance", "front", "available", "back", "atm"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_245", question = "Where is the locker room?", answer = "Locker facilities are available in the Basement. Please check with reception for access instructions.", keywords = listOf("basement", "facilities", "access", "reception", "room", "locker", "please", "check", "available", "where"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_246", question = "Where is the children's play area?", answer = "A small play area for children is located within the OPD area on the Ground Floor.", keywords = listOf("floor", "play", "within", "ground", "children", "childrens", "located", "where", "opd", "area"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_247", question = "Where is the family lounge?", answer = "While we don't have a dedicated family lounge, we offer a VIP lounge for added comfort. Please ask reception for access details.", keywords = listOf("access", "while", "reception", "offer", "added", "dont", "have", "lounge", "dedicated", "comfort"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_248", question = "Where is the smoking area?", answer = "Smoking is not permitted anywhere on hospital premises—and for good reason: smoking is harmful to your health and can affect healing, breathing, and overall wellness. We encourage a smoke-free environment to support everyone's recovery and well-being.", keywords = listOf("smoking", "area", "where", "premises", "permitted", "smoke-free", "not allowed", "forbidden", "prohibited"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_249", question = "Where is the admin office?", answer = "For administrative inquiries, please check with reception—they'll direct you to the appropriate office or staff member.", keywords = listOf("staff", "inquiries", "receptiontheyll", "admin", "appropriate", "please", "check", "direct", "office", "administrative"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_250", question = "Where is the HR department?", answer = "HR-related matters are handled internally. For visitor access or queries, kindly coordinate through reception.", keywords = listOf("queries", "hrrelated", "access", "handled", "through", "reception", "coordinate", "department", "internally", "visitor"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_251", question = "Where is the medical records department?", answer = "The MRD is located in the Basement. For records requests or assistance, please visit during working hours or check with reception first.", keywords = listOf("basement", "records", "hours", "during", "reception", "department", "medical", "assistance", "please", "visit"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_252", question = "Where is Discharge Counter ?", answer = "For discharge, please proceed to the Billing Counter on the Ground Floor. Your doctor will coordinate the medical clearance, and reception can guide you through the final steps.", keywords = listOf("floor", "will", "clearance", "through", "reception", "discharge", "coordinate", "ground", "medical", "final"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_285", question = "Where is the doctor's consultation room?", answer = "Consultation rooms are assigned by specialty and schedule. For your doctor's exact location, please check with reception—they'll guide you right away.", keywords = listOf("exact", "assigned", "schedule", "room", "receptiontheyll", "specialty", "right", "guide", "please", "check"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_286", question = "Where is the nurse station?", answer = "Nurse stations are available on every floor, within each ward and department. Look for the nursing desk near your patient's room or ask any staff member.", keywords = listOf("nursing", "desk", "nurse", "station", "department", "every", "each", "available", "any", "patients"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_287", question = "Where is the staff room?", answer = "The staff room is located on the 2nd Floor. This area is for hospital personnel only—visitors please check with reception for assistance.", keywords = listOf("staff", "floor", "hospital", "onlyvisitors", "reception", "room", "personnel", "assistance", "2nd", "please"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_288", question = "Where is the ground floor pharmacy?", answer = "The pharmacy on the Ground Floor is located directly in front of the billing/reception desk for quick access.", keywords = listOf("floor", "quick", "desk", "access", "billingreception", "ground", "front", "directly", "located", "pharmacy"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_289", question = "Where is the first floor OPD?", answer = "OPD services span multiple floors. For the exact location of your specialist's OPD, please confirm with reception at check-in.", keywords = listOf("floor", "exact", "services", "confirm", "span", "reception", "floors", "specialists", "first", "please"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_290", question = "Where is the second floor ICU?", answer = "Specialized ICUs (including KICU) are located on the 2nd Floor. Access is coordinated through medical staff—please check with reception for visitor guidelines.", keywords = listOf("icus", "specialized", "second", "through", "medical", "2nd", "visitor", "guidelines", "where", "floor"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_291", question = "Where is the blood bank?", answer = "The blood bank is located in the Basement. For donations, requests, or emergencies, please contact reception for immediate coordination.", keywords = listOf("basement", "immediate", "bank", "emergencies", "reception", "donations", "located", "contact", "please", "coordination"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_292", question = "Where is the security desk?", answer = "Security personnel are stationed throughout the campus. If you need assistance, ask any staff member—they'll quickly connect you with security.", keywords = listOf("staff", "security", "desk", "campus", "membertheyll", "personnel", "quickly", "assistance", "any", "need"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_293", question = "Where is the taxi stand or cab pickup point?", answer = "Cab pickup and drop-off is conveniently located near the main entrance for easy access.", keywords = listOf("cab", "access", "point", "near", "conveniently", "dropoff", "entrance", "pickup", "easy", "taxi"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_294", question = "Where is the visitor locker facility?", answer = "Visitor lockers are available in the Basement. Please check with reception for access instructions and usage guidelines.", keywords = listOf("basement", "guidelines", "access", "reception", "visitor", "locker", "please", "facility", "available", "lockers"), category = "facilities", language = "en" ), )
// Dynamic doctor Q&As injected from Strapi private val dynamicDoctorQAs = mutableListOf<KnowledgeBaseQA>()
/** * Inject doctor Q&As from Strapi into the knowledge base * Called whenever doctors are fetched or updated */ fun injectDoctorQAs(doctors: List<Doctor>) { android.util.Log.d("HospitalKnowledgeBase", "Starting injection of ${doctors.size} doctors")
// Clear previous dynamic doctor QAs dynamicDoctorQAs.clear()
// Create Q&A pairs for each doctor doctors.forEach { doctor -> val doctorName = if (doctor.name.startsWith("Dr", ignoreCase = true)) doctor.name else "Dr. ${doctor.name}"
android.util.Log.d("HospitalKnowledgeBase", "Injecting doctor: $doctorName (${doctor.department})")
// Extract keywords from name (first name, last name, full name) val nameKeywords = mutableListOf<String>() val nameParts = doctor.name.replace("Dr.", "").replace("Dr", "").trim().split(" ") nameKeywords.addAll(nameParts.map { it.lowercase() }) nameKeywords.add(doctor.name.lowercase())
// Extract keywords from bio val bioKeywords = doctor.aboutBio.lowercase() .split(" ") .filter { it.length > 4 && !it.matches(Regex(".*[0-9].*")) } // Words longer than 4 chars, no numbers .distinct() .take(10) // Top 10 bio keywords
// Q&A 1: Direct doctor name query with COMPLETE details - SPECIALTY FIRST val primarySpecialty = if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) { doctor.specialization } else { doctor.department }
dynamicDoctorQAs.add( KnowledgeBaseQA( id = "dynamic_doc_${doctor.id}_name", question = "Who is $doctorName?", answer = "$doctorName is a $primarySpecialty. " + "PRIMARY SPECIALTY: $primarySpecialty. " + "Department: ${doctor.department}. " + "Experience: ${doctor.yearsOfExperience} years. " + "Cabin: ${doctor.cabin}. " + "Details: ${doctor.aboutBio}", keywords = listOf( doctor.name.lowercase(), doctor.specialization?.lowercase() ?: "", doctor.department.lowercase(), "doctor", "specialist", "cabin", doctor.cabin.lowercase(), doctor.department.lowercase() // Added as primary keyword ).plus(nameKeywords).plus(bioKeywords).filter { it.isNotEmpty() }.distinct(), category = "departments", language = "en" ) )
// Q&A 2: Department query with COMPLETE details - SPECIALTY FIRST dynamicDoctorQAs.add( KnowledgeBaseQA( id = "dynamic_doc_${doctor.id}_dept", question = "Is there a ${doctor.department} specialist?", answer = "$doctorName - PRIMARY SPECIALTY: $primarySpecialty. " + "Department: ${doctor.department}. " + "Experience: ${doctor.yearsOfExperience} years. " + "Cabin: ${doctor.cabin}. " + "About: ${doctor.aboutBio}", keywords = listOf( doctor.department.lowercase(), "specialist", "doctor", "department", doctor.specialization?.lowercase() ?: "", "experience", doctor.cabin.lowercase() ).plus(nameKeywords).filter { it.isNotEmpty() }.distinct(), category = "departments", language = "en" ) )
// Q&A 3: Specialization query (if different from department) - SPECIALTY FIRST if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) { dynamicDoctorQAs.add( KnowledgeBaseQA( id = "dynamic_doc_${doctor.id}_spec", question = "Who specializes in ${doctor.specialization}?", answer = "$doctorName - PRIMARY SPECIALTY: ${doctor.specialization}. " + "Department: ${doctor.department}. " + "Experience: ${doctor.yearsOfExperience} years. " + "Cabin: ${doctor.cabin}. " + "Details: ${doctor.aboutBio}", keywords = listOf( doctor.specialization.lowercase(), doctor.department.lowercase(), "specialist", "specialization", doctor.name.lowercase() ).plus(nameKeywords).filter { it.isNotEmpty() }.distinct(), category = "departments", language = "en" ) ) } }
android.util.Log.d("HospitalKnowledgeBase", "Successfully injected ${dynamicDoctorQAs.size} dynamic doctor Q&As from ${doctors.size} doctors") }
