/** * Hospital Knowledge Base - 294 Q&A pairs (COMPLETE VERSION) * Each QA pair represents common hospital questions and answers * These are retrieved intelligently based on user query */ data class KnowledgeBaseQA( val id: String, val question: String, val answer: String, val keywords: List<String>, // For matching user queries val category: String, // hospital_info, departments, appointments, etc. val language: String = "en" // "en" or "hi" )
object HospitalKnowledgeBase {
// ==================== ALL 294 Q&A PAIRS ==================== // Generated from Hospital temi Dataset.json // Updated: April 22, 2026 private val qaDatabase = listOf( // ...existing code... KnowledgeBaseQA( id = "qa_1", question = "What is the hospital name ?", answer = "All Is Well Hospital is a modern multi-speciality healthcare institution located in Burhanpur, Madhya Pradesh. The founder and chairman of All is Well Hospiital is Mr. Anand Prakash Chouksey. The hospital was established in 2019 with the vision of delivering high-quality, ethical, and patient-centered medical care to people in and around the region. The mission of All Is Well Hospital is to provide accessible, affordable, and advanced healthcare services with compassion and integrity.", keywords = listOf("transparent", "dignity", "hospiital", "outcomes", "dental", "specialists", "ophthalmology", "professionals", "burhanpur", "monitoring"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_1_hi", question = "अस्पताल का नाम क्या है?", answer = "ऑल इज़ वेल हॉस्पिटल एक आधुनिक मल्टी-स्पेशलिटी स्वास्थ्य संस्थान है, जो बुरहानपुर, मध्य प्रदेश में स्थित है। इसके संस्थापक और चेयरमैन श्री आनंद प्रकाश चौकसे हैं। अस्पताल 2019 में स्थापित किया गया था, जिसका उद्देश्य उच्च गुणवत्ता, नैतिक और रोगी-केंद्रित चिकित्सा सेवा प्रदान करना है। ऑल इज़ वेल हॉस्पिटल का मिशन करुणा और ईमानदारी के साथ सुलभ, किफायती और उन्नत स्वास्थ्य सेवाएं प्रदान करना है।", keywords = listOf("अस्पताल", "नाम", "ऑल इज़ वेल", "बुरहानपुर", "चौकसे", "मिशन", "सेवा", "स्वास्थ्य", "मध्य प्रदेश"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_2_hi", question = "क्या आपके पास बीमा सुविधाएं हैं?", answer = "अस्पताल विस्तृत श्रेणी के विश्वसनीय स्वास्थ्य बीमा प्रदाताओं के माध्यम से कैशलेस और प्रतिपूर्ति सुविधाएं प्रदान करता है। स्वीकृत बीमा कंपनियों में स्टार हेल्थ इन्शुरेंस, केयर हेल्थ इन्शुरेंस, पैरामाउंट हेल्थ सर्विसेज़, IFFCO-टोकियो जनरल इंश्योरेंस, डिजिट इंश्योरेंस, आदित्य बिड़ला हेल्थ इन्शुरेंस, SBI जनरल इंश्योरेंस शामिल हैं।", keywords = listOf("बीमा", "सुविधाएं", "कैशलेस", "प्रतिपूर्ति", "स्वास्थ्य", "कंपनियां"), category = "insurance", language = "hi" ), KnowledgeBaseQA( id = "qa_3_hi", question = "स्वास्थ्य पैकेज कौन से हैं?", answer = "ऑल इज़ वेल हॉस्पिटल में विशेष रूप से डिज़ाइन किए गए स्वास्थ्य पैकेज हैं: बेसिक वेलनेस, कम्प्रिहेंसिव वेलनेस, महिला स्वास्थ्य पैकेज, डायबिटिक वेलनेस और बाल स्वास्थ्य पैकेज। प्रत्येक पैकेज में प्रयोगशाला परीक्षण और नैदानिक मूल्यांकन शामिल हैं।", keywords = listOf("पैकेज", "स्वास्थ्य", "वेलनेस", "परीक्षण", "महिला", "बाल", "मधुमेह"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_6_hi", question = "क्या वॉक-इन परामर्श की अनुमति है?", answer = "ऑल इज़ वेल हॉस्पिटल 24/7 OPD सेवाएं प्रदान करता है। मरीज़ रिसेप्शन पर आकर परामर्श ले सकते हैं। आपातकालीन मामलों में प्राथमिकता दी जाती है। 24 घंटे फार्मेसी, प्रयोगशाला और रेडियोलॉजी विभाग उपलब्ध हैं।", keywords = listOf("परामर्श", "OPD", "आपातकालीन", "24/7", "डॉक्टर", "उपलब्ध"), category = "departments", language = "hi" ), KnowledgeBaseQA( id = "qa_7_hi", question = "अस्पताल का फोन नंबर क्या है?", answer = "ऑल इज़ वेल हॉस्पिटल से संपर्क करने के लिए आपातकालीन नंबर +91 76977 44444 या +91 70890 66888 पर कॉल करें। ये नंबर अस्पताल के सामने के डेस्क से जुड़े हैं जहां विभाग की जानकारी, अपॉइंटमेंट बुकिंग और आपातकालीन सहायता उपलब्ध है।", keywords = listOf("फोन", "नंबर", "संपर्क", "अपॉइंटमेंट", "आपातकालीन"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_8_hi", question = "क्या आप हिंदी में बोल सकते हैं?", answer = "हां, मैं हिंदी में बोल सकता हूँ। आप हिंदी में अपने सवाल पूछ सकते हैं और मैं हिंदी में जवाब दूंगा। मेरा लक्ष्य आपके लिए संचार को आसान और सुविधाजनक बनाना है।", keywords = listOf("हिंदी", "भाषा", "बोल", "समझ", "सवाल", "जवाब"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_9_hi", question = "क्या आप दोहरा सकते हैं?", answer = "जी, मैं आपके लिए जानकारी को स्पष्ट और धीरे-धीरे दोहराऊंगा। यदि आपको कोई विस्तृत जानकारी चाहिए, तो बस पूछें। मैं आपकी सहायता के लिए यहां हूँ।", keywords = listOf("दोहराना", "स्पष्ट", "जानकारी", "धीरे", "समझ", "विस्तार"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_13_hi", question = "अस्पताल में कौन सी सुविधाएं उपलब्ध हैं?", answer = "ऑल इज़ वेल हॉस्पिटल में उन्नत नैदानिक प्रयोगशालाएं, 24/7 फार्मेसी, कैफेटेरिया, ATM, पेयजल स्टेशन, शौचालय, लिफ्टें, व्हीलचेयर सहायता और समर्पित प्रतीक्षा क्षेत्र हैं। ICU के लिए विशेष समय हैं (आमतौर पर 11 AM-12 PM और 6 PM-7 PM)।", keywords = listOf("सुविधाएं", "प्रयोगशाला", "फार्मेसी", "ATM", "शौचालय", "लिफ्ट", "ICU"), category = "diagnostics", language = "hi" ), KnowledgeBaseQA( id = "qa_51_hi", question = "अस्पताल का ईमेल क्या है?", answer = "आप अस्पताल को frontdesk@alliswellhospital.com पर ईमेल कर सकते हैं। यह ईमेल पता अस्पताल की प्रशासनिक टीम द्वारा समीक्षा किया जाता है और सामान्य पूछताछ, अपॉइंटमेंट अनुरोध और स्वास्थ्य पैकेज विवरण के लिए उपयोग किया जा सकता है।", keywords = listOf("ईमेल", "संपर्क", "frontdesk", "अपॉइंटमेंट", "पूछताछ"), category = "general", language = "hi" ), KnowledgeBaseQA( id = "qa_57_hi", question = "अस्पताल का खुलने का समय क्या है?", answer = "सोमवार से शुक्रवार: सुबह 8:00 से शाम 8:00 बजे | शनिवार से रविवार: सुबह 9:00 से शाम 6:00 बजे", keywords = listOf("खुलने", "समय", "सोमवार", "शुक्रवार", "शनिवार", "रविवार", "घंटे"), category = "hospital_info", language = "hi" ), KnowledgeBaseQA( id = "qa_58_hi", question = "ऑल इज़ वेल हॉस्पिटल कहां स्थित है?", answer = "ऑल इज़ वेल हॉस्पिटल मैक्रो विजन अकादमी के पास, बुरहानपुर, मध्य प्रदेश, 450331 में स्थित है।", keywords = listOf("स्थान", "पता", "बुरहानपुर", "मध्य प्रदेश", "मैक्रो", "विजन", "अकादमी"), category = "facilities", language = "hi" ), KnowledgeBaseQA( id = "qa_2", question = "Do you have insurance facilities?", answer = "The hospital provides cashless and reimbursement facilities through a wide range of trusted health insurance providers to ensure convenient and hassle-free treatment for patients. The accepted insurance companies include Star Health Insurance, Care Health Insurance, Paramount Health Services, IFFCO-Tokio General Insurance, Digit Insurance, Aditya Birla Health Insurance, SBI General Insurance, ICICI Lombard, FHPL (Family Health Plan Limited), MDIndia Healthcare Services, Niva Bupa Health Insurance.", keywords = listOf("provided", "limited", "plan", "according", "available", "doctor", "unless", "specific", "coverage", "eligible"), category = "insurance", language = "en" ), KnowledgeBaseQA( id = "qa_3", question = "What all are the health packages ?", answer = "At All Is Well Hospital, we offer a variety of specially designed health check-up packages to meet the preventive and diagnostic healthcare needs of adults, women, children, and patients managing chronic conditions such as diabetes. Currently, we provide five major health packages: Basic Wellness, Comprehensive Wellness, Comprehensive Women Wellness, Diabetic Wellness, and Healthy Child Wellness. Each package includes a carefully selected combination of laboratory tests and diagnostic evaluations.", keywords = listOf("metabolic", "8540", "performance", "focuses", "tsh", "ecg", "lipid", "each", "available", "consultation"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_4", question = "What are types of yoga treatment available ?", answer = "At All Is Well Hospital, a range of structured yoga treatments is available to support physical health, mental well-being, and overall lifestyle balance. The hospital offers multiple therapeutic yoga approaches tailored to different health needs. These include Hatha Yoga, Vinyasa Flow, Yin Yoga, Pranayama, Meditation and Mindfulness, and Yoga Therapy, each designed with specific benefits and therapeutic goals.", keywords = listOf("fascia", "ligaments", "focuses", "supports", "stamina", "fluid", "each", "yin", "particularly", "available"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_5", question = "Treatments Available in Nutrition and diet ?", answer = "The Treatments Available in Nutrition and Diet focus on improving overall health, preventing diseases, and supporting specific medical conditions through scientifically designed dietary strategies. Personalized Meal Planning involves creating custom nutrition plans tailored to an individual's health goals, medical history, lifestyle, and dietary preferences. This approach ensures balanced nutrient intake while addressing concerns such as weight control, nutrient deficiencies, food allergies.", keywords = listOf("strategies", "gain", "metabolic", "performance", "holistic", "focuses", "qualified", "loss", "available", "specific"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_6", question = "Is walk in consultation allowed ?", answer = "All Is Well Hospital provides 24×7 OPD services along with emergency care, and patients can generally walk in for consultations on a first-come, first-served basis at the reception, with priority sometimes given to emergency cases or senior citizens. Specific walk-in policies will depend on doctor availability, but urgent care is always accessible any time due to the 24-hour OPD and emergency setup. The in-house Pharmacy, the labs and radiology department at All Is Well Hospital operates 24×7.", keywords = listOf("availability", "consultation", "available", "doctor", "urgent", "specific", "online", "firstserved", "room", "reports"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_7", question = "What is the hospital's phone number?", answer = "You can contact All Is Well Hospital directly by calling on the emergency number +91 76977 44444 or +91 70890 66888. These numbers connect you to the hospital's front desk and support team, where staff members can assist you with appointment bookings, department inquiries, emergency coordination, and general hospital information. The phone lines are active to ensure patients and visitors receive timely assistance whenever needed.", keywords = listOf("query", "feedback", "bookings", "quicker", "available", "specific", "package", "without", "ensure", "health", "phone number"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_8", question = "Can you speak in Hindi?", answer = "Yes, I can speak in Hindi. You can ask your questions in Hindi, and I will respond in Hindi to make it easier for you. My goal is to make communication simple and comfortable for you during your visit to the hospital.", keywords = listOf("questions", "will", "hospital", "easier", "during", "yes", "hindi", "goal", "respond", "simple"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_9", question = "Can you repeat?", answer = "Of course. I will repeat the information for you clearly and slowly. Please listen carefully, and if you need me to repeat it again or explain any specific part in more detail, feel free to ask. I am here to assist you.", keywords = listOf("specific", "information", "any", "detail", "slowly", "here", "please", "clearly", "repeat", "feel"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_10", question = "Can you repeat the direction ?", answer = "Certainly. I will repeat the directions step by step so you can follow them easily. Please proceed straight from your current location, then turn as instructed. If you would like, I can also guide you by moving with you to the destination. Let me know how you would prefer to proceed.", keywords = listOf("moving", "directions", "direction", "proceed", "them", "step", "from", "current", "know", "prefer"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_11", question = "Can you show the map ?", answer = "yes. Yes, I can display the hospital map on my screen for you. The map will show your current location and the route to your destination inside the hospital. You can follow the highlighted path, or I can guide you personally to the location. Please confirm where you would like to go.", keywords = listOf("personally", "confirm", "current", "please", "location", "path", "destination", "where", "highlighted", "hospital"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_12", question = "can you explain again ?", answer = "Yes, let me explain you again in a simple language. I am here to ensure you receive complete and accurate information.", keywords = listOf("let", "language", "accurate", "receive", "yes", "explain", "here", "simple", "ensure", "complete"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_13", question = "What facilities are available at the hospital?", answer = "All Is Well Hospital provides comprehensive facilities including advanced diagnostic labs, 24/7 pharmacy, cafeteria, ATM, drinking water stations, restrooms, elevators, wheelchair assistance, and dedicated waiting areas for visitors . Visiting hours for general wards are typically not defined one family member/visitor can visit the patient with a pass that is given to the patient. ICU visiting hours are more restricted (commonly 11 AM-12 PM and 6 PM-7 PM) to ensure patient rest and infection control.", keywords = listOf("provided", "xray", "additional", "availability", "12000day", "discharge", "each", "available", "consultation", "doctor"), category = "diagnostics", language = "en" ), KnowledgeBaseQA( id = "qa_14", question = "How much the radiology and imaging costs ?", answer = "At All Is Well Hospital, the Radiology and Imaging Department offers a wide range of advanced diagnostic imaging services. The exact cost of each test depends on the type of scan, body part examined, contrast usage, and clinical requirements. Patients are advised to contact the billing counter for updated pricing. The available radiology and imaging services include X-Ray for examining bones, chest, lungs, fractures, infections, and joint conditions.", keywords = listOf("safe", "internal", "xray", "performance", "nursing", "perday", "105", "tsh", "each", "available"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_15", question = "Is cash accepted ?", answer = "Yes, the hospital accepts cash payments for consultations, diagnostic tests, room charges, and other medical services. In addition to cash, digital payment options may also be available for patient convenience. For large bills such as admissions or surgeries, patients can confirm accepted payment methods at the billing counter.", keywords = listOf("availability", "discharge", "station", "doctor", "visits", "ensure", "suites", "gear", "preauthorization", "instructions"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_16", question = "Name of Hospital", answer = "The Name of the Hospital is All is Well Hospital. I'm here to assist you, Welcome to All Is Well Hospital. I'm your digital assistant—ready to help with directions, appointments, or information.", keywords = listOf("help", "hospital", "well", "appointments", "name", "here", "assistantready", "welcome", "all", "directions"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_17", question = "Who is the Director?", answer = "Kabir Chouksey and Devanshi Chouksey is the Director of the hospital.", keywords = listOf("hospital", "director", "devanshi", "chouksey", "who", "kabir"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_18", question = "Who is Kabir Chouksey?", answer = "Kabir Chouksey is the Director of the hospital.", keywords = listOf("hospital", "director", "chouksey", "who", "kabir"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_19", question = "Who is Devanshi Chouksey?", answer = "Devanshi Chouksey is the Director of the hospital.", keywords = listOf("hospital", "director", "devanshi", "chouksey", "who"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_51", question = "What is Hospital's Email?", answer = "You can reach the hospital via email at frontdesk@alliswellhospital.com. This email address is monitored by the hospital's administrative team and can be used for general inquiries, appointment requests, health package details, feedback, or non-urgent medical coordination.", keywords = listOf("recommended", "query", "sending", "feedback", "quicker", "receive", "number", "package", "medical", "brief"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_52", question = "How many OTs are there?", answer = "There are 6+ Modular OTs in All is Well", keywords = listOf("well", "there", "many", "all", "how", "modular", "ots"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_53", question = "How many rooms are there in hospital?", answer = "There are around 350 rooms in our hospital.", keywords = listOf("hospital", "there", "around", "our", "many", "350", "rooms", "how"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_54", question = "How many beds are there in hospital?", answer = "There are 360+ beds in hospital.", keywords = listOf("hospital", "there", "many", "beds", "360", "how"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_55", question = "What are the core Values of All is Well?", answer = "1)Valuing Time , 2) Striving for Excellence, 3) Practicing Humility, 4) Fostering Inclusion , 5) Living with Integrity.", keywords = listOf("integrity", "inclusion", "well", "core", "fostering", "practicing", "striving", "all", "1valuing", "excellence"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_56", question = "Which Hospital is best in All is Well Hospital?", answer = "All is Well Hospital is Counted in best hospitals in Burhanpur.", keywords = listOf("which", "hospital", "well", "best", "all", "hospitals", "counted", "burhanpur"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_57", question = "What is Hospital Opening timing?", answer = "Mon - Fri: 8:00 AM - 8:00 PM | Sat - Sun: 9:00 AM - 6:00 PM", keywords = listOf("900", "hospital", "mon", "sat", "800", "opening", "sun", "600", "timing", "fri"), category = "hospital_info", language = "en" ), KnowledgeBaseQA( id = "qa_58", question = "Where is All is Well Hospital located?", answer = "Near Macro Vision Academy, Burhanpur, Madhya Pradesh, 450331", keywords = listOf("madhya", "academy", "hospital", "well", "macro", "near", "pradesh", "all", "vision", "located"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_59", question = "How can i contact to hospital?", answer = "You can contact on +91 7697744444 or +91 7089099888", keywords = listOf("hospital", "7089099888", "contact", "7697744444", "how"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_60", question = "What is the email for all is well hospital?", answer = "digitalmarketing@mvaburhanpur.com", keywords = listOf("hospital", "well", "email", "all", "digitalmarketingmvaburhanpurcom"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_61", question = "Do I need a referral to see a specialist?", answer = "No referral is needed for most departments; you can directly book with the specialist of your choice.", keywords = listOf("referral", "departments", "specialist", "most", "choice", "directly", "need", "book", "needed", "see"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_62", question = "How can I see which doctor treats my condition?", answer = "Visit \"Meet Our Specialists\" on the website to filter doctors by department and view their expertise.", keywords = listOf("which", "meet", "our", "website", "view", "expertise", "department", "specialists", "visit", "see"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_63", question = "Are your doctors experienced?", answer = "Yes, our team includes qualified consultants with fellowships and specialized training in their fields.", keywords = listOf("our", "includes", "yes", "qualified", "fields", "specialized", "experienced", "their", "fellowships", "doctors"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_64", question = "What health check-up packages do you offer?", answer = "We offer Basic Wellness (₹899), Comprehensive Wellness (₹4999), Women's, Diabetic, Pregnancy, and Child packages.", keywords = listOf("wellness", "899", "4999", "womens", "offer", "checkup", "diabetic", "packages", "health", "pregnancy"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_65", question = "Are the health packages discounted?", answer = "Yes, all packages currently offer 25–53% off the original price—check the website for latest offers.", keywords = listOf("2553", "discounted", "yes", "currently", "offer", "original", "pricecheck", "all", "offers", "off"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_66", question = "What's included in the Diabetic Wellness package?", answer = "It includes HbA1c, sugar tests, ECG, 2D Echo, kidney/liver tests, eye exam, and consultations with physician & dietitian.", keywords = listOf("wellness", "exam", "eye", "includes", "package", "sugar", "consultations", "hba1c", "kidneyliver", "dietitian"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_67", question = "Do you offer dietitian consultations?", answer = "Yes, dietitian consultations are included in Comprehensive Wellness and Diabetic Wellness packages.", keywords = listOf("wellness", "consultations", "yes", "offer", "dietitian", "included", "diabetic", "packages", "comprehensive"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_68", question = "Are your services affordable?", answer = "We provide high-quality, cost-effective care with transparent pricing and discounted wellness packages.", keywords = listOf("services", "provide", "transparent", "wellness", "costeffective", "discounted", "highquality", "affordable", "care", "packages"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_69", question = "Is parking available at the hospital?", answer = "Yes, we offer free parking for patients and visitors near the main entrance.", keywords = listOf("patients", "hospital", "free", "near", "yes", "offer", "entrance", "available", "parking", "visitors"), category = "facilities", language = "en" ), KnowledgeBaseQA( id = "qa_70", question = "Do you accept walk-in patients?", answer = "Yes, walk-ins are welcome for general consultation; appointments help reduce waiting time.", keywords = listOf("patients", "help", "waiting", "time", "appointments", "walkins", "yes", "welcome", "general", "consultation"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_71", question = "Can I get a bill estimate before treatment?", answer = "Yes, our front desk can provide a tentative cost estimate after a brief consultation with the doctor.", keywords = listOf("get", "before", "bill", "provide", "our", "desk", "tentative", "yes", "treatment", "front"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_72", question = "Can I access my past visit history online?", answer = "Hospital have all past detail of the patient every patient has a unique ID at the time of first visit from there they can access there past history.", keywords = listOf("online", "has", "patient", "hospital", "access", "detail", "there", "unique", "from", "history"), category = "general", language = "en" ), KnowledgeBaseQA( id = "qa_73", question = "Do you share reports with other doctors?", answer = "Yes, with your consent, we can share digital or printed reports with any specialist you refer to.", keywords = listOf("refer", "share", "yes", "other", "consent", "specialist", "digital", "doctors", "reports", "any"), category = "departments", language = "en" ), KnowledgeBaseQA( id = "qa_74", question = "What should I do in a medical emergency?", answer = "Call our emergency number immediately or visit the hospital—our 24/7 team is ready to help.", keywords = listOf("should", "call", "247", "help", "our", "number", "hospitalour", "m