// === DEPARTMENTS & SPECIALIZATIONS === "हृदय" to "heart", "heart" to "heart", "cardiology" to "cardiology", "कार्डियोलॉजी" to "cardiology", "हृदयरोग" to "cardiology", "मस्तिष्क" to "brain", "brain" to "brain", "neurology" to "neurology", "न्यूरोलॉजी" to "neurology", "मस्तिष्करोग" to "neurology", "हड्डी" to "bone", "bone" to "bone", "orthopedics" to "orthopedics", "ऑर्थोपेडिक्स" to "orthopedics", "हड्डीरोग" to "orthopedics", "त्वचा" to "skin", "skin" to "skin", "dermatology" to "dermatology", "डर्मेटोलॉजी" to "dermatology", "त्वचारोग" to "dermatology", "बच्चे" to "children", "children" to "children", "pediatrics" to "pediatrics", "पीडियाट्रिक्स" to "pediatrics", "बालरोग" to "pediatrics", "आंख" to "eye", "eye" to "eye", "eyes" to "eye", "नेत्र" to "eye", "ophthalmology" to "ophthalmology", "ऑप्थेल्मोलॉजी" to "ophthalmology", "नेत्ररोग" to "ophthalmology", "दांत" to "dental", "dental" to "dental", "dentist" to "dental", "दंत" to "dental", "surgery" to "surgery", "सर्जरी" to "surgery", "शल्यचिकित्सा" to "surgery", "स्त्री" to "gynecology", "gynecology" to "gynecology", "गायनेकोलॉजी" to "gynecology", "मनोरोग" to "psychiatry", "psychiatry" to "psychiatry", "साइकियाट्री" to "psychiatry",
