// === FACILITIES SERVICES === "x-ray" to "xray", "xray" to "xray", "एक्स-रे" to "xray", "एक्सरे" to "xray", "mri" to "mri", "एमआरआई" to "mri", "ct" to "ct", "सीटी" to "ct", "scan" to "scan", "स्कैन" to "scan", "ultrasound" to "ultrasound", "अल्ट्रासाउंड" to "ultrasound", "blood" to "blood", "खून" to "blood", "रक्त" to "blood", "collection" to "collection", "संग्रह" to "collection",
// === DEPARTMENTS === "विभाग" to "department", "department" to "department", "vibhag" to "department", "केबिन" to "cabin", "cabin" to "cabin", "kabin" to "cabin" )
/** * Normalize query by translating Hindi/Hinglish terms to English for better matching */ private fun normalizeQueryForSearch(query: String): String { var normalized = query.lowercase()
// Replace Hindi/Hinglish keywords with English equivalents hindiToEnglishKeywords.forEach { (hindi, english) -> normalized = normalized.replace(hindi, " $english ") }
return normalized.trim() }
/** * Search knowledge base for relevant Q&As * ENHANCED: Better matching for doctor queries with partial matches and answer text search * NOW SUPPORTS HINDI QUERIES via keyword translation * Returns top N results sorted by relevance (includes dynamic doctor Q&As) */ fun search(userQuery: String, limit: Int = 3): List<KnowledgeBaseQA> { val lowerQuery = userQuery.lowercase()
// Normalize query to translate Hindi/Hinglish to English for better matching val normalizedQuery = normalizeQueryForSearch(lowerQuery)
android.util.Log.d("HospitalKnowledgeBase", "KB Search - Original: '$lowerQuery'") android.util.Log.d("HospitalKnowledgeBase", "KB Search - Normalized: '$normalizedQuery'")
val queryWords = normalizedQuery.split(" ").filter { it.length > 2 } // Words longer than 2 chars
// Combine static and dynamic Q&As val allQAs = qaDatabase + dynamicDoctorQAs
// Score each QA pair based on multiple matching criteria val results = allQAs.map { qa -> var score = 0
// 1. Exact keyword matches (highest score) score += qa.keywords.count { keyword -> normalizedQuery.contains(keyword) } * 3
// 2. Partial word matches in keywords (medium score) score += qa.keywords.count { keyword -> queryWords.any { word -> keyword.contains(word) || word.contains(keyword) } }
// 3. Question text contains query words (good score for doctor name matching) val questionLower = qa.question.lowercase() score += queryWords.count { word -> questionLower.contains(word) } * 2
// 4. Answer text contains query words (helps with department/specialization matching) val answerLower = qa.answer.lowercase() score += queryWords.count { word -> answerLower.contains(word) }
// Priority Boost: If it's a dynamic doctor entry, add a significant boost // to ensure it outranks static hospital info for same-keyword matches if (score > 0 && qa.id.startsWith("dynamic_doc_")) { score += 10 // Significant boost to prioritize Strapi doctor data }
qa to score } .filter { it.second > 0 } // Only include matches .sortedByDescending { it.second } // Sort by relevance .take(limit) .map { it.first }
return results }
/** * Get QA by category (e.g., all departments Q&As) */ fun getByCategory(category: String): List<KnowledgeBaseQA> { return qaDatabase.filter { it.category == category } }
/** * Get single best match for a query */ fun findBestMatch(userQuery: String): KnowledgeBaseQA? { return search(userQuery, limit = 1).firstOrNull() } }

package com.example.alliswelltemi.data
/** * Data model for hospital locations with Temi map integration * * @param id Unique identifier for the location * @param name English name of the location * @param nameHi Hindi name of the location (for voice recognition) * @param mapName Temi robot map name - must match pre-registered locations on Temi's control system * @param isPopular Whether location should appear in quick access * @param icon Emoji icon for UI display */ data class Location( val id: String, val name: String, val nameHi: String = "", // Hindi translation for voice recognition val mapName: String = "", // Temi robot map identifier val isPopular: Boolean = false, val icon: String = "" ) { /** * Get location name in specified language */ fun getNameInLanguage(language: String): String { return if (language == "hi" && nameHi.isNotEmpty()) nameHi else name } }
/** * Predefined hospital locations with bilingual support and Temi map integration * * NOTE: mapName values MUST match locations pre-registered on your Temi robot's map. * If a location is not on your map, the robot cannot navigate to it. * To add new locations: Use Temi Admin Panel → Map Management → Register Location */ object LocationData { val MOST_USED_LOCATIONS = listOf( Location( id = "main_pharmacy", name = "Main Pharmacy", nameHi = "मुख्य फार्मेसी", mapName = "main_pharmacy", isPopular = true, icon = "" ), Location( id = "main_reception", name = "Main Reception", nameHi = "मुख्य रिसेप्शन", mapName = "main_reception", isPopular = true, icon = "" ), Location( id = "pathology_department", name = "Pathology Department", nameHi = "पैथोलॉजी विभाग", mapName = "pathology_department", isPopular = true, icon = "" ), Location( id = "pathology_reception", name = "Pathology Reception", nameHi = "पैथोलॉजी रिसेप्शन", mapName = "pathology_reception", isPopular = true, icon = "" ), Location( id = "opd", name = "OPD", nameHi = "ओ.पी.डी", mapName = "opd", isPopular = true, icon = "" ) )
val ALL_LOCATIONS = listOf( Location( id = "home_base", name = "Home Base", nameHi = "होम बेस", mapName = "home_base", icon = "" ), Location( id = "pathology_department", name = "Pathology Department", nameHi = "पैथोलॉजी विभाग", mapName = "pathology_department", icon = "" ), Location( id = "ayushman_department", name = "Ayushman Department", nameHi = "आयुष्मान विभाग", mapName = "ayushman_department", icon = "" ), Location( id = "main_pharmacy", name = "Main Pharmacy", nameHi = "मुख्य फार्मेसी", mapName = "main_pharmacy", icon = "" ), Location( id = "back_entrance", name = "Back Entrance", nameHi = "पिछला प्रवेश द्वार", mapName = "back_entrance", icon = "" ), Location( id = "rotary_dialysis_center", name = "Rotary Dialysis Center", nameHi = "रोटरी डायलिसिस सेंटर", mapName = "rotary_dialysis_center", icon = "" ), Location( id = "phlebotomy", name = "Phlebotomy", nameHi = "फलेबोटोमी", mapName = "phlebotomy", icon = "" ), Location( id = "pathology_reception", name = "Pathology Reception", nameHi = "पैथोलॉजी रिसेप्शन", mapName = "pathology_reception", icon = "" ), Location( id = "opticals", name = "Opticals", nameHi = "ऑप्टिकल्स", mapName = "opticals", icon = "" ), Location( id = "opd", name = "OPD", nameHi = "ओ.पी.डी", mapName = "opd", icon = "" ), Location( id = "dialysis_department", name = "Dialysis Department", nameHi = "डायलिसिस विभाग", mapName = "dialysis_department", icon = "" ), Location( id = "main_entrance", name = "Main Entrance", nameHi = "मुख्य प्रवेश द्वार", mapName = "main_entrance", icon = "" ), Location( id = "ophthalmology_department", name = "Ophthalmology Department", nameHi = "नेत्र विज्ञान विभाग", mapName = "ophthalmology_department", icon = "️" ), Location( id = "health_shop", name = "Health Shop", nameHi = "स्वास्थ्य दुकान", mapName = "health_shop", icon = "" ), Location( id = "ipd_billing", name = "IPD Billing", nameHi = "आई.पी.डी बिलिंग", mapName = "ipd_billing", icon = "" ), Location( id = "radiology", name = "Radiology", nameHi = "रेडियोलॉजी", mapName = "radiology", icon = "" ), Location( id = "main_reception", name = "Main Reception", nameHi = "मुख्य रिसेप्शन", mapName = "main_reception", icon = "" ), Location( id = "common_washroom", name = "Common Washroom", nameHi = "सामान्य शौचालय", mapName = "common_washroom", icon = "" ) )
/** * Find location by name (supports both English and Hindi) */ fun findByName(name: String): Location? { val normalizedInput = name.lowercase().trim() return ALL_LOCATIONS.find { location -> location.name.lowercase().contains(normalizedInput) || location.nameHi.lowercase().contains(normalizedInput) || location.id.lowercase().contains(normalizedInput) } }
/** * Find location by ID */ fun findById(id: String): Location? { return ALL_LOCATIONS.find { it.id.lowercase() == id.lowercase() } }
/** * Get list of all location names that should be registered on the Temi robot * Use this for debugging and setting up the robot's map */ fun getAllLocationNamesToRegister(): List<String> { return ALL_LOCATIONS.map { it.name }.distinct().sorted() }
/** * Check if a robot location matches any of our database locations * Useful for matching robot's saved locations to app database */ fun matchRobotLocation(robotLocationName: String): Location? { return ALL_LOCATIONS.find { location -> location.name.lowercase() == robotLocationName.lowercase() || location.mapName.lowercase() == robotLocationName.lowercase() || location.id.lowercase() == robotLocationName.lowercase() } } }

