            horizontalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Text(text = location.icon, fontSize = 20.sp)

            Column(
                modifier = Modifier.weight(1f),
                verticalArrangement = Arrangement.Center
            ) {
                Text(
                    text = location.name,
                    color = Color.White,
                    fontSize = 16.sp,
                    fontWeight = FontWeight.SemiBold
                )
            }

            Icon(
                imageVector = Icons.Default.ChevronRight,
                contentDescription = null,
                tint = Color.White.copy(alpha = 0.5f),
                modifier = Modifier.size(20.dp)
            )
        }
    }
}

/**
 * Navigation overlay animation with animated path/route visualization
 */
@Composable
private fun NavigationOverlayAnimated(
    selectedLocation: Location? = null,
    isThinking: Boolean = false
) {
    val infiniteTransition = rememberInfiniteTransition(label = "nav_overlay")

    // Pulsing dot animation
    val dotScale by infiniteTransition.animateFloat(
        initialValue = 0.8f,
        targetValue = 1.2f,
        animationSpec = infiniteRepeatable(
            animation = tween(1000, easing = EaseInOutCubic),
            repeatMode = RepeatMode.Reverse
        ),
        label = "dot_pulse"
    )

    // Arrow animation (moving forward)
    val arrowOffset by infiniteTransition.animateFloat(
        initialValue = 0f,
        targetValue = 30f,
        animationSpec = infiniteRepeatable(
            animation = tween(1500, easing = EaseInOutCubic),
            repeatMode = RepeatMode.Restart
        ),
        label = "arrow_movement"
    )

    // Wave animation
    val waveScale by infiniteTransition.animateFloat(
        initialValue = 0f,
        targetValue = 1f,
        animationSpec = infiniteRepeatable(
            animation = tween(1500, easing = EaseInOutCubic),
            repeatMode = RepeatMode.Restart
        ),
        label = "wave_scale"
    )

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color.Black.copy(alpha = 0.7f)),
        contentAlignment = Alignment.Center
    ) {
        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center,
            modifier = Modifier.fillMaxSize()
        ) {
            // Animated wave circles
            Box(
                modifier = Modifier
                    .size(200.dp)
                    .padding(32.dp),
                contentAlignment = Alignment.Center
            ) {
                // Outer wave circle
                Surface(
                    modifier = Modifier
                        .size(150.dp)
                        .graphicsLayer {
                            scaleX = 0.5f + (waveScale * 0.8f)
                            scaleY = 0.5f + (waveScale * 0.8f)
                            alpha = 1f - waveScale
                        },
                    shape = CircleShape,
                    color = Color(0xFF00D9FF).copy(alpha = 0.3f)
                ) {}

                // Middle wave circle
                Surface(
                    modifier = Modifier
                        .size(120.dp)
                        .graphicsLayer {
                            scaleX = 0.6f + (waveScale * 0.6f)
                            scaleY = 0.6f + (waveScale * 0.6f)
                            alpha = 1f - waveScale
                        },
                    shape = CircleShape,
                    color = Color(0xFF00D9FF).copy(alpha = 0.4f)
                ) {}

                // Central pulsing dot
                Surface(
                    modifier = Modifier
                        .size(40.dp)
                        .scale(dotScale),
                    shape = CircleShape,
                    color = Color(0xFF00D9FF)
                ) {
                    Box(contentAlignment = Alignment.Center) {
                        Icon(
                            imageVector = Icons.Default.Navigation,
                            contentDescription = "Navigating",
                            tint = Color.Black,
                            modifier = Modifier.size(24.dp)
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(40.dp))

            // Location name
            Text(
                text = when {
                    isThinking -> "Thinking..."
                    selectedLocation != null -> "Taking you to ${selectedLocation.name}"
                    else -> "Processing..."
                },
                color = Color.White,
                fontSize = 24.sp,
                fontWeight = FontWeight.Bold
            )

            Spacer(modifier = Modifier.height(20.dp))

            // Animated progress text
            Text(
                text = if (isThinking) "Consulting hospital database" else "Robot is moving...",
                color = Color.White.copy(alpha = 0.7f),
                fontSize = 16.sp
            )

            Spacer(modifier = Modifier.height(40.dp))

            // Arrow animation
            Row(
                horizontalArrangement = Arrangement.Center,
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier.fillMaxWidth()
            ) {
                repeat(5) { index ->
                    Icon(
                        imageVector = Icons.Default.ArrowForward,
                        contentDescription = null,
                        tint = Color(0xFF00D9FF),
                        modifier = Modifier
                            .size(24.dp)
                            .graphicsLayer {
                                translationX = arrowOffset - (index * 8f)
                                alpha = 0.3f + (0.7f * (1f - (index * 0.2f)))
                            }
                    )
                }
            }
        }
    }
}

package com.example.alliswelltemi.network

import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

/**
 * Retrofit Client for Ollama LLM API
 * Configured for local network communication with Ollama server
 *
 * Usage:
 *   val ollama = OllamaClient.api
 *   val response = ollama.generate(OllamaRequest(prompt = "Hello"))
 */
object OllamaClient {
    // IMPORTANT: For Temi robot on local network, use the Ollama server IP
    // Default: http://localhost:11434/ (change to your actual server IP)
    // For emulator/testing: http://10.0.2.2:11434/
    private const val BASE_URL = "http://localhost:11434/"

    private val loggingInterceptor = HttpLoggingInterceptor().apply {
        level = HttpLoggingInterceptor.Level.BODY
    }

    private val httpClient = OkHttpClient.Builder()
        .addInterceptor(loggingInterceptor)
        .connectTimeout(60, TimeUnit.SECONDS)  // Long timeout for LLM generation
        .readTimeout(120, TimeUnit.SECONDS)    // LLM may take time to generate
        .writeTimeout(60, TimeUnit.SECONDS)
        .build()

    val api: OllamaApiService by lazy {
        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .client(httpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(OllamaApiService::class.java)
    }

    /**
     * Change the Ollama server IP (useful for testing different environments)
     * Example: "http://10.0.2.2:11434/" for Android emulator
     */
    fun setBaseUrl(newBaseUrl: String) {
        // This would require rebuilding the client
        // For now, use the constant above
    }

    /**
     * Generate streaming response from Ollama
     * Returns Flow<String> for real-time text chunks
     */
    suspend fun generateStreaming(request: OllamaRequest): kotlinx.coroutines.flow.Flow<String> {
        return kotlinx.coroutines.flow.flow {
            try {
                val response = api.generateStream(request.copy(stream = true))
                val responseBody = response.body()

                responseBody?.let { body ->
                    val source = body.source()
                    val buffer = okio.Buffer()

                    while (!source.exhausted()) {
                        val read = source.read(buffer, 8192)
                        if (read > 0) {
                            val chunk = buffer.readUtf8()
                            // Parse NDJSON chunks
                            chunk.lines().forEach { line ->
                                if (line.isNotBlank()) {
                                    try {
                                        val streamResponse = com.google.gson.Gson().fromJson(line, OllamaStreamResponse::class.java)
                                        emit(streamResponse.response)
                                        if (streamResponse.done) {
                                            return@flow
                                        }
                                    } catch (e: Exception) {
                                        // Skip malformed JSON lines
                                        android.util.Log.w("OllamaClient", "Skipping malformed chunk: $line")
                                    }
                                }
                            }
                        }
                    }
                }
            } catch (e: Exception) {
                android.util.Log.e("OllamaClient", "Streaming error: ${e.message}", e)
                throw e
            }
        }
    }
}

package com.example.alliswelltemi.network

import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

/**
 * Retrofit Client for Ollama LLM API
 * Configured for local network communication with Ollama server
 *
 * Usage:
 *   val ollama = OllamaClient.api
 *   val response = ollama.generate(OllamaRequest(prompt = "Hello"))
 */
object OllamaClient {
    // IMPORTANT: For Temi robot on local network, use the Ollama server IP
    // Default: http://localhost:11434/ (change to your actual server IP)
    // For emulator/testing: http://10.0.2.2:11434/
    private const val BASE_URL = "http://10.1.90.89:11434/"

    private val loggingInterceptor = HttpLoggingInterceptor().apply {
        level = HttpLoggingInterceptor.Level.BODY
    }

    private val httpClient = OkHttpClient.Builder()
        .addInterceptor(loggingInterceptor)
        .connectTimeout(60, TimeUnit.SECONDS)  // Long timeout for LLM generation
        .readTimeout(120, TimeUnit.SECONDS)    // LLM may take time to generate
        .writeTimeout(60, TimeUnit.SECONDS)
        .build()

    val api: OllamaApiService by lazy {
        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .client(httpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(OllamaApiService::class.java)
    }

    /**
     * Change the Ollama server IP (useful for testing different environments)
     * Example: "http://10.0.2.2:11434/" for Android emulator
     */
    fun setBaseUrl(newBaseUrl: String) {
        // This would require rebuilding the client
        // For now, use the constant above
    }

    /**
     * Generate streaming response from Ollama
     * Returns Flow<String> for real-time text chunks
     */
    suspend fun generateStreaming(request: OllamaRequest): kotlinx.coroutines.flow.Flow<String> {
        return kotlinx.coroutines.flow.flow {
            try {
                val response = api.generateStream(request.copy(stream = true))
                val responseBody = response.body()

                responseBody?.let { body ->
                    val source = body.source()
                    val buffer = okio.Buffer()

                    while (!source.exhausted()) {
                        val read = source.read(buffer, 8192)
                        if (read > 0) {
                            val chunk = buffer.readUtf8()
                            // Parse NDJSON chunks
                            chunk.lines().forEach { line ->
                                if (line.isNotBlank()) {
                                    try {
                                        val streamResponse = com.google.gson.Gson().fromJson(line, OllamaStreamResponse::class.java)
                                        emit(streamResponse.response)
                                        if (streamResponse.done) {
                                            return@flow
                                        }
                                    } catch (e: Exception) {
                                        // Skip malformed JSON lines
                                        android.util.Log.w("OllamaClient", "Skipping malformed chunk: $line")
                                    }
                                }
                            }
                        }
                    }
                }
            } catch (e: Exception) {
                android.util.Log.e("OllamaClient", "Streaming error: ${e.message}", e)
                throw e
            }
        }
    }
}

package com.example.alliswelltemi.utils

import com.example.alliswelltemi.data.Doctor
import com.example.alliswelltemi.data.LocationData
import com.example.alliswelltemi.data.HospitalKnowledgeBase
import java.text.SimpleDateFormat
import java.util.*

/**
 * RagContextBuilder - Enhanced RAG (Retrieval Augmented Generation) Context Builder
 * Builds optimized prompts with filtered, relevant context for Ollama LLM
 * Includes language detection, smart follow-ups, and performance optimizations
 */
object RagContextBuilder {

    /**
     * Detect language from user input text
     * Returns "hi" for Hindi, "en" for English
     * Enhanced with logging and better detection
     */
    fun detectLanguage(text: String): String {
        // Check for Devanagari script (Hindi Unicode range: U+0900 to U+097F)
        val hasHindiChars = text.matches(Regex(".*[\\u0900-\\u097F].*"))

        // Additional check for common Hindi words
        val hindiKeywords = listOf(
            "डॉक्टर", "कहां", "कहाँ", "क्या", "कैसे", "मुझे", "बताओ", "बताइए",
            "अस्पताल", "अपॉइंटमेंट", "बुक", "विशेषज्ञ", "चिकित्सक"
        )
        val hasHindiKeywords = hindiKeywords.any { text.contains(it) }

        val detectedLanguage = if (hasHindiChars || hasHindiKeywords) "hi" else "en"

        android.util.Log.d("RagContextBuilder", "========== LANGUAGE DETECTION ==========")
        android.util.Log.d("RagContextBuilder", "Input text: '$text'")
        android.util.Log.d("RagContextBuilder", "Has Hindi chars: $hasHindiChars")
        android.util.Log.d("RagContextBuilder", "Has Hindi keywords: $hasHindiKeywords")
        android.util.Log.d("RagContextBuilder", "Detected language: $detectedLanguage")
        android.util.Log.d("RagContextBuilder", "========================================")

        return detectedLanguage
    }

    /**
     * Medical terminology translation guide for Hindi responses
     * Provides common English medical terms and their Hindi equivalents
     */
    private fun getMedicalTerminologyGuide(): String {
        return """
        Medical Terms Translation (USE EXACT SPECIALTY FROM CONTEXT):
        Cardiology = हृदय रोग विशेषज्ञ/कार्डियोलॉजी
        Plastic Surgery = प्लास्टिक सर्जन/प्लास्टिक सर्जरी
        Cosmetic Surgery = कॉस्मेटिक सर्जन/सौंदर्य शल्य चिकित्सा
        Neurology = मस्तिष्क रोग विशेषज्ञ/न्यूरोलॉजी
        Orthopedics = हड्डी रोग विशेषज्ञ/ऑर्थोपेडिक्स
        Dermatology = त्वचा रोग विशेषज्ञ/डर्मेटोलॉजी
        Pediatrics = बाल रोग विशेषज्ञ/पीडियाट्रिक्स
        Ophthalmology = नेत्र रोग विशेषज्ञ/ऑप्थेल्मोलॉजी
        General Surgery = सामान्य शल्य चिकित्सा/जनरल सर्जरी
        Psychiatry = मनोचिकित्सा/मनोरोग विशेषज्ञ
        Gynecology = स्त्री रोग विशेषज्ञ/गायनेकोलॉजी
        ENT = कान, नाक, गला विशेषज्ञ
        Pulmonology = फेफड़े के रोग विशेषज्ञ
        Urology = मूत्र रोग विशेषज्ञ
        Gastroenterology = पाचन तंत्र रोग विशेषज्ञ
        Oncology = कैंसर विशेषज्ञ
        Cabin = केबिन
        Department = विभाग
        Specialization = विशेषज्ञता
        Consultant = सलाहकार
        Surgeon = सर्जन/शल्य चिकित्सक
        """.trimIndent()
    }

    /**
     * Build comprehensive RAG context with hospital data
     * For general doctor queries, include ALL doctors
     * For specific queries, filter to relevant doctors
     */
    fun buildContext(query: String, doctors: List<Doctor>): String {
        val language = detectLanguage(query)
        val lowerQuery = query.lowercase()

        android.util.Log.d("RagContextBuilder", "Building context for query: '$query' with ${doctors.size} total doctors")

        // Check if this is a general "tell me doctors" type query
        val isGeneralDoctorQuery = isGeneralDoctorQuery(lowerQuery)
        val isFollowUp = isFollowUpQuery(lowerQuery)

        // For general queries, include ALL doctors. For specific queries, filter to relevant ones
        val relevantDoctors = if (isGeneralDoctorQuery) {
            // General "tell me doctors" query - include ALL
            doctors
        } else {
            // Specific query - filter to relevant doctors
            val filtered = doctors.filter { doctor ->
                val doctorName = doctor.name.lowercase().replace("dr.", "").replace("dr ", "").trim()
                val department = doctor.department.lowercase()
                val specialty = doctor.specialization?.lowercase() ?: ""

                lowerQuery.contains(doctorName) ||
                lowerQuery.contains(department) ||
                lowerQuery.contains(specialty)
            }

            if (filtered.isEmpty() && (lowerQuery.contains("doctor") || lowerQuery.contains("specialist"))) {
                listOf() // Removed fallback to all doctors to prevent hallucinations
            } else {
                filtered.take(10) // Increase limit from 5 to 10 for better context
            }
        }

        android.util.Log.d("RagContextBuilder", "Found ${relevantDoctors.size} relevant doctors for query (general=$isGeneralDoctorQuery, followUp=$isFollowUp)")
        relevantDoctors.forEach { doctor ->
            android.util.Log.d("RagContextBuilder", "  - ${doctor.name} (${doctor.department})")
        }

        // Build doctor context with COMPLETE details - SPECIALIZATION-FOCUSED
        val doctorContext = if (relevantDoctors.isNotEmpty()) {
            relevantDoctors.joinToString("\n") { doctor ->
                val name = if (doctor.name.startsWith("Dr", ignoreCase = true)) doctor.name else "Dr. ${doctor.name}"
                buildString {
                    append("$name | ")

                    // CRITICAL: Use specialization as PRIMARY field if available
                    if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) {
                        append("SPECIALTY: ${doctor.specialization}")
                        append(" | Department: ${doctor.department}")
                    } else {
                        append("SPECIALTY: ${doctor.department}")
                    }

                    append(" | Cabin: ${doctor.cabin}")
                    if (doctor.aboutBio.isNotBlank()) append(" | Bio: ${doctor.aboutBio.take(100)}")
                }
            }
        } else if (isFollowUp) {
            "Relevant doctor mentioned in previous turn."
        } else {
            "Requested doctor or department not found in database."
        }

        // Build location context (popular locations only)
        val locationContext = LocationData.ALL_LOCATIONS
            .filter { it.isPopular }
            .take(3)
            .joinToString(", ") { it.name }

        // Hospital info (keep brief)
        val today = SimpleDateFormat("EEEE, MMMM dd, yyyy", Locale.getDefault()).format(Date())
        val hospitalInfo = "All Is Well Hospital | 9AM-5PM | Emergency: 24/7 | $today"

        return """
        Hospital: $hospitalInfo
        Popular Locations: $locationContext
        Doctors: $doctorContext
        """.trimIndent()
    }

    /**
     * Build context with ALL doctors (for comprehensive doctor list queries)
     */
    fun buildContextWithAllDoctors(query: String, doctors: List<Doctor>): String {
        android.util.Log.d("RagContextBuilder", "Building context with ALL ${doctors.size} doctors for query: '$query'")

        // Build doctor context with ALL doctors and COMPLETE details - SPECIALIZATION-FOCUSED
        val doctorContext = if (doctors.isNotEmpty()) {
            doctors.joinToString("\n") { doctor ->
                val name = if (doctor.name.startsWith("Dr", ignoreCase = true))
                    doctor.name else "Dr. ${doctor.name}"
                buildString {
                    append("$name: ")
                    // PRIORITIZE specialization over department if available
                    if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) {
                        append("Specialization=${doctor.specialization}, ")
                    }
                    append("Department=${doctor.department}, ")
                    append("Cabin=${doctor.cabin}")
                    if (doctor.aboutBio.isNotBlank()) append(", Details: ${doctor.aboutBio.take(120)}")
                }
            }
        } else {
            "No doctors available"
        }

        // Build location context
        val locationContext = LocationData.ALL_LOCATIONS
            .filter { it.isPopular }
            .take(3)
            .joinToString(", ") { it.name }

        // Hospital info
        val today = SimpleDateFormat("EEEE, MMMM dd, yyyy", Locale.getDefault()).format(Date())
        val hospitalInfo = "All Is Well Hospital | 9AM-5PM | Emergency: 24/7 | $today"

        return """
        Hospital: $hospitalInfo
        Popular Locations: $locationContext
        Doctors (Total: ${doctors.size}): $doctorContext
        """.trimIndent()
    }

    /**
     * Helper to detect if query is asking for a list of doctors
     * Refined to avoid treating specialty queries as general lists
     */
    private fun isGeneralDoctorQuery(query: String): Boolean {
        val q = query.lowercase()

        // If it's a follow-up query, it's NOT a general query
        if (isFollowUpQuery(q)) return false

        // If it contains a specific department or doctor name, it's NOT a general query
        val specificSpecialties = listOf("eye", "ophthalmologist", "heart", "cardiologist", "dental", "dentist", "skin", "dermatologist", "bone", "orthopedic")
        if (specificSpecialties.any { q.contains(it) }) return false

        return (q.contains("list") || q.contains("show") || q.contains("tell") || q.contains("who are") || q.contains("available")) && 
               (q.contains("doctor") || q.contains("specialist") || q.contains("physician"))
    }

    /**
     * Helper to detect if query is a follow-up to previous conversation
     */
    private fun isFollowUpQuery(query: String): Boolean {
        val q = query.lowercase()
        return q.contains("repeat") || q.contains("that") || q.contains("him") || q.contains("her") || 
               q.contains("his") || q.contains("hers") || q.contains("they") || q.contains("them") ||
               q.contains("previous") || q.contains("last") || q.contains("again") || q.contains("who is he") ||
               q.contains("who is she")
    }

    /**
     * Detect user intent from query
     * Returns the medical department/specialty they're asking about
     */
    private fun extractDepartmentIntent(query: String): String? {
        val q = query.lowercase()

        // Medical specialty mappings (common terms → medical department)
        val specialtyMappings = mapOf(
            // Cardiology
            "cardio" to "cardio",
            "heart" to "cardio",
            "cardiovascular" to "cardio",

            // Neurology
            "neuro" to "neuro",
            "brain" to "neuro",
            "nervous" to "neuro",

            // Orthopedics
            "ortho" to "ortho",
            "bone" to "ortho",
            "joint" to "ortho",
            "fracture" to "ortho",

            // Ophthalmology
            "ophthal" to "ophthal",
            "eye" to "ophthal",
            "vision" to "ophthal",

            // Dermatology
            "dermat" to "dermat",
            "skin" to "dermat",

            // Pediatrics
            "pediatr" to "pediatr",
            "child" to "pediatr",
            "kids" to "pediatr",

            // Gynecology
            "gynec" to "gynec",
            "women" to "gynec",
            "pregnancy" to "gynec",
            "maternity" to "gynec",

            // Psychiatry
            "psychiat" to "psychiat",
            "mental" to "psychiat",

            // Physiotherapy
            "physio" to "physio",
            "therapy" to "physio",
            "rehab" to "physio",

            // General/Internal Medicine
            "general" to "general",
            "internal" to "general",
            "physician" to "general",

            // Pulmonology
            "pulmo" to "pulmo",
            "lung" to "pulmo",
            "respiratory" to "pulmo",

            // Anesthesia
            "anesth" to "anesth",
            "anesthesia" to "anesth"
        )

        // Check for matches
        for ((term, stem) in specialtyMappings) {
            if (q.contains(term)) {
                android.util.Log.d("RagContextBuilder", " Intent detected: '$term' → stem='$stem'")
                return stem
            }
        }

        return null
    }

    /**
     * Build optimized Ollama prompt with INTENT-BASED query understanding
     * PERFORMANCE OPTIMIZED: Shorter prompts = faster generation
     * For "tell me doctors" queries, includes ALL doctors
     * For department queries (e.g., "cardiology office"), finds ALL doctors in that specialty
     * For other queries, uses filtered context
     * Now includes conversation history for context-aware responses
     */
    fun buildOllamaPrompt(query: String, doctors: List<Doctor>, historyContext: String = ""): String {
        val language = detectLanguage(query)
        val lowerQuery = query.lowercase()

        // Check if this is a general doctor list query
        val isGeneralDoctorQuery = isGeneralDoctorQuery(query)

        // Check if query is about symptoms/health issues (needs general doctor guidance)
        val isHealthQuery = lowerQuery.matches(Regex(".*(pain|ache|fever|cough|cold|sick|ill|feel|hurt|problem|issue|symptom|stomach|head|eye|heart|skin|bone).*"))

        // INTENT DETECTION: Extract department/specialty intent
        val departmentIntent = extractDepartmentIntent(query)

        // Check if this is a doctor-specific query (asking about a specific doctor or department)
        val isDoctorSpecificQuery = lowerQuery.contains("doctor") || lowerQuery.contains("dr.") ||
                                     lowerQuery.contains("specialist") || lowerQuery.contains("who is") ||
                                     lowerQuery.contains("department") || lowerQuery.contains("office") ||
                                     departmentIntent != null

        // SMART RETRIEVAL: Get relevant Q&As from knowledge base
        // For doctor queries, increase limit to capture more dynamic doctor Q&As
        val kbSearchLimit = if (isDoctorSpecificQuery) 5 else 2
        val relevantQAs = HospitalKnowledgeBase.search(query, limit = kbSearchLimit)

        // Log knowledge base results for debugging
        android.util.Log.d("RagContextBuilder", "KB search for '$query' returned ${relevantQAs.size} results (limit=$kbSearchLimit)")
        relevantQAs.forEach { qa ->
            android.util.Log.d("RagContextBuilder", "  - KB Match: ${qa.question} (category=${qa.category}, id=${qa.id})")
        }

        val knowledgeBaseContext = if (relevantQAs.isNotEmpty()) {
            relevantQAs.joinToString("; ") { qa -> "${qa.question}: ${qa.answer}" }
        } else {
            ""
        }

        // SMART DOCTOR SELECTION WITH INTENT UNDERSTANDING
        val hasDynamicDocMatches = relevantQAs.any { it.id.startsWith("dynamic_doc_") }

        // Even if KB has dynamic doctor Q&As, we still fetch the doctor objects for structured context
        val relevantDoctors = when {
            // General doctor query - show sample doctors
            isGeneralDoctorQuery -> {
                android.util.Log.d("RagContextBuilder", " Intent: General doctor list")
                doctors.take(5)
            }

            // INTENT-BASED DEPARTMENT QUERY (e.g., "cardiology office", "heart doctors")
            departmentIntent != null -> {
                val matchedDoctors = doctors.filter { doctor ->
                    val department = doctor.department.lowercase()
                    val specialization = doctor.specialization?.lowercase() ?: ""

                    // Match against the intent stem
                    department.contains(departmentIntent) || specialization.contains(departmentIntent)
                }

                android.util.Log.d("RagContextBuilder", " Intent: Department query for '$departmentIntent' → found ${matchedDoctors.size} doctors")
                matchedDoctors.forEach { doctor ->
                    android.util.Log.d("RagContextBuilder", "  ✓ Matched: ${doctor.name} (${doctor.department})")
                }

                // Return ALL matching doctors (up to 10 for comprehensive list)
                matchedDoctors.take(10)
            }

            // Health symptom query - show general practitioners + relevant specialists
            isHealthQuery -> {
                android.util.Log.d("RagContextBuilder", " Intent: Health symptom query")
                val generalDocs = doctors.filter {
                    it.department.lowercase().contains("general") ||
                    it.department.lowercase().contains("internal") ||
                    it.department.lowercase().contains("physician")
                }.take(2)

                // If no general docs, take first available doctors
                if (generalDocs.isEmpty()) doctors.take(3) else generalDocs
            }

            // Specific doctor NAME query
            else -> {
                android.util.Log.d("RagContextBuilder", " Intent: Specific doctor name query")
                // Extract key medical terms from query (remove common words)
                val queryWords = lowerQuery.split(" ")
                    .filter { it.length > 3 && !listOf("doctor", "specialist", "who", "are", "the", "tell", "about", "show", "find", "office").contains(it) }

                val matchedDoctors = doctors.filter { doctor ->
                    val doctorName = doctor.name.lowercase().replace("dr.", "").replace("dr ", "").trim()
                    val department = doctor.department.lowercase()
                    val specialization = doctor.specialization?.lowercase() ?: ""

                    // Name exact/substring match
                    val nameMatch = lowerQuery.contains(doctorName) || doctorName.contains(lowerQuery)

                    // Department/specialization STEM matching
                    val deptMatch = queryWords.any { word ->
                        val wordStem = word.take(5)
                        department.contains(wordStem) ||
                        specialization.contains(wordStem) ||
                        department.contains(word) ||
                        specialization.contains(word)
                    }

                    nameMatch || deptMatch
                }.sortedBy { doctor ->
                    // Prioritize name matches over department matches
                    val name = doctor.name.lowercase()
                    if (lowerQuery.contains(name) || name.contains(lowerQuery)) 0 else 1
                }

                android.util.Log.d("RagContextBuilder", "  → Found ${matchedDoctors.size} doctors by name/dept matching")
                matchedDoctors.take(5)
            }
        }

        // Build doctor context with COMPLETE details for accurate LLM responses - SPECIALIZATION-FOCUSED
        // Format: Name | PRIMARY_FIELD | Secondary_Field | Cabin | Bio
        val doctorContext = if (relevantDoctors.isNotEmpty()) {
            relevantDoctors.joinToString("\n") { doctor ->
                val name = if (doctor.name.startsWith("Dr", ignoreCase = true)) doctor.name else "Dr. ${doctor.name}"
                buildString {
                    append("$name | ")

                    // CRITICAL: Use specialization as PRIMARY field if available, otherwise use department
                    if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) {
                        append("SPECIALTY: ${doctor.specialization}")
                        append(" | Department: ${doctor.department}")
                    } else {
                        append("SPECIALTY: ${doctor.department}")
                    }

                    append(" | Cabin: ${doctor.cabin}")
                    append(" | Experience: ${doctor.yearsOfExperience} years")
                    if (doctor.aboutBio.isNotBlank()) append(" | Bio: ${doctor.aboutBio.take(100)}")
                }
            }
        } else if (hasDynamicDocMatches) {
            // This case is unlikely now that we always filter, but kept for safety
            "Refer to Info section for matching doctor details."
        } else {
            "Requested doctor or specialist not found in the list."
        }

        // Hospital info for context
        val hospitalInfo = "All Is Well Hospital. OPD, Pharmacy, ICU, Pathology Lab, Billing Counter available."

        // PERFORMANCE: Simplified prompt - removed verbose instructions
        val systemPrompt = if (language == "hi") {
            """आप 'ऑल इज़ वेल हॉस्पिटल' के एक अत्यंत मददगार, खुशदिल, और सम्मानजनक सहायक हैं। हिंदी में जवाब दें। आपकी भाषा सरल, स्पष्ट और आदरपूर्ण होनी चाहिए। अपनी बात संक्षिप्त (1-2 वाक्य) रखें। हमेशा रोगियों का सम्मान करें और उन्हें 'जी' या 'आप' कहकर संबोधित करें। सवाल का सीधा जवाब दें। कोई अतिरिक्त प्रश्न या सहायता की पेशकश न करें।

बेहद महत्वपूर्ण - डॉक्टर जानकारी के नियम:
1. नीचे "Doctors:" सेक्शन में दी गई जानकारी को बिल्कुल वैसे ही इस्तेमाल करें जैसे लिखी है।
2. डॉक्टर का नाम अंग्रेजी में बोलें (उदाहरण: "Dr. Abhishek Sharma")।
3. "SPECIALTY:" के बाद जो भी लिखा है, वही उस डॉक्टर की विशेषज्ञता है। इसे हिंदी में अनुवाद करें।
4. अगर "Consultant Cosmetic & Plastic Surgeon" लिखा है, तो "प्लास्टिक सर्जन" या "कॉस्मेटिक सर्जन" कहें। "हृदय रोग विशेषज्ञ" मत कहें!
5. केबिन नंबर वैसे ही बताएं जैसे दिया गया है।
6. किसी भी जानकारी को अपने आप मत बनाएं। सिर्फ दी गई जानकारी का इस्तेमाल करें।

डिपार्टमेंट अनुवाद गाइड: Cardiology=हृदय रोग, Plastic Surgery=प्लास्टिक सर्जरी, Neurology=मस्तिष्क रोग, Orthopedics=हड्डी रोग, Dermatology=त्वचा रोग, Pediatrics=बाल रोग, Ophthalmology=नेत्र रोग।"""
        } else {
            """You are an extremely helpful, cheerful, and respectful hospital assistant for 'All Is Well Hospital'. Answer in English with clarity. Be brief (1-2 sentences). Always be polite, welcoming, and professional. Use a warm tone. Answer the question directly without offering additional help or asking follow-up questions.

CRITICAL RULES FOR DOCTOR INFORMATION:
1. Use ONLY the information provided in the "Doctors:" section below. Do NOT make up or infer any information.
2. The "SPECIALTY:" field is the PRIMARY specialization of the doctor. Use this field to describe what the doctor specializes in.
3. If a doctor's SPECIALTY says "Consultant Cosmetic & Plastic Surgeon", they are a PLASTIC SURGEON, NOT a cardiologist or any other specialty.
4. NEVER confuse the Department field with the Specialty field. Always read the SPECIALTY field first.
5. If asked about a department (like "cardiology office" or "heart doctors"), list ALL matching doctors whose SPECIALTY or Department matches the query.
6. State the doctor's name, specialty, and cabin number exactly as provided. Do not invent experiences or details not listed."""
        }

        // OPTIMIZED PROMPT: Compact but informative
        // For Hindi, include medical terminology translation guide
        val terminologyGuide = if (language == "hi") getMedicalTerminologyGuide() else ""

        return """
        $systemPrompt
        ${if (terminologyGuide.isNotEmpty()) "\n$terminologyGuide\n" else ""}
        ${if (historyContext.isNotEmpty()) "Previous: $historyContext" else ""}
        Hospital: $hospitalInfo
        ${if (knowledgeBaseContext.isNotEmpty()) "Info: $knowledgeBaseContext" else ""}
        Doctors: $doctorContext
        Q: $query
        A:""".trimIndent().replace("\n\n", "\n")
    }

    /**
     * Build streaming-optimized prompt (shorter for faster initial response)
     * Cheerful and respectful tone, NO follow-up suggestions
     * Enhanced with medical terminology guide for Hindi
     */
    fun buildStreamingPrompt(query: String, doctors: List<Doctor>): String {
        val language = detectLanguage(query)
        val context = buildContext(query, doctors)

        val langInstruction = if (language == "hi") {
            """आप 'ऑल इज़ वेल हॉस्पिटल' के एक खुशदिल, स्पष्ट और अत्यंत सम्मानजनक सहायक हैं। सवाल का सीधा जवाब दें, कोई अतिरिक्त प्रश्न न करें।
            महत्वपूर्ण: डॉक्टरों के नाम अंग्रेजी में बोलें, लेकिन विभाग (Department) को हिंदी में अनुवाद करें। उदाहरण: "Cardiology" को "हृदय रोग विशेषज्ञ", "Neurology" को "मस्तिष्क रोग विशेषज्ञ" कहें।"""
        } else {
            "You are a cheerful, clear, and highly respectful hospital assistant for 'All Is Well Hospital'. Answer directly without follow-up questions."
        }

        val terminologyGuide = if (language == "hi") getMedicalTerminologyGuide() else ""

        // Even more concise for streaming, no follow-ups
        return """
        $langInstruction
        ${if (terminologyGuide.isNotEmpty()) "\n$terminologyGuide\n" else ""}

        $context

        User: $query

        Answer clearly, respectfully, and warmly in 1-2 sentences. Do not ask follow-up questions or offer additional help.
        """.trimIndent()
    }

    /**
     * Generate fallback response when Ollama fails
     * Context-aware fallbacks based on detected intent
     */
    fun generateFallbackResponse(query: String, doctors: List<Doctor>): String {
        val language = detectLanguage(query)
        val lowerQuery = query.lowercase()

        val response = when {
            // Doctor queries
            lowerQuery.contains("doctor") || lowerQuery.contains("specialist") -> {
                if (doctors.isNotEmpty()) {
                    if (language == "hi") {
                        "मैं आपको डॉक्टर ढूंढने में मदद कर सकता हूं। हमारे पास ${doctors.size} डॉक्टर हैं। डॉक्टर सूची देखें।"
                    } else {
                        "I can help you find doctors. We have ${doctors.size} doctors available. Please check the doctors section."
                    }
                } else {
                    if (language == "hi") "डॉक्टर सूची अभी लोड हो रही है। कृपया पुनः प्रयास करें।" else "Doctor list is loading. Please try again."
                }
            }

            // Navigation queries
            lowerQuery.contains("navigate") || lowerQuery.contains("where") || lowerQuery.contains("go to") -> {
                if (language == "hi") {
                    "मैं आपको नेविगेट करने में मदद कर सकता हूं। हमारे पास फार्मेसी, ICU, पैथोलॉजी लैब, बिलिंग काउंटर और OPD हैं।"
                } else {
                    "I can help you navigate. We have pharmacy, ICU, pathology lab, billing counter, and OPD areas."
                }
            }

            // Booking queries
            lowerQuery.contains("book") || lowerQuery.contains("appointment") -> {
                if (language == "hi") "मैं आपको अपॉइंटमेंट बुक करने में मदद कर सकता हूं। अपॉइंटमेंट सेक्शन देखें।" else "I can help you book an appointment. Please visit the appointment section."
            }

            // Default fallback
            else -> {
                if (language == "hi") {
                    "नमस्ते! मैं ऑल इज़ वेल हॉस्पिटल में आपकी किस प्रकार सहायता कर सकता हूँ? कृपया मुझे बताएं या मुख्य मेनू में विकल्पों को देखें।"
                } else {
                    "Hello! I am here to help you at All Is Well Hospital. How can I assist you today? Please let me know your requirement or explore the main menu."
                }
            }
        }

        return response
    }
}

package com.example.alliswelltemi.utils

import com.example.alliswelltemi.data.Doctor
import com.example.alliswelltemi.data.LocationData
import com.example.alliswelltemi.data.HospitalKnowledgeBase
import java.text.SimpleDateFormat
import java.util.*

/**
 * RagContextBuilder - Enhanced RAG (Retrieval Augmented Generation) Context Builder
 * Builds optimized prompts with filtered, relevant context for Ollama LLM
 * Includes language detection, smart follow-ups, and performance optimizations
 */
object RagContextBuilder {

    /**
     * Detect language from user input text
     * Returns "hi" for Hindi, "en" for English
     * Enhanced with logging and better detection
     */
    fun detectLanguage(text: String): String {
        // Check for Devanagari script (Hindi Unicode range: U+0900 to U+097F)
        val hasHindiChars = text.matches(Regex(".*[\\u0900-\\u097F].*"))

        // Additional check for common Hindi words
        val hindiKeywords = listOf(
            "डॉक्टर", "कहां", "कहाँ", "क्या", "कैसे", "मुझे", "बताओ", "बताइए",
            "अस्पताल", "अपॉइंटमेंट", "बुक", "विशेषज्ञ", "चिकित्सक"
        )
        val hasHindiKeywords = hindiKeywords.any { text.contains(it) }

        val detectedLanguage = if (hasHindiChars || hasHindiKeywords) "hi" else "en"

        android.util.Log.d("RagContextBuilder", "========== LANGUAGE DETECTION ==========")
        android.util.Log.d("RagContextBuilder", "Input text: '$text'")
        android.util.Log.d("RagContextBuilder", "Has Hindi chars: $hasHindiChars")
        android.util.Log.d("RagContextBuilder", "Has Hindi keywords: $hasHindiKeywords")
        android.util.Log.d("RagContextBuilder", "Detected language: $detectedLanguage")
        android.util.Log.d("RagContextBuilder", "========================================")

        return detectedLanguage
    }

    /**
     * Medical terminology translation guide for Hindi responses
     * Provides common English medical terms and their Hindi equivalents
     */
    private fun getMedicalTerminologyGuide(): String {
        return """
        Medical Terms Translation (USE EXACT SPECIALTY FROM CONTEXT):
        Cardiology = हृदय रोग विशेषज्ञ/कार्डियोलॉजी
        Plastic Surgery = प्लास्टिक सर्जन/प्लास्टिक सर्जरी
        Cosmetic Surgery = कॉस्मेटिक सर्जन/सौंदर्य शल्य चिकित्सा
        Neurology = मस्तिष्क रोग विशेषज्ञ/न्यूरोलॉजी
        Orthopedics = हड्डी रोग विशेषज्ञ/ऑर्थोपेडिक्स
        Dermatology = त्वचा रोग विशेषज्ञ/डर्मेटोलॉजी
        Pediatrics = बाल रोग विशेषज्ञ/पीडियाट्रिक्स
        Ophthalmology = नेत्र रोग विशेषज्ञ/ऑप्थेल्मोलॉजी
        General Surgery = सामान्य शल्य चिकित्सा/जनरल सर्जरी
        Psychiatry = मनोचिकित्सा/मनोरोग विशेषज्ञ
        Gynecology = स्त्री रोग विशेषज्ञ/गायनेकोलॉजी
        ENT = कान, नाक, गला विशेषज्ञ
        Pulmonology = फेफड़े के रोग विशेषज्ञ
        Urology = मूत्र रोग विशेषज्ञ
        Gastroenterology = पाचन तंत्र रोग विशेषज्ञ
        Oncology = कैंसर विशेषज्ञ
        Cabin = केबिन
        Department = विभाग
        Specialization = विशेषज्ञता
        Consultant = सलाहकार
        Surgeon = सर्जन/शल्य चिकित्सक
        """.trimIndent()
    }

    /**
     * Build comprehensive RAG context with hospital data
     * For general doctor queries, include ALL doctors
     * For specific queries, filter to relevant doctors
     */
    fun buildContext(query: String, doctors: List<Doctor>): String {
        val language = detectLanguage(query)
        val lowerQuery = query.lowercase()

        android.util.Log.d("RagContextBuilder", "Building context for query: '$query' with ${doctors.size} total doctors")

        // Check if this is a general "tell me doctors" type query
        val isGeneralDoctorQuery = isGeneralDoctorQuery(lowerQuery)
        val isFollowUp = isFollowUpQuery(lowerQuery)

        // For general queries, include ALL doctors. For specific queries, filter to relevant ones
        val relevantDoctors = if (isGeneralDoctorQuery) {
            // General "tell me doctors" query - include ALL
            doctors
        } else {
            // Specific query - filter to relevant doctors
            val filtered = doctors.filter { doctor ->
                val doctorName = doctor.name.lowercase().replace("dr.", "").replace("dr ", "").trim()
                val department = doctor.department.lowercase()
                val specialty = doctor.specialization?.lowercase() ?: ""

                lowerQuery.contains(doctorName) ||
                lowerQuery.contains(department) ||
                lowerQuery.contains(specialty)
            }

            if (filtered.isEmpty() && (lowerQuery.contains("doctor") || lowerQuery.contains("specialist"))) {
                listOf() // Removed fallback to all doctors to prevent hallucinations
            } else {
                filtered.take(10) // Increase limit from 5 to 10 for better context
            }
        }

        android.util.Log.d("RagContextBuilder", "Found ${relevantDoctors.size} relevant doctors for query (general=$isGeneralDoctorQuery, followUp=$isFollowUp)")
        relevantDoctors.forEach { doctor ->
            android.util.Log.d("RagContextBuilder", "  - ${doctor.name} (${doctor.department})")
        }

        // Build doctor context with COMPLETE details - SPECIALIZATION-FOCUSED
        val doctorContext = if (relevantDoctors.isNotEmpty()) {
            relevantDoctors.joinToString("\n") { doctor ->
                val name = if (doctor.name.startsWith("Dr", ignoreCase = true)) doctor.name else "Dr. ${doctor.name}"
                buildString {
                    append("$name | ")

                    // CRITICAL: Use specialization as PRIMARY field if available
                    if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) {
                        append("SPECIALTY: ${doctor.specialization}")
                        append(" | Department: ${doctor.department}")
                    } else {
                        append("SPECIALTY: ${doctor.department}")
                    }

                    append(" | Cabin: ${doctor.cabin}")
                    if (doctor.aboutBio.isNotBlank()) append(" | Bio: ${doctor.aboutBio.take(100)}")
                }
            }
        } else if (isFollowUp) {
            "Relevant doctor mentioned in previous turn."
        } else {
            "Requested doctor or department not found in database."
        }

        // Build location context (popular locations only)
        val locationContext = LocationData.ALL_LOCATIONS
            .filter { it.isPopular }
            .take(3)
            .joinToString(", ") { it.name }

        // Hospital info (keep brief)
        val today = SimpleDateFormat("EEEE, MMMM dd, yyyy", Locale.getDefault()).format(Date())
        val hospitalInfo = "All Is Well Hospital | 9AM-5PM | Emergency: 24/7 | $today"

        return """
        Hospital: $hospitalInfo
        Popular Locations: $locationContext
        Doctors: $doctorContext
        """.trimIndent()
    }

    /**
     * Build context with ALL doctors (for comprehensive doctor list queries)
     */
    fun buildContextWithAllDoctors(query: String, doctors: List<Doctor>): String {
        android.util.Log.d("RagContextBuilder", "Building context with ALL ${doctors.size} doctors for query: '$query'")

        // Build doctor context with ALL doctors and COMPLETE details - SPECIALIZATION-FOCUSED
        val doctorContext = if (doctors.isNotEmpty()) {
            doctors.joinToString("\n") { doctor ->
                val name = if (doctor.name.startsWith("Dr", ignoreCase = true))
                    doctor.name else "Dr. ${doctor.name}"
                buildString {
                    append("$name | ")

                    // CRITICAL: Use specialization as PRIMARY field if available
                    if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) {
                        append("SPECIALTY: ${doctor.specialization}")
                        append(" | Department: ${doctor.department}")
                    } else {
                        append("SPECIALTY: ${doctor.department}")
                    }

                    append(" | Cabin: ${doctor.cabin}")
                    if (doctor.aboutBio.isNotBlank()) append(" | Bio: ${doctor.aboutBio.take(100)}")
                }
            }
        } else {
            "No doctors available"
        }

        // Build location context
        val locationContext = LocationData.ALL_LOCATIONS
            .filter { it.isPopular }
            .take(3)
            .joinToString(", ") { it.name }

        // Hospital info
        val today = SimpleDateFormat("EEEE, MMMM dd, yyyy", Locale.getDefault()).format(Date())
        val hospitalInfo = "All Is Well Hospital | 9AM-5PM | Emergency: 24/7 | $today"

        return """
        Hospital: $hospitalInfo
        Popular Locations: $locationContext
        Doctors (Total: ${doctors.size}): $doctorContext
        """.trimIndent()
    }

    /**
     * Helper to detect if query is asking for a list of doctors
     * Refined to avoid treating specialty queries as general lists
     */
    private fun isGeneralDoctorQuery(query: String): Boolean {
        val q = query.lowercase()

        // If it's a follow-up query, it's NOT a general query
        if (isFollowUpQuery(q)) return false

        // If it contains a specific department or doctor name, it's NOT a general query
        val specificSpecialties = listOf("eye", "ophthalmologist", "heart", "cardiologist", "dental", "dentist", "skin", "dermatologist", "bone", "orthopedic")
        if (specificSpecialties.any { q.contains(it) }) return false

        return (q.contains("list") || q.contains("show") || q.contains("tell") || q.contains("who are") || q.contains("available")) && 
               (q.contains("doctor") || q.contains("specialist") || q.contains("physician"))
    }

    /**
     * Helper to detect if query is a follow-up to previous conversation
     */
    private fun isFollowUpQuery(query: String): Boolean {
        val q = query.lowercase()
        return q.contains("repeat") || q.contains("that") || q.contains("him") || q.contains("her") || 
               q.contains("his") || q.contains("hers") || q.contains("they") || q.contains("them") ||
               q.contains("previous") || q.contains("last") || q.contains("again") || q.contains("who is he") ||
               q.contains("who is she")
    }

    /**
     * Detect user intent from query
     * Returns the medical department/specialty they're asking about
     */
    private fun extractDepartmentIntent(query: String): String? {
        val q = query.lowercase()

        // Medical specialty mappings (common terms → medical department)
        val specialtyMappings = mapOf(
            // Cardiology
            "cardio" to "cardio",
            "heart" to "cardio",
            "cardiovascular" to "cardio",

            // Neurology
            "neuro" to "neuro",
            "brain" to "neuro",
            "nervous" to "neuro",

            // Orthopedics
            "ortho" to "ortho",
            "bone" to "ortho",
            "joint" to "ortho",
            "fracture" to "ortho",

            // Ophthalmology
            "ophthal" to "ophthal",
            "eye" to "ophthal",
            "vision" to "ophthal",

            // Dermatology
            "dermat" to "dermat",
            "skin" to "dermat",

            // Pediatrics
            "pediatr" to "pediatr",
            "child" to "pediatr",
            "kids" to "pediatr",

            // Gynecology
            "gynec" to "gynec",
            "women" to "gynec",
            "pregnancy" to "gynec",
            "maternity" to "gynec",

            // Psychiatry
            "psychiat" to "psychiat",
            "mental" to "psychiat",

            // Physiotherapy
            "physio" to "physio",
            "therapy" to "physio",
            "rehab" to "physio",

            // General/Internal Medicine
            "general" to "general",
            "internal" to "general",
            "physician" to "general",

            // Pulmonology
            "pulmo" to "pulmo",
            "lung" to "pulmo",
            "respiratory" to "pulmo",

            // Anesthesia
            "anesth" to "anesth",
            "anesthesia" to "anesth"
        )

        // Check for matches
        for ((term, stem) in specialtyMappings) {
            if (q.contains(term)) {
                android.util.Log.d("RagContextBuilder", " Intent detected: '$term' → stem='$stem'")
                return stem
            }
        }

        return null
    }

    /**
     * Build optimized Ollama prompt with INTENT-BASED query understanding
     * PERFORMANCE OPTIMIZED: Shorter prompts = faster generation
     * For "tell me doctors" queries, includes ALL doctors
     * For department queries (e.g., "cardiology office"), finds ALL doctors in that specialty
     * For other queries, uses filtered context
     * Now includes conversation history for context-aware responses
     */
    fun buildOllamaPrompt(query: String, doctors: List<Doctor>, historyContext: String = ""): String {
        val language = detectLanguage(query)
        val lowerQuery = query.lowercase()

        // Check if this is a general doctor list query
        val isGeneralDoctorQuery = isGeneralDoctorQuery(query)

        // Check if query is about symptoms/health issues (needs general doctor guidance)
        val isHealthQuery = lowerQuery.matches(Regex(".*(pain|ache|fever|cough|cold|sick|ill|feel|hurt|problem|issue|symptom|stomach|head|eye|heart|skin|bone).*"))

        // INTENT DETECTION: Extract department/specialty intent
        val departmentIntent = extractDepartmentIntent(query)

        // Check if this is a doctor-specific query (asking about a specific doctor or department)
        val isDoctorSpecificQuery = lowerQuery.contains("doctor") || lowerQuery.contains("dr.") ||
                                     lowerQuery.contains("specialist") || lowerQuery.contains("who is") ||
                                     lowerQuery.contains("department") || lowerQuery.contains("office") ||
                                     departmentIntent != null

        // SMART RETRIEVAL: Get relevant Q&As from knowledge base
        // For doctor queries, increase limit to capture more dynamic doctor Q&As
        val kbSearchLimit = if (isDoctorSpecificQuery) 5 else 2
        val relevantQAs = HospitalKnowledgeBase.search(query, limit = kbSearchLimit)

        // Log knowledge base results for debugging
        android.util.Log.d("RagContextBuilder", "KB search for '$query' returned ${relevantQAs.size} results (limit=$kbSearchLimit)")
        relevantQAs.forEach { qa ->
            android.util.Log.d("RagContextBuilder", "  - KB Match: ${qa.question} (category=${qa.category}, id=${qa.id})")
        }

        val knowledgeBaseContext = if (relevantQAs.isNotEmpty()) {
            relevantQAs.joinToString("; ") { qa -> "${qa.question}: ${qa.answer}" }
        } else {
            ""
        }

        // SMART DOCTOR SELECTION WITH INTENT UNDERSTANDING
        val hasDynamicDocMatches = relevantQAs.any { it.id.startsWith("dynamic_doc_") }

        // Even if KB has dynamic doctor Q&As, we still fetch the doctor objects for structured context
        val relevantDoctors = when {
            // General doctor query - show sample doctors
            isGeneralDoctorQuery -> {
                android.util.Log.d("RagContextBuilder", " Intent: General doctor list")
                doctors.take(5)
            }

            // INTENT-BASED DEPARTMENT QUERY (e.g., "cardiology office", "heart doctors")
            departmentIntent != null -> {
                val matchedDoctors = doctors.filter { doctor ->
                    val department = doctor.department.lowercase()
                    val specialization = doctor.specialization?.lowercase() ?: ""

                    // Match against the intent stem
                    department.contains(departmentIntent) || specialization.contains(departmentIntent)
                }

                android.util.Log.d("RagContextBuilder", " Intent: Department query for '$departmentIntent' → found ${matchedDoctors.size} doctors")
                matchedDoctors.forEach { doctor ->
                    android.util.Log.d("RagContextBuilder", "  ✓ Matched: ${doctor.name} (${doctor.department})")
                }

                // Return ALL matching doctors (up to 10 for comprehensive list)
                matchedDoctors.take(10)
            }

            // Health symptom query - show general practitioners + relevant specialists
            isHealthQuery -> {
                android.util.Log.d("RagContextBuilder", " Intent: Health symptom query")
                val generalDocs = doctors.filter {
                    it.department.lowercase().contains("general") ||
                    it.department.lowercase().contains("internal") ||
                    it.department.lowercase().contains("physician")
                }.take(2)

                // If no general docs, take first available doctors
                if (generalDocs.isEmpty()) doctors.take(3) else generalDocs
            }

            // Specific doctor NAME query
            else -> {
                android.util.Log.d("RagContextBuilder", " Intent: Specific doctor name query")
                // Extract key medical terms from query (remove common words)
                val queryWords = lowerQuery.split(" ")
                    .filter { it.length > 3 && !listOf("doctor", "specialist", "who", "are", "the", "tell", "about", "show", "find", "office").contains(it) }

                val matchedDoctors = doctors.filter { doctor ->
                    val doctorName = doctor.name.lowercase().replace("dr.", "").replace("dr ", "").trim()
                    val department = doctor.department.lowercase()
                    val specialization = doctor.specialization?.lowercase() ?: ""

                    // Name exact/substring match
                    val nameMatch = lowerQuery.contains(doctorName) || doctorName.contains(lowerQuery)

                    // Department/specialization STEM matching
                    val deptMatch = queryWords.any { word ->
                        val wordStem = word.take(5)
                        department.contains(wordStem) ||
                        specialization.contains(wordStem) ||
                        department.contains(word) ||
                        specialization.contains(word)
                    }

                    nameMatch || deptMatch
                }.sortedBy { doctor ->
                    // Prioritize name matches over department matches
                    val name = doctor.name.lowercase()
                    if (lowerQuery.contains(name) || name.contains(lowerQuery)) 0 else 1
                }

                android.util.Log.d("RagContextBuilder", "  → Found ${matchedDoctors.size} doctors by name/dept matching")
                matchedDoctors.take(5)
            }
        }

        // Build doctor context with COMPLETE details for accurate LLM responses - SPECIALIZATION-FOCUSED
        // Format: Name | PRIMARY_FIELD | Secondary_Field | Cabin | Bio
        val doctorContext = if (relevantDoctors.isNotEmpty()) {
            relevantDoctors.joinToString("\n") { doctor ->
                val name = if (doctor.name.startsWith("Dr", ignoreCase = true)) doctor.name else "Dr. ${doctor.name}"
                buildString {
                    append("$name | ")

                    // CRITICAL: Use specialization as PRIMARY field if available, otherwise use department
                    if (doctor.specialization.isNotBlank() && !doctor.specialization.equals(doctor.department, ignoreCase = true)) {
                        append("SPECIALTY: ${doctor.specialization}")
                        append(" | Department: ${doctor.department}")
                    } else {
                        append("SPECIALTY: ${doctor.department}")
                    }

                    append(" | Cabin: ${doctor.cabin}")
                    append(" | Experience: ${doctor.yearsOfExperience} years")
                    if (doctor.aboutBio.isNotBlank()) append(" | Bio: ${doctor.aboutBio.take(100)}")
                }
            }
        } else if (hasDynamicDocMatches) {
            // This case is unlikely now that we always filter, but kept for safety
            "Refer to Info section for matching doctor details."
        } else {
            "Requested doctor or specialist not found in the list."
        }

        // Hospital info for context
        val hospitalInfo = "All Is Well Hospital. OPD, Pharmacy, ICU, Pathology Lab, Billing Counter available."

        // PERFORMANCE: Simplified prompt - removed verbose instructions
        val systemPrompt = if (language == "hi") {
            """आप 'ऑल इज़ वेल हॉस्पिटल' के एक अत्यंत मददगार, खुशदिल, और सम्मानजनक सहायक हैं। हिंदी में जवाब दें। आपकी भाषा सरल, स्पष्ट और आदरपूर्ण होनी चाहिए। अपनी बात संक्षिप्त (1-2 वाक्य) रखें। हमेशा रोगियों का सम्मान करें और उन्हें 'जी' या 'आप' कहकर संबोधित करें। सवाल का सीधा जवाब दें। कोई अतिरिक्त प्रश्न या सहायता की पेशकश न करें।

बेहद महत्वपूर्ण - डॉक्टर जानकारी के नियम:
1. नीचे "Doctors:" सेक्शन में दी गई जानकारी को बिल्कुल वैसे ही इस्तेमाल करें जैसे लिखी है।
2. डॉक्टर का नाम अंग्रेजी में बोलें (उदाहरण: "Dr. Abhishek Sharma")।
3. "SPECIALTY:" के बाद जो भी लिखा है, वही उस डॉक्टर की विशेषज्ञता है। इसे हिंदी में अनुवाद करें।
4. अगर "Consultant Cosmetic & Plastic Surgeon" लिखा है, तो "प्लास्टिक सर्जन" या "कॉस्मेटिक सर्जन" कहें। "हृदय रोग विशेषज्ञ" मत कहें!
5. केबिन नंबर वैसे ही बताएं जैसे दिया गया है।
6. किसी भी जानकारी को अपने आप मत बनाएं। सिर्फ दी गई जानकारी का इस्तेमाल करें।

डिपार्टमेंट अनुवाद गाइड: Cardiology=हृदय रोग, Plastic Surgery=प्लास्टिक सर्जरी, Neurology=मस्तिष्क रोग, Orthopedics=हड्डी रोग, Dermatology=त्वचा रोग, Pediatrics=बाल रोग, Ophthalmology=नेत्र रोग।"""
        } else {
            """You are an extremely helpful, cheerful, and respectful hospital assistant for 'All Is Well Hospital'. Answer in English with clarity. Be brief (1-2 sentences). Always be polite, welcoming, and professional. Use a warm tone. Answer the question directly without offering additional help or asking follow-up questions.

CRITICAL RULES FOR DOCTOR INFORMATION:
1. Use ONLY the information provided in the "Doctors:" section below. Do NOT make up or infer any information.
2. The "SPECIALTY:" field is the PRIMARY specialization of the doctor. Use this field to describe what the doctor specializes in.
3. If a doctor's SPECIALTY says "Consultant Cosmetic & Plastic Surgeon", they are a PLASTIC SURGEON, NOT a cardiologist or any other specialty.
4. NEVER confuse the Department field with the Specialty field. Always read the SPECIALTY field first.
5. If asked about a department (like "cardiology office" or "heart doctors"), list ALL matching doctors whose SPECIALTY or Department matches the query.
6. State the doctor's name, specialty, and cabin number exactly as provided. Do not invent experiences or details not listed."""
        }

        // OPTIMIZED PROMPT: Compact but informative
        // For Hindi, include medical terminology translation guide
        val terminologyGuide = if (language == "hi") getMedicalTerminologyGuide() else ""

        return """
        $systemPrompt
        ${if (terminologyGuide.isNotEmpty()) "\n$terminologyGuide\n" else ""}
        ${if (historyContext.isNotEmpty()) "Previous: $historyContext" else ""}
        Hospital: $hospitalInfo
        ${if (knowledgeBaseContext.isNotEmpty()) "Info: $knowledgeBaseContext" else ""}
        Doctors: $doctorContext
        Q: $query
        A:""".trimIndent().replace("\n\n", "\n")
    }

    /**
     * Build streaming-optimized prompt (shorter for faster initial response)
     * Cheerful and respectful tone, NO follow-up suggestions
     * Enhanced with medical terminology guide for Hindi
     */
    fun buildStreamingPrompt(query: String, doctors: List<Doctor>): String {
        val language = detectLanguage(query)
        val context = buildContext(query, doctors)

        val langInstruction = if (language == "hi") {
            """आप 'ऑल इज़ वेल हॉस्पिटल' के एक खुशदिल, स्पष्ट और अत्यंत सम्मानजनक सहायक हैं। सवाल का सीधा जवाब दें, कोई अतिरिक्त प्रश्न न करें।
            महत्वपूर्ण: डॉक्टरों के नाम अंग्रेजी में बोलें, लेकिन विभाग (Department) को हिंदी में अनुवाद करें। उदाहरण: "Cardiology" को "हृदय रोग विशेषज्ञ", "Neurology" को "मस्तिष्क रोग विशेषज्ञ" कहें।"""
        } else {
            "You are a cheerful, clear, and highly respectful hospital assistant for 'All Is Well Hospital'. Answer directly without follow-up questions."
        }

        val terminologyGuide = if (language == "hi") getMedicalTerminologyGuide() else ""

        // Even more concise for streaming, no follow-ups
        return """
        $langInstruction
        ${if (terminologyGuide.isNotEmpty()) "\n$terminologyGuide\n" else ""}

        $context

        User: $query

        Answer clearly, respectfully, and warmly in 1-2 sentences. Do not ask follow-up questions or offer additional help.
        """.trimIndent()
    }

    /**
     * Generate fallback response when Ollama fails
     * Context-aware fallbacks based on detected intent
     */
    fun generateFallbackResponse(query: String, doctors: List<Doctor>): String {
        val language = detectLanguage(query)
        val lowerQuery = query.lowercase()

        val response = when {
            // Doctor queries
            lowerQuery.contains("doctor") || lowerQuery.contains("specialist") -> {
                if (doctors.isNotEmpty()) {
                    if (language == "hi") {
                        "मैं आपको डॉक्टर ढूंढने में मदद कर सकता हूं। हमारे पास ${doctors.size} डॉक्टर हैं। डॉक्टर सूची देखें।"
                    } else {
                        "I can help you find doctors. We have ${doctors.size} doctors available. Please check the doctors section."
                    }
                } else {
                    if (language == "hi") "डॉक्टर सूची अभी लोड हो रही है। कृपया पुनः प्रयास करें।" else "Doctor list is loading. Please try again."
                }
            }

            // Navigation queries
            lowerQuery.contains("navigate") || lowerQuery.contains("where") || lowerQuery.contains("go to") -> {
                if (language == "hi") {
                    "मैं आपको नेविगेट करने में मदद कर सकता हूं। हमारे पास फार्मेसी, ICU, पैथोलॉजी लैब, बिलिंग काउंटर और OPD हैं।"
                } else {
                    "I can help you navigate. We have pharmacy, ICU, pathology lab, billing counter, and OPD areas."
                }
            }

            // Booking queries
            lowerQuery.contains("book") || lowerQuery.contains("appointment") -> {
                if (language == "hi") "मैं आपको अपॉइंटमेंट बुक करने में मदद कर सकता हूं। अपॉइंटमेंट सेक्शन देखें।" else "I can help you book an appointment. Please visit the appointment section."
            }

            // Default fallback
            else -> {
                if (language == "hi") {
                    "नमस्ते! मैं ऑल इज़ वेल हॉस्पिटल में आपकी किस प्रकार सहायता कर सकता हूँ? कृपया मुझे बताएं या मुख्य मेनू में विकल्पों को देखें।"
                } else {
                    "Hello! I am here to help you at All Is Well Hospital. How can I assist you today? Please let me know your requirement or explore the main menu."
                }
            }
        }

        return response
    }
}

package com.example.alliswelltemi.utils

import com.example.alliswelltemi.data.Doctor
import com.example.alliswelltemi.data.Location
import com.example.alliswelltemi.data.LocationData
import com.example.alliswelltemi.data.DoctorData
import android.util.Log
import com.robotemi.sdk.Robot

/**
 * SpeechOrchestrator - Centralized intent detection and routing
 *
 * Analyzes user speech input and determines the intent with contextual data.
 * Produces a lightweight Context object for downstream processing.
 * Supports location-based navigation in addition to doctor and appointment intents.
 */
class SpeechOrchestrator(
    private val doctors: List<Doctor>,
    private var robot: Robot? = null
) {

    enum class Intent {
        FIND_DOCTOR,      // User asking about doctors or specialties
        NAVIGATE,         // User wants to go to a location or doctor's cabin
        BOOK,             // User wants to book an appointment
        DANCE,            // User asking robot to dance
        GENERAL           // General questions about hospital
    }

    data class Context(
        val intent: Intent,
        val query: String,
        val doctor: Doctor? = null,
        val department: String? = null,
        val location: Location? = null,  // Location to navigate to (new field)
        val confidence: Float = 0.5f,
        val danceMove: DanceService.DanceMove? = null  // Specific dance type if DANCE intent
    )

    private val tag = "SpeechOrchestrator"

    /**
     * Update robot instance (useful for when robot becomes available after initialization)
     */
    fun setRobot(newRobot: Robot?) {
        this.robot = newRobot
        Log.d(tag, "Robot instance updated for location validation")
    }

    /**
     * Analyze speech input and extract intent + relevant context
     * Supports both English and Hindi keywords
     * Detects location names for navigation commands
     *
     * @param text User's spoken/typed input
     * @return Context with detected intent and relevant data
     */
    fun analyze(text: String): Context {
        if (text.isBlank()) {
            return Context(Intent.GENERAL, text)
        }

        val lower = text.lowercase()

        // Step 0: Remove noise from ASR (common misrecognitions)
        val cleaned = removeASRNoise(lower)

        // Step 1: Try to match a specific doctor by name
        val doctor = doctors.find { doctor ->
            val doctorNameClean = doctor.name
                .lowercase()
                .replace("dr.", "")
                .replace("dr ", "")
                .trim()
            cleaned.contains(doctorNameClean)
        }

        // Step 2: Try to match a department
        val department = doctors
            .map { it.department }
            .distinct()
            .find { dept -> cleaned.contains(dept.lowercase()) }
            ?: run {
                // Also try to match Hindi department names
                val hindiDept = DoctorData.findDepartmentByName(cleaned)
                if (hindiDept != null) {
                    Log.d(tag, " Matched Hindi department: $hindiDept")
                    hindiDept
                } else {
                    null
                }
            }

        // Step 3: Try to match a hospital location (for navigation)
        val location = extractLocation(cleaned)

        // Step 4: Detect dance intent (MUST be before other intents)
        val danceMove = detectDanceIntent(cleaned)

        // Step 5: Detect intent from keywords (English + Hindi)
        val intent = when {
            // Dance-related keywords (FIRST priority)
            danceMove != null ||
            cleaned.contains("dance") ||
            cleaned.contains("dancing") ||
            cleaned.contains("move") ||
            cleaned.contains("groove") ||
            cleaned.contains("boogie") ||
            cleaned.contains("spin") ||
            cleaned.contains("नाच") ||
            cleaned.contains("नृत्य") ||
            cleaned.contains("हिलना") ||
            cleaned.contains("घूमना") -> Intent.DANCE

            // Navigation-related keywords (English + Hindi)
             // Priority: Location matching first, then doctor/cabin
             location != null ||
             cleaned.contains("navigate") ||
             cleaned.contains("take me") ||
             cleaned.contains("go to") ||
             cleaned.contains("where is") ||
             cleaned.contains("cabin") ||
             cleaned.contains("ले चलो") ||
             cleaned.contains("ले जाओ") ||
            cleaned.contains("लेके चलो") ||
             cleaned.contains("कहां है") ||
             cleaned.contains("कहाँ है") ||
             cleaned.contains("किधर") ||
             cleaned.contains("कहा है") ||
             cleaned.contains("केबिन") ||
             cleaned.contains("दिशा") ||
             cleaned.contains("रास्ता") ||
             cleaned.contains("पता") -> Intent.NAVIGATE

            // Booking-related keywords (English + Hindi)
            cleaned.contains("book") ||
            cleaned.contains("appointment") ||
            cleaned.contains("schedule") ||
            cleaned.contains("reserve") ||
            cleaned.contains("बुक") ||
            cleaned.contains("अपॉइंटमेंट") ||
            cleaned.contains("अपोइंटमेंट") ||
            cleaned.contains("समय") ||
            cleaned.contains("मिलना") ||
            cleaned.contains("परामर्श") -> Intent.BOOK

            // Doctor lookup keywords (English + Hindi)
            doctor != null ||
            department != null ||
            cleaned.contains("doctor") ||
            cleaned.contains("specialist") ||
            cleaned.contains("cardiologist") ||
            cleaned.contains("surgeon") ||
            cleaned.contains("neurologist") ||
            cleaned.contains("pediatrician") ||
            cleaned.contains("डॉक्टर") ||
            cleaned.contains("डाक्टर") ||
            cleaned.contains("विशेषज्ञ") ||
            cleaned.contains("चिकित्सक") ||
            cleaned.contains("सर्जन") ||
            cleaned.contains("डाक्टर कहां") ||
            cleaned.contains("कौन डॉक्टर") -> Intent.FIND_DOCTOR

            // Default to general inquiry
            else -> Intent.GENERAL
        }

        // Calculate confidence
        val confidence = when {
            intent == Intent.DANCE -> 0.95f  // High confidence for dance
            location != null && (cleaned.contains("navigate") || cleaned.contains("take me") || cleaned.contains("go to")) -> 0.95f  // High confidence for location navigation
            doctor != null && department != null -> 0.95f
            doctor != null || department != null -> 0.85f
            intent != Intent.GENERAL -> 0.75f
            else -> 0.5f
        }

        Log.d(tag, "️ Analyzed: intent=$intent, location=${location?.name}, doctor=${doctor?.name}, confidence=$confidence")

        return Context(
            intent = intent,
            query = text,
            doctor = doctor,
            department = department,
            location = location,  // Include extracted location
            confidence = confidence,
            danceMove = danceMove
        )
    }

    /**
     * Extract location from cleaned query text
     * Supports both English and Hindi location names
     * Handles synonyms like "entrance", "exit", "gate", "front", "back", etc.
     * Validates that locations exist on the robot's actual saved map
     * Returns null if no location is found
     */
    private fun extractLocation(cleaned: String): Location? {
        // Get robot's saved locations - CRITICAL for actual navigation
        val robotSavedLocations = if (robot != null) {
            try {
                MapLocationService.fetchSavedLocations(robot)
            } catch (e: Exception) {
                Log.e(tag, "Error fetching robot locations: ${e.message}")
                emptyList()
            }
        } else {
            emptyList()
        }

        Log.d(tag, " Robot has ${robotSavedLocations.size} saved locations")
        if (robotSavedLocations.isNotEmpty()) {
            Log.d(tag, " Available locations on robot: ${robotSavedLocations.map { it.name }.joinToString(", ")}")
        }

        // PRIORITY 1: Try matching against robot's actual saved locations directly
         // This is the MOST IMPORTANT - only navigate to locations the robot actually has
         if (robotSavedLocations.isNotEmpty()) {
             for (robotLocation in robotSavedLocations) {
                 val robotNameLower = robotLocation.name.lowercase()
                 val robotMapNameLower = robotLocation.mapName.lowercase()

                 // Try exact substring match
                 if (cleaned.contains(robotNameLower) || cleaned.contains(robotMapNameLower)) {
                     Log.d(tag, "✅ MATCHED from robot map: ${robotLocation.name} (exact match)")
                     return robotLocation
                 }

                 // Try fuzzy match against robot location
                 val nameDistance = levenshteinDistance(cleaned, robotNameLower)
                 val mapDistance = levenshteinDistance(cleaned, robotMapNameLower)
                 if (nameDistance <= 2 || mapDistance <= 2) {
                     Log.d(tag, "✅ MATCHED from robot map: ${robotLocation.name} (fuzzy match, distance=$nameDistance)")
                     return robotLocation
                 }
             }
         }

         // PRIORITY 1B: Try matching Hindi location names (for "फार्मेसी" etc.)
         // Enhanced bilingual matching for locations with Hindi names
         for (location in LocationData.ALL_LOCATIONS) {
             if (location.nameHi.isNotEmpty()) {
                 // Direct substring match for Hindi (case-sensitive but exact)
                 if (cleaned.contains(location.nameHi)) {
                     Log.d(tag, "✅ MATCHED Hindi location name: ${location.name} (Hindi: ${location.nameHi})")
                     // Try to find matching robot location with same ID/content
                     val robotMatch = robotSavedLocations.find {
                         it.name.lowercase() == location.name.lowercase() ||
                         it.mapName.lowercase() == location.id.lowercase()
                     }
                     return robotMatch ?: location
                 }

                 // Partial Hindi match (important for "कार्डियो" matching "कार्डियोलॉजी")
                 if (location.nameHi.contains(cleaned) && cleaned.length >= 3) {
                     Log.d(tag, "✅ PARTIAL MATCHED Hindi location: ${location.name} (Hindi partial: ${location.nameHi})")
                     val robotMatch = robotSavedLocations.find {
                         it.name.lowercase() == location.name.lowercase() ||
                         it.mapName.lowercase() == location.id.lowercase()
                     }
                     return robotMatch ?: location
                 }
             }
         }

        // PRIORITY 2: Try synonym-based matching for common entrance/exit patterns
        // Handle patterns like "back entrance", "front entrance", "side exit", etc.
        val entranceMatches = listOf(
            Pair(Regex("\\b(back|rear|side)\\s+(entrance|door|gate|entry|way)\\b"), "entrance"),
            Pair(Regex("\\b(front|main)\\s+(entrance|door|gate|entry|way)\\b"), "entrance"),
            Pair(Regex("\\b(exit|leave|out)\\s*(way)?\\b"), "exit")
        )

        for ((pattern, keyword) in entranceMatches) {
            if (pattern.containsMatchIn(cleaned)) {
                Log.d(tag, " Pattern matched: '$keyword' from input")
                // Try to find a matching location on the robot's map
                if (robotSavedLocations.isNotEmpty()) {
                    val matchedLocation = robotSavedLocations.find {
                        it.name.lowercase().contains(keyword) ||
                        it.mapName.lowercase().contains(keyword)
                    }
                    if (matchedLocation != null) {
                        Log.d(tag, "✅ SYNONYM MATCHED from robot map: ${matchedLocation.name}")
                        return matchedLocation
                    } else {
                        Log.d(tag, "⚠️ Pattern '$keyword' found but no matching location on robot map")
                    }
                }
            }
        }

        // PRIORITY 3: Try matching against predefined locations (fallback)
        // Only use if robot doesn't have a better match
        if (robotSavedLocations.isEmpty()) {
            for (location in LocationData.ALL_LOCATIONS) {
                val nameMatch = location.name.lowercase()
                val nameHiMatch = location.nameHi.lowercase()
                val idMatch = location.id.lowercase()

                if (cleaned.contains(nameMatch) ||
                    cleaned.contains(nameHiMatch) ||
                    cleaned.contains(idMatch)) {
                    Log.d(tag, "⚠️ FALLBACK: Using predefined location (robot map unavailable): ${location.name}")
                    return location
                }
            }
        }

        Log.d(tag, "❌ No location matched in extracted text: '$cleaned'")
        return null
    }

    /**
     * Calculate Levenshtein distance for fuzzy location matching
     */
    private fun levenshteinDistance(s1: String, s2: String): Int {
        if (s1 == s2) return 0
        if (s1.isEmpty()) return s2.length
        if (s2.isEmpty()) return s1.length

        val dp = Array(s1.length + 1) { IntArray(s2.length + 1) }

        for (i in 0..s1.length) dp[i][0] = i
        for (j in 0..s2.length) dp[0][j] = j

        for (i in 1..s1.length) {
            for (j in 1..s2.length) {
                val cost = if (s1[i - 1] == s2[j - 1]) 0 else 1
                dp[i][j] = minOf(
                    dp[i - 1][j] + 1,      // deletion
                    dp[i][j - 1] + 1,      // insertion
                    dp[i - 1][j - 1] + cost // substitution
                )
            }
        }

        return dp[s1.length][s2.length]
    }

    /**
     * Detect which type of dance the user is requesting
     * Returns null if no specific dance detected
     */
    private fun detectDanceIntent(cleaned: String): DanceService.DanceMove? {
        return when {
            cleaned.contains("spin") || cleaned.contains("घूमना") -> DanceService.DanceMove.SPIN_DANCE
            cleaned.contains("hip hop") || cleaned.contains("hip-hop") || cleaned.contains("हिप हॉप") -> DanceService.DanceMove.HIP_HOP
            cleaned.contains("disco") || cleaned.contains("डिस्को") -> DanceService.DanceMove.DISCO_FEVER
            cleaned.contains("robot") || cleaned.contains("boogie") || cleaned.contains("रोबोट") -> DanceService.DanceMove.ROBOT_BOOGIE
            cleaned.contains("smooth") || cleaned.contains("groove") || cleaned.contains("सुचारु") -> DanceService.DanceMove.SMOOTH_GROOVE
            // If just "dance" without specifying which, pick a random one
            cleaned.contains("dance") || cleaned.contains("नाच") || cleaned.contains("नृत्य") -> {
                DanceService.DanceMove.values().random()
            }
            else -> null
        }
    }

    /**
     * Remove common ASR noise and misrecognitions
     */
    private fun removeASRNoise(text: String): String {
        val noiseWords = listOf(
            "japanese", "indian", "american", "british", "canadian", // nationalities
            "male", "female", // gender descriptors
            "senior", "junior", "sr", "jr", // qualifiers
            "the", "a", "an" // articles
        )

        var cleaned = text
        noiseWords.forEach { noise ->
            cleaned = cleaned.replace(Regex("\\b$noise\\b"), " ")
        }

        return cleaned.replace(Regex("\\s+"), " ").trim()
    }
}

package com.example.alliswelltemi.utils

import com.example.alliswelltemi.data.Doctor
import com.example.alliswelltemi.data.Location
import com.example.alliswelltemi.data.LocationData
import com.example.alliswelltemi.data.DoctorData
import android.util.Log
import com.robotemi.sdk.Robot

/**
 * SpeechOrchestrator - Centralized intent detection and routing
 *
 * Analyzes user speech input and determines the intent with contextual data.
 * Produces a lightweight Context object for downstream processing.
 * Supports location-based navigation in addition to doctor and appointment intents.
 */
class SpeechOrchestrator(
    private val doctors: List<Doctor>,
    private var robot: Robot? = null
) {

    enum class Intent {
        FIND_DOCTOR,      // User asking about doctors or specialties
        NAVIGATE,         // User wants to go to a location or doctor's cabin
        BOOK,             // User wants to book an appointment
        DANCE,            // User asking robot to dance
        GENERAL           // General questions about hospital
    }

    data class Context(
        val intent: Intent,
        val query: String,
        val doctor: Doctor? = null,
        val department: String? = null,
        val location: Location? = null,  // Location to navigate to (new field)
        val confidence: Float = 0.5f,
        val danceMove: DanceService.DanceMove? = null  // Specific dance type if DANCE intent
    )

    private val tag = "SpeechOrchestrator"

    /**
     * Update robot instance (useful for when robot becomes available after initialization)
     */
    fun setRobot(newRobot: Robot?) {
        this.robot = newRobot
        Log.d(tag, "Robot instance updated for location validation")
    }

    /**
     * Analyze speech input and extract intent + relevant context
     * Supports both English and Hindi keywords
     * Detects location names for navigation commands
     *
     * @param text User's spoken/typed input
     * @return Context with detected intent and relevant data
     */
    fun analyze(text: String): Context {
        if (text.isBlank()) {
            return Context(Intent.GENERAL, text)
        }

        val lower = text.lowercase()

        // Step 0: Remove noise from ASR (common misrecognitions)
        val cleaned = removeASRNoise(lower)

        // Step 1: Try to match a specific doctor by name
        val doctor = doctors.find { doctor ->
            val doctorNameClean = doctor.name
                .lowercase()
                .replace("dr.", "")
                .replace("dr ", "")
                .trim()
            cleaned.contains(doctorNameClean)
        }

        // Step 2: Try to match a department
        val department = doctors
            .map { it.department }
            .distinct()
            .find { dept -> cleaned.contains(dept.lowercase()) }
            ?: run {
                // Also try to match Hindi department names
                val hindiDept = DoctorData.findDepartmentByName(cleaned)
                if (hindiDept != null) {
                    Log.d(tag, " Matched Hindi department: $hindiDept")
                    hindiDept
                } else {
                    null
                }
            }

        // Step 3: Try to match a hospital location (for navigation)
        val location = extractLocation(cleaned)

        // Step 4: Detect dance intent (MUST be before other intents)
        val danceMove = detectDanceIntent(cleaned)

        // Step 5: Detect intent from keywords (English + Hindi)
        val intent = when {
            // Dance-related keywords (FIRST priority)
            danceMove != null ||
            cleaned.contains("dance") ||
            cleaned.contains("dancing") ||
            cleaned.contains("move") ||
            cleaned.contains("groove") ||
            cleaned.contains("boogie") ||
            cleaned.contains("spin") ||
            cleaned.contains("नाच") ||
            cleaned.contains("नृत्य") ||
            cleaned.contains("हिलना") ||
            cleaned.contains("घूमना") -> Intent.DANCE

            // Navigation-related keywords (English + Hindi)
             // Priority: Location matching first, then doctor/cabin
             location != null ||
             cleaned.contains("navigate") ||
             cleaned.contains("take me") ||
             cleaned.contains("go to") ||
             cleaned.contains("where is") ||
             cleaned.contains("cabin") ||
             cleaned.contains("ले चलो") ||
             cleaned.contains("ले जाओ") ||
            cleaned.contains("लेके चलो") ||
             cleaned.contains("कहां है") ||
             cleaned.contains("कहाँ है") ||
             cleaned.contains("किधर") ||
             cleaned.contains("कहा है") ||
             cleaned.contains("केबिन") ||
             cleaned.contains("दिशा") ||
             cleaned.contains("रास्ता") ||
             cleaned.contains("पता") -> Intent.NAVIGATE

            // Booking-related keywords (English + Hindi)
            cleaned.contains("book") ||
            cleaned.contains("appointment") ||
            cleaned.contains("schedule") ||
            cleaned.contains("reserve") ||
            cleaned.contains("बुक") ||
            cleaned.contains("अपॉइंटमेंट") ||
            cleaned.contains("अपोइंटमेंट") ||
            cleaned.contains("समय") ||
            cleaned.contains("मिलना") ||
            cleaned.contains("परामर्श") -> Intent.BOOK

            // Doctor lookup keywords (English + Hindi)
            doctor != null ||
            department != null ||
            cleaned.contains("doctor") ||
            cleaned.contains("specialist") ||
            cleaned.contains("cardiologist") ||
            cleaned.contains("surgeon") ||
            cleaned.contains("neurologist") ||
            cleaned.contains("pediatrician") ||
            cleaned.contains("डॉक्टर") ||
            cleaned.contains("डाक्टर") ||
            cleaned.contains("विशेषज्ञ") ||
            cleaned.contains("चिकित्सक") ||
            cleaned.contains("सर्जन") ||
            cleaned.contains("डाक्टर कहां") ||
            cleaned.contains("कौन डॉक्टर") -> Intent.FIND_DOCTOR

            // Default to general inquiry
            else -> Intent.GENERAL
        }

        // Calculate confidence
        val confidence = when {
            intent == Intent.DANCE -> 0.95f  // High confidence for dance
            location != null && (cleaned.contains("navigate") || cleaned.contains("take me") || cleaned.contains("go to")) -> 0.95f  // High confidence for location navigation
            doctor != null && department != null -> 0.95f
            doctor != null || department != null -> 0.85f
            intent != Intent.GENERAL -> 0.75f
            else -> 0.5f
        }

        Log.d(tag, "️ Analyzed: intent=$intent, location=${location?.name}, doctor=${doctor?.name}, confidence=$confidence")

        return Context(
            intent = intent,
            query = text,
            doctor = doctor,
            department = department,
            location = location,  // Include extracted location
            confidence = confidence,
            danceMove = danceMove
        )
    }

    /**
     * Extract location from cleaned query text
     * Supports both English and Hindi location names
     * Handles synonyms like "entrance", "exit", "gate", "front", "back", etc.
     * Validates that locations exist on the robot's actual saved map
     * Returns null if no location is found
     */
    private fun extractLocation(cleaned: String): Location? {
        // Get robot's saved locations - CRITICAL for actual navigation
        val robotSavedLocations = if (robot != null) {
            try {
                MapLocationService.fetchSavedLocations(robot)
            } catch (e: Exception) {
                Log.e(tag, "Error fetching robot locations: ${e.message}")
                emptyList()
            }
        } else {
            emptyList()
        }

        Log.d(tag, " Robot has ${robotSavedLocations.size} saved locations")
        if (robotSavedLocations.isNotEmpty()) {
            Log.d(tag, " Available locations on robot: ${robotSavedLocations.map { it.name }.joinToString(", ")}")
        }

        // PRIORITY 1: Try matching against robot's actual saved locations directly
         // This is the MOST IMPORTANT - only navigate to locations the robot actually has
         if (robotSavedLocations.isNotEmpty()) {
             for (robotLocation in robotSavedLocations) {
                 val robotNameLower = robotLocation.name.lowercase()
                 val robotMapNameLower = robotLocation.mapName.lowercase()

                 // Try exact substring match
                 if (cleaned.contains(robotNameLower) || cleaned.contains(robotMapNameLower)) {
                     Log.d(tag, "✅ MATCHED from robot map: ${robotLocation.name} (exact match)")
                     return robotLocation
                 }

                 // Try fuzzy match against robot location
                 val nameDistance = levenshteinDistance(cleaned, robotNameLower)
                 val mapDistance = levenshteinDistance(cleaned, robotMapNameLower)
                 if (nameDistance <= 2 || mapDistance <= 2) {
                     Log.d(tag, "✅ MATCHED from robot map: ${robotLocation.name} (fuzzy match, distance=$nameDistance)")
                     return robotLocation
                 }
             }
         }

          // PRIORITY 1B: Try matching Hindi location names (for "फार्मेसी" etc.)
          // Enhanced bilingual matching for locations with Hindi names
          // Also supports compound Hindi names like "पैथोलॉजी रिसेप्शन"
          for (location in LocationData.ALL_LOCATIONS) {
              if (location.nameHi.isNotEmpty()) {
                  // Direct substring match for Hindi (case-sensitive but exact)
                  if (cleaned.contains(location.nameHi)) {
                      Log.d(tag, "✅ MATCHED Hindi location name: ${location.name} (Hindi: ${location.nameHi})")
                      // Try to find matching robot location with same ID/content
                      val robotMatch = robotSavedLocations.find {
                          it.lowercase() == location.name.lowercase() ||
                          it.lowercase() == location.mapName.lowercase() ||
                          it.lowercase() == location.id.lowercase()
                      }
                      return robotMatch?.let { Location(location.id, it, "", "", false) } ?: location
                  }

                  // Partial Hindi match (important for "कार्डियो" matching "कार्डियोलॉजी")
                  if (location.nameHi.contains(cleaned) && cleaned.length >= 3) {
                      Log.d(tag, "✅ PARTIAL MATCHED Hindi location: ${location.name} (Hindi partial: ${location.nameHi})")
                      val robotMatch = robotSavedLocations.find {
                          it.lowercase() == location.name.lowercase() ||
                          it.lowercase() == location.mapName.lowercase() ||
                          it.lowercase() == location.id.lowercase()
                      }
                      return robotMatch?.let { Location(location.id, it, "", "", false) } ?: location
                  }
              }
          }

          // PRIORITY 1C: Try matching compound Hindi location descriptions
          // For cases like "पैथोलॉजी रिसेप्शन" (Pathology Reception)
          // Extract individual Hindi words and try to match multiple locations
          val hindiWords = cleaned.split("\\s+".toRegex()).filter { it.length >= 3 }
          if (hindiWords.isNotEmpty()) {
              for (location in LocationData.ALL_LOCATIONS) {
                  if (location.nameHi.isNotEmpty()) {
                      // Check if any Hindi word in the input matches words in the location's Hindi name OR English name
                      val locationWords = (location.nameHi + " " + location.name).split("\\s+".toRegex()).map { it.lowercase() }
                      val matchedCount = hindiWords.count { word ->
                          locationWords.any { locWord -> locWord.contains(word) || word.contains(locWord) }
                      }

                      if (matchedCount > 0) {
                          Log.d(tag, "✅ COMPOUND MATCH: '${location.name}' matched ${matchedCount}/${hindiWords.size} words from input")
                          val robotMatch = robotSavedLocations.find {
                              it.lowercase() == location.name.lowercase() ||
                              it.lowercase() == location.mapName.lowercase() ||
                              it.lowercase() == location.id.lowercase()
                          }
                          return robotMatch?.let { Location(location.id, it, "", "", false) } ?: location
                      }
                  }
              }
          }

        // PRIORITY 2: Try synonym-based matching for common entrance/exit patterns
        // Handle patterns like "back entrance", "front entrance", "side exit", etc.
        val entranceMatches = listOf(
            Pair(Regex("\\b(back|rear|side)\\s+(entrance|door|gate|entry|way)\\b"), "entrance"),
            Pair(Regex("\\b(front|main)\\s+(entrance|door|gate|entry|way)\\b"), "entrance"),
            Pair(Regex("\\b(exit|leave|out)\\s*(way)?\\b"), "exit")
        )

        for ((pattern, keyword) in entranceMatches) {
            if (pattern.containsMatchIn(cleaned)) {
                Log.d(tag, " Pattern matched: '$keyword' from input")
                // Try to find a matching location on the robot's map
                if (robotSavedLocations.isNotEmpty()) {
                    val matchedLocation = robotSavedLocations.find {
                        it.name.lowercase().contains(keyword) ||
                        it.mapName.lowercase().contains(keyword)
                    }
                    if (matchedLocation != null) {
                        Log.d(tag, "✅ SYNONYM MATCHED from robot map: ${matchedLocation.name}")
                        return matchedLocation
                    } else {
                        Log.d(tag, "⚠️ Pattern '$keyword' found but no matching location on robot map")
                    }
                }
            }
        }

        // PRIORITY 3: Try matching against predefined locations (fallback)
        // Only use if robot doesn't have a better match
        if (robotSavedLocations.isEmpty()) {
            for (location in LocationData.ALL_LOCATIONS) {
                val nameMatch = location.name.lowercase()
                val nameHiMatch = location.nameHi.lowercase()
                val idMatch = location.id.lowercase()

                if (cleaned.contains(nameMatch) ||
                    cleaned.contains(nameHiMatch) ||
                    cleaned.contains(idMatch)) {
                    Log.d(tag, "⚠️ FALLBACK: Using predefined location (robot map unavailable): ${location.name}")
                    return location
                }
            }
        }

        Log.d(tag, "❌ No location matched in extracted text: '$cleaned'")
        return null
    }

    /**
     * Calculate Levenshtein distance for fuzzy location matching
     */
    private fun levenshteinDistance(s1: String, s2: String): Int {
        if (s1 == s2) return 0
        if (s1.isEmpty()) return s2.length
        if (s2.isEmpty()) return s1.length

        val dp = Array(s1.length + 1) { IntArray(s2.length + 1) }

        for (i in 0..s1.length) dp[i][0] = i
        for (j in 0..s2.length) dp[0][j] = j

        for (i in 1..s1.length) {
            for (j in 1..s2.length) {
                val cost = if (s1[i - 1] == s2[j - 1]) 0 else 1
                dp[i][j] = minOf(
                    dp[i - 1][j] + 1,      // deletion
                    dp[i][j - 1] + 1,      // insertion
                    dp[i - 1][j - 1] + cost // substitution
                )
            }
        }

        return dp[s1.length][s2.length]
    }

    /**
     * Detect which type of dance the user is requesting
     * Returns null if no specific dance detected
     */
    private fun detectDanceIntent(cleaned: String): DanceService.DanceMove? {
        return when {
            cleaned.contains("spin") || cleaned.contains("घूमना") -> DanceService.DanceMove.SPIN_DANCE
            cleaned.contains("hip hop") || cleaned.contains("hip-hop") || cleaned.contains("हिप हॉप") -> DanceService.DanceMove.HIP_HOP
            cleaned.contains("disco") || cleaned.contains("डिस्को") -> DanceService.DanceMove.DISCO_FEVER
            cleaned.contains("robot") || cleaned.contains("boogie") || cleaned.contains("रोबोट") -> DanceService.DanceMove.ROBOT_BOOGIE
            cleaned.contains("smooth") || cleaned.contains("groove") || cleaned.contains("सुचारु") -> DanceService.DanceMove.SMOOTH_GROOVE
            // If just "dance" without specifying which, pick a random one
            cleaned.contains("dance") || cleaned.contains("नाच") || cleaned.contains("नृत्य") -> {
                DanceService.DanceMove.values().random()
            }
            else -> null
        }
    }

    /**
     * Remove common ASR noise and misrecognitions
     */
    private fun removeASRNoise(text: String): String {
        val noiseWords = listOf(
            "japanese", "indian", "american", "british", "canadian", // nationalities
            "male", "female", // gender descriptors
            "senior", "junior", "sr", "jr", // qualifiers
            "the", "a", "an" // articles
        )

        var cleaned = text
        noiseWords.forEach { noise ->
            cleaned = cleaned.replace(Regex("\\b$noise\\b"), " ")
        }

        return cleaned.replace(Regex("\\s+"), " ").trim()
    }
}

