/**
 * Glowing Robot Avatar (Simplified SVG-like representation)
 */
@Composable
fun TemiAvatarComponent(modifier: Modifier = Modifier) {
    val infiniteTransition = rememberInfiniteTransition(label = "glow")
    val glowAlpha by infiniteTransition.animateFloat(
        initialValue = 0.4f,
        targetValue = 0.8f,
        animationSpec = infiniteRepeatable(
            animation = keyframes {
                durationMillis = 2000
                0.4f at 0
                0.8f at 1000
                0.4f at 2000
            }
        ),
        label = "glow_alpha"
    )

    Box(
        modifier = modifier
            .size(120.dp)
            .shadow(
                elevation = 20.dp,
                shape = CircleShape,
                ambientColor = Color(0xFF00D9FF).copy(alpha = glowAlpha),
                spotColor = Color(0xFF00D9FF).copy(alpha = glowAlpha)
            )
            .clip(CircleShape)
            .background(
                brush = Brush.radialGradient(
                    colors = listOf(
                        Color(0xFF1A2332),
                        Color(0xFF0B1220)
                    )
                )
            )
            .border(
                width = 3.dp,
                brush = Brush.linearGradient(
                    colors = listOf(
                        Color(0xFF00D9FF),
                        Color(0xFFB100FF)
                    )
                ),
                shape = CircleShape
            ),
        contentAlignment = Alignment.Center
    ) {
        // Simplified robot face (emoji-like)
        Text(
            text = "",
            fontSize = 60.sp,
            modifier = Modifier.align(Alignment.Center)
        )
    }
}

